def _write_stage_grounding_files(
    workspace: Path,
    *,
    base_name: str,
    title: str,
    payload: dict[str, Any],
) -> tuple[Path, Path]:
    json_path = workspace / f"{base_name}.json"
    md_path = workspace / f"{base_name}.md"
    _write_normalized_json(json_path, payload)
    read_order_lines = []
    for item in list(payload.get("read_order") or []):
        if not isinstance(item, dict):
            continue
        path_text = str(item.get("path") or "").strip()
        purpose = str(item.get("purpose") or "").strip()
        line = f"- `{path_text}`"
        if purpose:
            line += f": {purpose}"
        read_order_lines.append(line)
    must_cover_lines = []
    for key, value in list(dict(payload.get("must_cover") or {}).items()):
        values = _stringify_list_like(value)
        if values:
            must_cover_lines.append(f"- {key}: " + " / ".join(values[:8]))
    md_path.write_text(
        "\n".join(
            [
                f"# {title}",
                "",
                "## Read Order",
                *(read_order_lines or ["- none"]),
                "",
                "## Must Cover",
                *(must_cover_lines or ["- none"]),
            ]
        ),
        encoding="utf-8",
    )
    return json_path, md_path


def _register_grounding_artifacts(
    pipeline_job_id: str,
    *,
    stage_id: str,
    paths: list[Path],
) -> list[dict[str, Any]]:
    artifacts: list[dict[str, Any]] = []
    for path in paths:
        if not path.exists():
            continue
        artifacts.append(
            _register_artifact(
                pipeline_job_id,
                stage_id=stage_id,
                artifact_path=path,
                artifact_type=path.suffix.lstrip(".") or "txt",
                role="grounding_index",
                is_primary=False,
            )
        )
    return artifacts


