def _build_ecommerce_question_tree_grounding_payload(
    *,
    workspace: Path,
    requirement_intent_payload: dict[str, Any],
    inventory_payload: dict[str, Any],
    fact_pack_payload: dict[str, Any],
    metric_consumption_payload: dict[str, Any],
) -> dict[str, Any]:
    inventory_summary = _compact_ecommerce_inventory_for_question_tree(inventory_payload)
    fact_pack_summary = _compact_ecommerce_fact_pack_for_question_tree(fact_pack_payload)
    action_anchor_summary: list[dict[str, Any]] = []
    for candidate_name in ("ecommerce_action_table.json", "ecommerce_action_roadmap.json"):
        candidate_path = workspace / candidate_name
        candidate_payload = _read_json_value(candidate_path)
        source_rows: list[dict[str, Any]] = []
        if isinstance(candidate_payload, list):
            source_rows = [row for row in candidate_payload if isinstance(row, dict)]
        elif isinstance(candidate_payload, dict):
            for key in ("rows", "seven_day_ecommerce_action_table", "thirty_day_ecommerce_action_table", "actions"):
                values = candidate_payload.get(key)
                if isinstance(values, list):
                    source_rows = [row for row in values if isinstance(row, dict)]
                    if source_rows:
                        break
        for row in source_rows[:6]:
            action_anchor_summary.append(
                {
                    "source": candidate_name,
                    "priority": str(row.get("priority") or row.get("priority_level") or "").strip(),
                    "owner": str(row.get("owner") or row.get("owner_role") or row.get("责任人") or "").strip(),
                    "action": str(row.get("action") or row.get("recommended_action") or row.get("最终动作") or "").strip(),
                    "validation_metric": str(row.get("validation_metric") or row.get("验证指标") or "").strip(),
                }
            )
        if action_anchor_summary:
            break
    return {
        "stage_id": "ecommerce_question_tree",
        "grounding_mode": "file_grounded",
        "safe_file_only_mode": True,
        "read_order": [
            {"path": "01a_ecommerce_table_fact_pack.json", "purpose": "顶层事实包和文件索引"},
            {"path": "01b_ecommerce_metric_consumption_index.json", "purpose": "派生/代理指标消费合同"},
            {"path": "01_ecommerce_inventory.json", "purpose": "管理层阅读顺序和当前重点对象"},
            {"path": "01a_dimension_catalog.json", "purpose": "可用维度和覆盖策略"},
            {"path": "01a_object_pool_registry.json", "purpose": "命名对象池"},
            {"path": "01a_dimension_pair_summary.csv", "purpose": "交叉维度证据"},
            {"path": "01a_route_cube.csv", "purpose": "路线证据"},
            {"path": "01a_exception_casebook.json", "purpose": "异常样本"},
            {"path": "01a_review_text_theme_summary.json", "purpose": "文本主题和引文"},
        ],
        "forbidden_raw_sources": [
            "ecommerce_object_decision_registry.json",
            "ecommerce_action_table.json",
        ],
        "must_cover": {
            "business_questions": _stringify_list_like(requirement_intent_payload.get("business_questions"))[:6],
            "dimensions": _stringify_list_like(inventory_summary.get("dimensions_covered"))[:12],
            "object_pools": list(_compact_mapping_string_lists(inventory_payload.get("focus_pools_used")).keys())[:8],
            "routes": _stringify_list_like(inventory_summary.get("routes_used"))[:8],
            "text_themes": _stringify_list_like(_dict_or_empty(inventory_summary.get("text_evidence_used")).get("themes_used"))[:8],
            "body_primary_metric_ids": [str(item.get("metric_id") or "") for item in list(metric_consumption_payload.get("body_primary_metrics") or [])[:8] if str(item.get("metric_id") or "").strip()],
            "body_support_metric_ids": [str(item.get("metric_id") or "") for item in list(metric_consumption_payload.get("body_support_metrics") or [])[:8] if str(item.get("metric_id") or "").strip()],
            "appendix_metric_ids": [str(item.get("metric_id") or "") for item in list(metric_consumption_payload.get("appendix_metrics") or [])[:8] if str(item.get("metric_id") or "").strip()],
        },
        "question_tree_contract": {
            "required_top_level_keys": [
                "root_question",
                "question_nodes",
                "analysis_paths",
                "decision_questions",
                "recommended_sections",
                "action_focus_objects",
            ],
            "required_node_keys": [
                "evidence_sources",
                "dimension_ids",
                "object_pool_ids",
                "derived_metric_ids",
            ],
        },
        "requirement_intent_summary": _compact_requirement_intent_for_ecommerce_question_tree(requirement_intent_payload),
        "inventory_summary": inventory_summary,
        "fact_pack_summary": fact_pack_summary,
        "action_anchor_summary": action_anchor_summary,
        "metric_consumption_summary": {
            "metric_universe_count": int(metric_consumption_payload.get("metric_universe_count") or 0),
            "body_primary_metric_ids": [str(item.get("metric_id") or "") for item in list(metric_consumption_payload.get("body_primary_metrics") or [])[:8]],
            "body_support_metric_ids": [str(item.get("metric_id") or "") for item in list(metric_consumption_payload.get("body_support_metrics") or [])[:8]],
            "appendix_metric_ids": [str(item.get("metric_id") or "") for item in list(metric_consumption_payload.get("appendix_metrics") or [])[:8]],
        },
    }


