def _build_ecommerce_html_grounding_payload(
    *,
    chart_insights_payload: dict[str, Any],
    visual_asset_index_payload: dict[str, Any],
    reader_interpretation_payload: dict[str, Any] | None = None,
) -> dict[str, Any]:
    reader_interpretation_payload = reader_interpretation_payload or {}
    figures = [
        {
            "figure_id": str(item.get("figure_id") or ""),
            "relative_path": str(item.get("relative_path") or ""),
            "chart_type": str(item.get("chart_type") or ""),
        }
        for item in list(chart_insights_payload.get("figures") or [])
        if isinstance(item, dict) and str(item.get("relative_path") or item.get("figure_id") or "").strip()
    ]
    image_assets = [
        {
            "name": str(((item.get("render_metadata") or {}).get("name") or item.get("name") or "")).strip(),
            "relative_path": str(((item.get("render_metadata") or {}).get("relative_path") or item.get("relative_path") or "")).strip(),
            "chart_type": str(((item.get("render_metadata") or {}).get("chart_type") or item.get("chart_type") or "")).strip(),
        }
        for item in list(visual_asset_index_payload.get("image_assets") or [])
        if isinstance(item, dict)
    ]
    required_figures = [
        figure for figure in figures[:6]
        if str(figure.get("relative_path") or "").strip()
    ]
    return {
        "stage_id": "ecommerce_html_css_package",
        "grounding_mode": "file_grounded",
        "safe_file_only_mode": True,
        "read_order": [
            {"path": "05_report.md", "purpose": "reader-facing report body"},
            {"path": "05b_ecommerce_reader_interpretation_pack.json", "purpose": "table, figure, and metric human interpretation contract"},
            {"path": "05b_ecommerce_reader_interpretation_pack.md", "purpose": "human-readable interpretation checklist"},
            {"path": "chart_insights.json", "purpose": "figure observations / implications / actions"},
            {"path": "source_visual_assets_index.json", "purpose": "available image assets and relative paths"},
        ],
        "must_cover": {
            "required_figure_ids": [str(item.get("figure_id") or "") for item in required_figures],
            "required_asset_paths": [str(item.get("relative_path") or "") for item in required_figures],
            "required_table_card_count": [str(reader_interpretation_payload.get("table_count") or 0)],
            "required_metric_usage_count": [str(reader_interpretation_payload.get("metric_count") or 0)],
        },
        "figure_preview": required_figures,
        "asset_preview": image_assets[:8],
        "reader_interpretation_preview": {
            "table_count": int(reader_interpretation_payload.get("table_count") or 0),
            "figure_count": int(reader_interpretation_payload.get("figure_count") or 0),
            "metric_count": int(reader_interpretation_payload.get("metric_count") or 0),
        },
    }


def _clean_reader_text(value: Any, *, limit: int = 360) -> str:
    text = str(value or "").strip()
    text = re.sub(r"\s+", " ", text)
    return text[:limit].strip()


def _extract_markdown_tables_for_reader_pack(markdown_text: str) -> list[dict[str, Any]]:
    tables: list[dict[str, Any]] = []
    lines = markdown_text.splitlines()
    current_section = ""
    current_heading = ""
    index = 0
    table_index = 0
    while index < len(lines):
        line = lines[index]
        stripped = line.strip()
        if stripped.startswith("#"):
            heading = stripped.lstrip("#").strip()
            current_heading = heading or current_heading
            if stripped.startswith("##"):
                current_section = heading or current_section
            index += 1
            continue
        if stripped.startswith("|"):
            block: list[str] = []
            while index < len(lines) and lines[index].strip().startswith("|"):
                block.append(lines[index])
                index += 1
            parsed = [_split_markdown_table_cells(row) for row in block]
            parsed = [row for row in parsed if row and not _is_markdown_separator_row(row)]
            if len(parsed) >= 2:
                table_index += 1
                headers = parsed[0]
                rows = parsed[1:8]
                title = current_heading or f"表格 {table_index}"
                tables.append(
                    {
                        "table_id": f"T{table_index:02d}",
                        "title": title,
                        "section": current_section,
                        "headers": headers,
                        "sample_rows": rows,
                    }
                )
            continue
        index += 1
    return tables


def _table_reader_theme(title: str, headers: list[str]) -> str:
    text = f"{title} {' '.join(headers)}"
    if any(token in text for token in ("路线", "运费", "履约", "延迟")):
        return "路线、履约与成本压力"
    if any(token in text for token in ("卖家", "店铺", "责任")):
        return "卖家承接质量与责任分层"
    if any(token in text for token in ("类目", "品类", "SKU", "商品")):
        return "商品与类目结构治理"
    if any(token in text for token in ("指标", "KPI", "metric")):
        return "派生指标如何进入经营判断"
    if any(token in text for token in ("异常", "低评", "体验", "评论")):
        return "异常体验与客户感知修复"
    return "经营优先级与本周动作"


def _action_from_table_rows(headers: list[str], rows: list[list[str]]) -> str:
    action_indexes = [
        idx
        for idx, header in enumerate(headers)
        if any(token in str(header) for token in ("动作", "建议", "责任", "检查", "管理含义", "判断"))
    ]
    fragments: list[str] = []
    for row in rows[:3]:
        for idx in action_indexes:
            if idx < len(row):
                cell = _clean_reader_text(row[idx], limit=90)
                if cell:
                    fragments.append(cell)
        if len(fragments) >= 3:
            break
    if fragments:
        return "；".join(fragments[:3])
    return "把表内排序靠前、费率异常、评分偏低或动作列已标出的对象放入本周复盘清单。"


def _evidence_from_table_rows(headers: list[str], rows: list[list[str]]) -> list[str]:
    evidence: list[str] = []
    for row in rows[:4]:
        if not row:
            continue
        object_name = _clean_reader_text(row[0], limit=80)
        numeric_cells = [
            _clean_reader_text(cell, limit=50)
            for cell in row[1:]
            if re.search(r"\d", str(cell or ""))
        ][:3]
        if object_name and numeric_cells:
            evidence.append(f"{object_name}: " + " / ".join(numeric_cells))
    return evidence[:4]


def _build_table_reader_card(table: dict[str, Any]) -> dict[str, Any]:
    title = _clean_reader_text(table.get("title"), limit=100)
    headers = [str(item) for item in list(table.get("headers") or [])]
    rows = [list(row) for row in list(table.get("sample_rows") or []) if isinstance(row, list)]
    theme = _table_reader_theme(title, headers)
    first_object = _clean_reader_text(rows[0][0] if rows and rows[0] else "", limit=80)
    evidence = _evidence_from_table_rows(headers, rows)
    how_to_read = f"先按表内对象排序看谁最先影响本期结果，再横向比较规模、费率、评分和动作列，不把它当成普通明细清单。"
    if first_object:
        how_to_read += f" 首个需要确认的对象是 `{first_object}`。"
    business_meaning = f"这张表服务于“{theme}”：它把指标读数翻译成对象池、优先级和管理责任，读者应从中判断本周先处理哪一组对象。"
    management_action = _action_from_table_rows(headers, rows)
    return {
        "table_id": str(table.get("table_id") or ""),
        "title": title,
        "section": _clean_reader_text(table.get("section"), limit=100),
        "theme": theme,
        "how_to_read": how_to_read,
        "business_meaning": business_meaning,
        "management_action": management_action,
        "evidence": evidence,
        "required_html_class": "table-reading-card",
        "required_labels": ["怎么看：", "说明什么：", "下一步动作："],
    }


def _metric_usage_entries(metric_payload: dict[str, Any], markdown_text: str) -> list[dict[str, Any]]:
    metrics: list[dict[str, Any]] = []
    for bucket_key, target in (
        ("body_primary_metrics", "正文主指标"),
        ("body_support_metrics", "正文支撑指标"),
        ("appendix_metrics", "附录指标"),
    ):
        for item in list(metric_payload.get(bucket_key) or []):
            if not isinstance(item, dict):
                continue
            metric_id = str(item.get("metric_id") or "").strip()
            if not metric_id:
                continue
            metrics.append(
                {
                    "metric_id": metric_id,
                    "metric_name": _clean_reader_text(item.get("metric_name"), limit=80),
                    "consumption_target": target,
                    "target_sections": _stringify_list_like(item.get("target_sections"))[:6],
                    "used_in_markdown": metric_id in markdown_text or str(item.get("metric_name") or "") in markdown_text,
                    "reader_instruction": "在 HTML 的指标使用地图中说明该指标在哪个章节/表格被使用，以及它如何改变本周动作优先级。",
                }
            )
    seen: set[str] = set()
    unique_metrics: list[dict[str, Any]] = []
    for item in metrics:
        metric_id = str(item.get("metric_id") or "")
        if metric_id in seen:
            continue
        seen.add(metric_id)
        unique_metrics.append(item)
    return unique_metrics


def _write_ecommerce_reader_interpretation_pack(workspace: Path) -> tuple[Path, Path, dict[str, Any]]:
    markdown_path = workspace / "05_report.md"
    chart_insights_path = workspace / "chart_insights.json"
    metric_consumption_path = workspace / "01b_ecommerce_metric_consumption_index.json"
    markdown_text = _read_text_artifact(markdown_path)
    chart_payload = _read_json_if_present(chart_insights_path, "chart_insights")
    metric_payload = _read_json_if_present(metric_consumption_path, "ecommerce_metric_consumption")

    table_cards = [
        _build_table_reader_card(table)
        for table in _extract_markdown_tables_for_reader_pack(markdown_text)
    ]
    figure_cards: list[dict[str, Any]] = []
    for index, item in enumerate(list(chart_payload.get("figures") or []), start=1):
        if not isinstance(item, dict):
            continue
        figure_id = str(item.get("figure_id") or Path(str(item.get("relative_path") or "")).name).strip()
        if not figure_id:
            continue
        figure_cards.append(
            {
                "figure_id": figure_id,
                "relative_path": str(item.get("relative_path") or "").strip(),
                "chart_type": str(item.get("chart_type") or "").strip(),
                "figure_label": f"图 {index:02d}",
                "observation": _clean_reader_text(item.get("observation"), limit=520),
                "implication": _clean_reader_text(item.get("implication"), limit=520),
                "action": _clean_reader_text(item.get("action"), limit=520),
                "validation": f"核对 `{figure_id}` 的对象、数值和证据编号是否与正文一致。",
                "boundary": "该图只用于当前样本窗口和对象池，不外推成长期结论。",
                "follow_up_question": "若与正文结论冲突，回查对应表格、对象池和证据链。",
                "evidence_numbers": [_clean_reader_text(value, limit=120) for value in list(item.get("evidence_numbers") or [])[:5]],
                "required_html_class": "figure-notes",
                "required_labels": ["观察：", "含义：", "动作：", "证据：", "验证：", "边界：", "后续问题："],
            }
        )

    metric_usage = _metric_usage_entries(metric_payload, markdown_text)
    payload = {
        "stage_id": "ecommerce_reader_interpretation_pack",
        "source_markdown": "05_report.md",
        "table_count": len(table_cards),
        "figure_count": len(figure_cards),
        "metric_count": len(metric_usage),
        "table_reading_cards": table_cards,
        "figure_notes": figure_cards,
        "metric_usage_map": metric_usage,
        "html_contract": {
            "table_card_class": "table-reading-card",
            "figure_note_class": "figure-notes",
            "metric_usage_class": "metric-usage-map",
            "table_required_labels": ["怎么看：", "说明什么：", "下一步动作："],
            "figure_required_labels": ["观察：", "含义：", "动作：", "证据："],
        },
    }
    json_path = workspace / "05b_ecommerce_reader_interpretation_pack.json"
    md_path = workspace / "05b_ecommerce_reader_interpretation_pack.md"
    _write_normalized_json(json_path, payload)
    md_lines = [
        "# 电商报告读者解释包",
        "",
        f"- 表格解释卡数量：{len(table_cards)}",
        f"- 图表解释卡数量：{len(figure_cards)}",
        f"- 指标使用项数量：{len(metric_usage)}",
        "",
        "## 表格怎么读",
    ]
    for card in table_cards[:40]:
        md_lines.extend(
            [
                f"### {card.get('table_id')} {card.get('title')}",
                f"- 怎么看：{card.get('how_to_read')}",
                f"- 说明什么：{card.get('business_meaning')}",
                f"- 下一步动作：{card.get('management_action')}",
            ]
        )
    md_lines.append("")
    md_lines.append("## 图表怎么读")
    for card in figure_cards[:20]:
        md_lines.extend(
            [
                f"### {card.get('figure_label')} {card.get('figure_id')}",
                f"- 观察：{card.get('observation')}",
                f"- 含义：{card.get('implication')}",
                f"- 动作：{card.get('action')}",
                f"- 验证：{card.get('validation')}",
                f"- 边界：{card.get('boundary')}",
                f"- 后续问题：{card.get('follow_up_question')}",
                "- 证据：" + "；".join(list(card.get("evidence_numbers") or [])[:3]),
            ]
        )
    md_lines.append("")
    md_lines.append("## 指标使用地图")
    for item in metric_usage:
        md_lines.append(
            f"- `{item.get('metric_id')}` / {item.get('metric_name')} / {item.get('consumption_target')}: "
            + "、".join(list(item.get("target_sections") or [])[:4])
        )
    md_path.write_text("\n".join(md_lines).strip() + "\n", encoding="utf-8")
    return json_path, md_path, payload


def _read_text_if_present(path: Path, *, limit: int = 12000) -> str:
    if not path.exists():
        return ""
    try:
        text = _read_text_artifact(path)
    except Exception:
        return ""
    if limit > 0 and len(text) > limit:
        return text[:limit] + "\n\n[truncated]"
    return text


def _canonical_ecommerce_metric_contract(metric_payload: dict[str, Any]) -> list[dict[str, Any]]:
    contract: list[dict[str, Any]] = []
    for bucket_key, target in (
        ("body_primary_metrics", "body_primary"),
        ("body_support_metrics", "body_support"),
        ("appendix_metrics", "appendix_only"),
    ):
        for item in list(metric_payload.get(bucket_key) or []):
            if not isinstance(item, dict):
                continue
            metric_id = str(item.get("metric_id") or "").strip()
            if not metric_id:
                continue
            forbidden_uses: list[str] = []
            if target == "appendix_only":
                forbidden_uses.extend(
                    [
                        "main_body_decision",
                        "headline_conclusion",
                        "frontline_validation_metric",
                        "why_now_primary_reason",
                        "action_priority_reason",
                    ]
                )
            if metric_id in {"cpm_derived", "cpa_derived"}:
                forbidden_uses.extend(
                    [
                        "main_body_decision",
                        "headline_conclusion",
                        "frontline_validation_metric",
                        "why_now_primary_reason",
                    ]
                )
            allowed_locations = (
                ["main_body", "metric_usage_map", "frontline_validation_metric", "appendix"]
                if target in {"body_primary", "body_support"}
                else ["appendix", "technical_retention", "risk_note", "blocked_or_observation_item"]
            )
            contract.append(
                {
                    "metric_id": metric_id,
                    "metric_name": str(item.get("metric_name") or "").strip(),
                    "value": str(item.get("value") or "").strip(),
                    "formula": str(item.get("formula") or "").strip(),
                    "business_meaning": str(item.get("business_meaning") or "").strip(),
                    "consumption_target": target,
                    "target_sections": _stringify_list_like(item.get("target_sections"))[:10],
                    "allowed_locations": allowed_locations,
                    "forbidden_uses": list(dict.fromkeys(forbidden_uses)),
                    "weak_semantic_metric": bool(target == "appendix_only" or metric_id in {"cpm_derived", "cpa_derived"}),
                }
            )
    return contract


def _write_ecommerce_metric_consistency_evidence_pack(workspace: Path) -> tuple[Path, Path, dict[str, Any]]:
    metric_path = workspace / "01b_ecommerce_metric_consumption_index.json"
    metric_payload = _read_json(metric_path, "ecommerce_metric_consumption")
    contract = _canonical_ecommerce_metric_contract(metric_payload)
    batch_summaries: list[dict[str, Any]] = []
    for index in range(1, 5):
        batch_json = workspace / f"04_ecommerce_section_batch_{index:02d}.json"
        payload = _read_json_if_present(batch_json, f"ecommerce_section_batch_{index:02d}")
        if payload:
            batch_summaries.append(
                {
                    "batch_index": index,
                    "path": batch_json.name,
                    "derived_metrics_used": list(payload.get("derived_metrics_used") or []),
                    "derived_metric_tables_used": list(payload.get("derived_metric_tables_used") or []),
                    "section_ids": _stringify_list_like(payload.get("section_ids") or payload.get("sections"))[:12],
                }
            )
    payload = {
        "stage_id": "ecommerce_metric_consistency_evidence_pack",
        "canonical_metric_contract": contract,
        "source_paths": {
            "metric_consumption_contract": metric_path.name,
            "derived_metric_execution": "01c_derived_metric_family_execution.json",
            "markdown_report": "05_report.md",
            "outline": "03_ecommerce_long_outline.json",
            "section_batches": [f"04_ecommerce_section_batch_{index:02d}.json" for index in range(1, 5)],
        },
        "audit_focus": [
            "01b_ecommerce_metric_consumption_index.json 是唯一指标分层真相源。",
            "body_primary/body_support 可以进入正文判断；appendix_only 只能进入附录、技术留档或风险提示。",
            "检查中文指标名、数值、公式和业务含义是否在正文中保持一致。",
            "检查是否只暴露 raw metric_id 而没有中文读者口径。",
            "cpm_derived/cpa_derived 等弱语义指标不得进入正文主判断。",
        ],
        "known_weak_metric_ids": ["cpm_derived", "cpa_derived"],
        "report_excerpt": _read_text_if_present(workspace / "05_report.md", limit=18000),
        "outline_summary": _read_json_if_present(workspace / "03_ecommerce_long_outline.json", "ecommerce_long_outline"),
        "batch_summaries": batch_summaries,
    }
    json_path = workspace / "05c_metric_consistency_evidence_pack.json"
    md_path = workspace / "05c_metric_consistency_evidence_pack.md"
    _write_normalized_json(json_path, payload)
    md_lines = [
        "# 电商指标口径一致性证据包",
        "",
        "## 审计目标",
        "- 由 Codex CLI runtime 读取 01b 合同和 05_report.md，判断指标分层、读者口径和数值口径是否漂移。",
        "- 后端只提供 canonical contract，不替代 CLI 做语义判断。",
        "",
        "## 指标合同",
    ]
    for metric in contract:
        md_lines.append(
            f"- `{metric.get('metric_id')}` / {metric.get('metric_name')} / {metric.get('consumption_target')} / 禁止用途："
            + "、".join(list(metric.get("forbidden_uses") or []) or ["无"])
        )
    md_path.write_text("\n".join(md_lines).strip() + "\n", encoding="utf-8")
    return json_path, md_path, payload


