def _validate_ecommerce_runtime_consistency_audit(
    markdown_path: Path,
    json_path: Path,
    stage_name: str,
) -> dict[str, Any]:
    payload = _validate_required_pair(markdown_path, json_path, stage_name)
    required_keys = [
        "canonical_metric_contract",
        "report_body_findings",
        "html_findings",
        "frontline_findings",
        "blocking_issues",
        "retry_recommendations",
        "passed",
    ]
    missing = [key for key in required_keys if key not in payload]
    if missing:
        raise ValueError(f"{stage_name} missing required keys: {', '.join(missing)}")
    for key in [
        "canonical_metric_contract",
        "report_body_findings",
        "html_findings",
        "frontline_findings",
        "blocking_issues",
        "retry_recommendations",
    ]:
        if not isinstance(payload.get(key), list):
            raise ValueError(f"{stage_name}.{key} must be a list.")
    blocking_issues = list(payload.get("blocking_issues") or [])
    passed = bool(payload.get("passed"))
    if passed and blocking_issues:
        raise ValueError(f"{stage_name} cannot pass with blocking_issues present.")
    if not passed:
        issue_summary = "; ".join(
            str(item.get("issue_type") or item.get("metric_id") or item)
            for item in blocking_issues[:5]
            if isinstance(item, dict) or str(item).strip()
        )
        raise ValueError(f"{stage_name} failed consistency audit: {issue_summary or 'passed=false'}")
    return payload


def _frontline_text(value: Any, *, limit: int = 260) -> str:
    return _clean_reader_text(value, limit=limit).replace("\n", " ").strip()


def _frontline_action_rows(workspace: Path) -> list[dict[str, Any]]:
    roadmap = _read_json_if_present(workspace / "ecommerce_action_roadmap.json", "ecommerce_action_roadmap")
    action_table = _read_json_if_present(workspace / "ecommerce_action_table.json", "ecommerce_action_table")
    rows: list[dict[str, Any]] = []

    for item in list(roadmap.get("seven_day_ecommerce_action_table") or []):
        if not isinstance(item, dict):
            continue
        rows.append(
            {
                "horizon": "7日执行",
                "priority": _frontline_text(item.get("优先级") or item.get("priority"), limit=40),
                "object": _frontline_text(item.get("对象") or item.get("对象名称") or item.get("object"), limit=90),
                "action": _frontline_text(item.get("动作") or item.get("最终动作") or item.get("action"), limit=120),
                "owner": _frontline_text(item.get("负责人角色") or item.get("owner"), limit=90),
                "deadline": _frontline_text(item.get("截止时间") or item.get("时间要求") or item.get("deadline"), limit=60),
                "input_data": _frontline_text(item.get("输入数据") or item.get("触发证据"), limit=260),
                "check_metric": _frontline_text(item.get("验证标准") or item.get("验证指标"), limit=140),
                "guardrail": _frontline_text(item.get("护栏指标") or item.get("被拦截动作"), limit=160),
            }
        )

    for item in list(roadmap.get("thirty_day_ecommerce_experiment_backlog") or []):
        if not isinstance(item, dict):
            continue
        rows.append(
            {
                "horizon": "30日实验",
                "priority": _frontline_text(item.get("实验编号") or item.get("优先级"), limit=40),
                "object": _frontline_text(item.get("目标对象") or item.get("对象"), limit=90),
                "action": _frontline_text(item.get("实验动作") or item.get("动作"), limit=120),
                "owner": "商品运营 / 数据分析 / 履约协同",
                "deadline": _frontline_text(item.get("预计周期") or "14-30天", limit=60),
                "input_data": _frontline_text(item.get("实验假设") or item.get("数据依赖"), limit=260),
                "check_metric": _frontline_text(item.get("核心指标") or item.get("成功标准"), limit=140),
                "guardrail": _frontline_text(item.get("护栏指标") or item.get("失败后处理"), limit=160),
            }
        )

    if not rows and isinstance(action_table, list):
        for item in action_table:
            if not isinstance(item, dict):
                continue
            rows.append(
                {
                    "horizon": "7日执行",
                    "priority": _frontline_text(item.get("优先级"), limit=40),
                    "object": _frontline_text(item.get("对象名称") or item.get("对象层级"), limit=90),
                    "action": _frontline_text(item.get("最终动作"), limit=120),
                    "owner": _frontline_text(item.get("负责人角色"), limit=90),
                    "deadline": _frontline_text(item.get("时间要求"), limit=60),
                    "input_data": _frontline_text(item.get("触发证据"), limit=260),
                    "check_metric": _frontline_text(item.get("验证指标") or item.get("成功标准"), limit=140),
                    "guardrail": _frontline_text(item.get("被拦截动作"), limit=160),
                }
            )
    return rows


