def _read_limited_text(path: Path, *, limit_chars: int = 16000) -> str:
    if not path.exists() or not path.is_file():
        return ""
    try:
        return path.read_text(encoding="utf-8-sig", errors="ignore").strip()[:limit_chars]
    except Exception:
        return ""


def _dict_or_empty(value: Any) -> dict[str, Any]:
    return dict(value) if isinstance(value, dict) else {}


def _compact_visual_reference_for_reverse_spec(visual_reference: dict[str, Any]) -> dict[str, Any]:
    return {
        "source_is_real_pdf": bool(visual_reference.get("source_is_real_pdf")),
        "source_page_count": int(visual_reference.get("source_page_count") or 0),
        "preview_page_count": int(visual_reference.get("preview_page_count") or 0),
        "visual_reverse_source": str(visual_reference.get("visual_reverse_source") or ""),
        "preview_image_paths": list(visual_reference.get("preview_image_paths") or [])[:6],
        "dominant_palette_hint": list(visual_reference.get("dominant_palette_hint") or [])[:10],
        "page_orientation_summary": _dict_or_empty(visual_reference.get("page_orientation_summary")),
        "page_size_summary": _dict_or_empty(visual_reference.get("page_size_summary")),
        "margin_rhythm": _dict_or_empty(visual_reference.get("margin_rhythm")),
        "title_footer_rhythm": _dict_or_empty(visual_reference.get("title_footer_rhythm")),
        "suspected_area_stats": _dict_or_empty(visual_reference.get("suspected_area_stats")),
        "keyword_counts": _dict_or_empty(visual_reference.get("keyword_counts")),
        "text_density": _dict_or_empty(visual_reference.get("text_density")),
        "image_preview_stats": _dict_or_empty(visual_reference.get("image_preview_stats")),
        "historical_report_family_hint": str(visual_reference.get("historical_report_family_hint") or ""),
        "family_signal_tokens": list(visual_reference.get("family_signal_tokens") or [])[:16],
        "visual_style_tokens": list(visual_reference.get("visual_style_tokens") or [])[:20],
        "suggested_visual_system": _dict_or_empty(visual_reference.get("suggested_visual_system")),
    }


def _compact_logic_reference_for_reverse_spec(logic_reference: dict[str, Any]) -> dict[str, Any]:
    metrics = _dict_or_empty(logic_reference.get("logic_metrics"))
    return {
        "available": bool(logic_reference.get("available")),
        "source_name": str(logic_reference.get("source_name") or ""),
        "dominant_logic_pattern": str(logic_reference.get("dominant_logic_pattern") or ""),
        "logic_metrics": {
            "page_count": int(metrics.get("page_count") or 0),
            "answer_first_title_likelihood": float(metrics.get("answer_first_title_likelihood") or 0),
            "exhibit_reference_density": float(metrics.get("exhibit_reference_density") or 0),
            "action_density": float(metrics.get("action_density") or 0),
            "causal_density": float(metrics.get("causal_density") or 0),
            "contrast_density": float(metrics.get("contrast_density") or 0),
            "source_note_density": float(metrics.get("source_note_density") or 0),
        },
        "role_counts": _dict_or_empty(logic_reference.get("role_counts")),
        "title_chain": _compact_structured_items(logic_reference.get("title_chain"), key_name="title", limit=12),
        "exhibit_inventory": _compact_structured_items(logic_reference.get("exhibit_inventory"), key_name="exhibit", limit=12),
        "logic_flow_contract": _dict_or_empty(logic_reference.get("logic_flow_contract")),
        "argument_arc": list(logic_reference.get("argument_arc") or [])[:10],
        "page_transition_rules": _compact_structured_items(logic_reference.get("page_transition_rules"), key_name="transition", limit=14),
        "question_tree_seed": _dict_or_empty(logic_reference.get("question_tree_seed")),
        "claim_evidence_action_chains": _compact_structured_items(
            logic_reference.get("claim_evidence_action_chains"),
            key_name="chain",
            limit=12,
        ),
        "logic_samples": {
            key: list(value or [])[:6]
            for key, value in _dict_or_empty(logic_reference.get("logic_samples")).items()
        },
        "logic_rules_for_adaptation": list(logic_reference.get("logic_rules_for_adaptation") or [])[:8],
        "must_preserve_logic": list(logic_reference.get("must_preserve_logic") or [])[:8],
        "must_avoid_logic": list(logic_reference.get("must_avoid_logic") or [])[:8],
    }


def _write_historical_reverse_spec_context(
    *,
    workspace: Path,
    historical_report_path: Path,
    current_report_context_path: Path,
    visual_reference_path: Path,
    historical_text_excerpt_path: Path,
    output_path: Path,
) -> dict[str, Any]:
    current_context = _read_json(current_report_context_path, "historical_current_report_context") if current_report_context_path.exists() else {}
    visual_reference = _read_json(visual_reference_path, "historical_visual_reference") if visual_reference_path.exists() else {}
    logic_reference_path = workspace / "historical_logic_reference.json"
    logic_reference = _read_json(logic_reference_path, "historical_logic_reference") if logic_reference_path.exists() else _dict_or_empty(current_context.get("historical_logic_reference"))
    text_excerpt = _read_limited_text(historical_text_excerpt_path, limit_chars=18000)
    if not text_excerpt and historical_report_path.suffix.lower() in {".txt", ".md", ".html", ".htm"}:
        text_excerpt = _read_limited_text(historical_report_path, limit_chars=18000)
    payload = {
        "workspace_path": str(workspace.resolve()),
        "purpose": "compressed_real_pdf_reverse_spec_context",
        "historical_source": {
            "source_name": historical_report_path.name,
            "source_path": str(historical_report_path.resolve()),
            "source_suffix": historical_report_path.suffix.lower(),
            "source_is_real_pdf": bool(visual_reference.get("source_is_real_pdf")),
            "source_page_count": int(visual_reference.get("source_page_count") or 0),
            "preview_page_count": int(visual_reference.get("preview_page_count") or 0),
        },
        "visual_reference_path": str(visual_reference_path.resolve()) if visual_reference_path.exists() else "",
        "visual_reference_summary": _compact_visual_reference_for_reverse_spec(visual_reference),
        "logic_reference_path": str(logic_reference_path.resolve()) if logic_reference_path.exists() else "",
        "logic_reference_summary": _compact_logic_reference_for_reverse_spec(logic_reference),
        "text_excerpt": {
            "path": str(historical_text_excerpt_path.resolve()) if historical_text_excerpt_path.exists() else "",
            "available": bool(text_excerpt),
            "char_count": len(text_excerpt),
            "excerpt": text_excerpt[:12000],
        },
        "current_report_summary": {
            "dataset_name": str(current_context.get("dataset_name") or ""),
            "sheet_name": str(current_context.get("sheet_name") or ""),
            "historical_report_name": str(current_context.get("historical_report_name") or ""),
            "user_requirement": str(current_context.get("user_requirement") or "")[:1200],
            "target_audience": str(current_context.get("target_audience") or ""),
            "core_purpose": str(current_context.get("core_purpose") or "")[:1200],
            "target_page_count_min": current_context.get("target_page_count_min"),
            "target_page_count_max": current_context.get("target_page_count_max"),
            "executive_summary": list(current_context.get("executive_summary") or [])[:8],
            "section_summaries": _compact_structured_items(current_context.get("section_summaries"), key_name="section", limit=8),
            "column_summaries": _compact_structured_items(current_context.get("column_summaries"), key_name="column", limit=12),
        },
        "required_reverse_spec_contract": {
            "json_files_to_create": ["01_historical_reverse_spec.json"],
            "markdown_files_to_create": ["01_historical_reverse_spec.md"],
            "required_json_fields": [
                "source_name",
                "historical_report_family",
                "template_signals",
                "section_blueprint",
                "logic_blueprint",
                "logic_flow_contract",
                "argument_arc",
                "page_role_taxonomy",
                "narrative_progression_rules",
                "page_transition_rules",
                "claim_evidence_action_rules",
                "page_taxonomy",
                "visual_furniture_rules",
                "exhibit_rules",
                "source_footer_rules",
                "data_expression_rules",
                "appendix_rules",
                "tone_rules",
                "must_preserve",
                "must_avoid",
                "unsupported_or_softened_sections",
            ],
            "allowed_families": [
                "brand_analysis_deck_yili_family",
                "mckinsey_consulting_deck_family",
                "management_report_light_blue_family",
                "dark_editorial_management_family",
                "generic_chinese_analysis_deck",
            ],
        },
        "runtime_guidance": {
            "read_order": [
                "historical_reverse_spec_context.json",
                "historical_visual_reference.json",
                "historical_logic_reference.json",
                "historical_report_text_excerpt.md",
                "source PDF only if the compressed context is insufficient",
            ],
            "do_not_copy": [
                "source brand logo",
                "old report facts",
                "old report numeric values",
                "old dates",
                "old conclusions",
            ],
            "write_language": "zh-CN",
            "goal": "Extract reusable page system, exhibit rhythm, visual furniture, narrative grammar, logic progression, claim-evidence-action linkage, and source/footer rules from a real PDF.",
        },
    }
    _write_normalized_json(output_path, payload)
    return payload


