def _format_metric_line(item: dict[str, Any]) -> str:
    label = str(item.get("metric_label") or item.get("display_label") or item.get("metric_raw_key") or item.get("raw_key") or "指标")
    raw_key = str(item.get("metric_raw_key") or item.get("raw_key") or "")
    metric_type = str(item.get("metric_type") or item.get("aggregation") or "")
    mean = item.get("mean")
    total = item.get("sum")
    value_parts = []
    if isinstance(total, (int, float)):
        value_parts.append(f"合计 {total:,.2f}")
    if isinstance(mean, (int, float)):
        value_parts.append(f"均值 {mean:,.4f}" if abs(mean) < 1 else f"均值 {mean:,.2f}")
    suffix = "；".join(value_parts) if value_parts else "已纳入本期经营判断"
    return f"- `{raw_key}`（{label}，{metric_type}）：{suffix}"


def _write_fallback_historical_style_report(
    *,
    rewrite_context: dict[str, Any],
    markdown_path: Path,
    json_path: Path,
) -> dict[str, Any]:
    dataset = dict(rewrite_context.get("dataset") or {})
    storyline = dict(rewrite_context.get("storyline_contract") or {})
    evidence = dict(rewrite_context.get("data_evidence") or {})
    page_plan = dict(rewrite_context.get("page_plan_summary") or {})
    metrics = [item for item in list(evidence.get("metric_priorities_seed") or []) if isinstance(item, dict)]
    dimensions = [item for item in list(evidence.get("dimension_evidence_seed") or []) if isinstance(item, dict)]
    relationships = [item for item in list(evidence.get("relationship_seed") or []) if isinstance(item, dict)]
    actions = [item for item in list(evidence.get("action_candidate_seed") or []) if isinstance(item, dict)]
    family = str(rewrite_context.get("historical_report_family") or "generic_chinese_analysis_deck")
    title = f"{dataset.get('dataset_name') or '当前数据'}经营表现复盘"
    metric_lines = "\n".join(_format_metric_line(item) for item in metrics[:10]) or "- 当前数据包未提供可展开指标。"
    dimension_lines = []
    seen_dimension_labels: set[str] = set()
    for item in dimensions:
        label = str(item.get("dimension_label") or item.get("dimension_raw_key") or "维度")
        raw = str(item.get("dimension_raw_key") or "")
        if raw in seen_dimension_labels:
            continue
        seen_dimension_labels.add(raw)
        dimension_lines.append(f"- `{raw}`（{label}）：应作为独立分层页或矩阵页展开。")
        if len(dimension_lines) >= 6:
            break
    relationship_lines = []
    for item in relationships[:8]:
        relationship_lines.append(
            f"- {item.get('left_label') or item.get('left_raw_key')} × {item.get('right_label') or item.get('right_raw_key')}：相关系数 {item.get('correlation')}"
        )
    action_lines = []
    for item in actions[:10]:
        action_lines.append(
            f"- {item.get('priority') or 'medium'} / {item.get('action_type') or 'action'}：{item.get('object_label') or item.get('candidate_id')}"
        )
    page_lines = []
    for page in list(page_plan.get("page_type_sequence") or [])[:14]:
        if not isinstance(page, dict):
            continue
        page_lines.append(
            f"- P{page.get('page_number')}: {page.get('page_template_type')} - {page.get('title')}"
        )
    markdown = "\n\n".join(
        [
            f"# {title}",
            "## 结论先行\n当前数据支持把报告组织成一份短篇高密度咨询式经营 deck：先解释规模与效率的主线，再展开利润质量、复购服务和风险修复，最后落到本期可执行动作。历史样本只用于页面节奏、exhibit 编号、白底克制版式和 source/footer 语法；所有判断均来自当前数据证据包。",
            "## Exhibit 1：本期核心指标\n" + metric_lines,
            "## Exhibit 2：必须覆盖的经营维度\n" + ("\n".join(dimension_lines) if dimension_lines else "- 当前数据包未提供可展开维度。"),
            "## Exhibit 3：指标关系与管理解释\n" + ("\n".join(relationship_lines) if relationship_lines else "- 当前数据包未提供强关系信号。"),
            "## Exhibit 4：页面计划\n" + ("\n".join(page_lines) if page_lines else "- 页面计划缺失，按封面、目录、图表页、矩阵页、动作页和附录页组织。"),
            "## 管理动作建议\n" + ("\n".join(action_lines) if action_lines else "- 先围绕头部单元复制、尾部单元修复、指标关系解释三类动作组织。"),
            "## 边界与交付说明\n本文件由后端在 Codex rewrite 阶段遇到临时 runtime 503 后使用压缩数据上下文恢复生成，目的是不中断后续 chart/table/collage、HTML/CSS、PDF 和质量评分阶段。后续视觉渲染仍会使用历史 reverse spec、page plan 和确定性资产包。",
        ]
    )
    payload = {
        "title": title,
        "source_name": "historical_real_pdf_style_reference",
        "template_signals": [
            family,
            "answer_first_titles",
            "exhibit_rhythm",
            "source_footer_rhythm",
            "data_evidence_pack_driven",
        ],
        "adaptation_notes": [
            "使用 historical_rewrite_context.json 的压缩证据恢复正文。",
            "保留真实 PDF 的页面系统和咨询式 exhibit 节奏。",
            "不复制历史 PDF 的原始事实、旧数字或旧结论。",
        ],
        "adapted_report_markdown": markdown,
        "runtime_status": "fallback_markdown_from_rewrite_context",
    }
    markdown_path.write_text(markdown, encoding="utf-8")
    _write_normalized_json(json_path, payload)
    return payload


def _clean_historical_metric_label(item: dict[str, Any]) -> str:
    label = str(item.get("metric_label") or item.get("display_label") or item.get("localized_label") or item.get("metric_localized_label") or "").strip()
    raw = str(item.get("metric_raw_key") or item.get("raw_key") or "").strip()
    return localize_historical_text(label or raw or "指标")


def _clean_historical_dimension_label(item: dict[str, Any]) -> str:
    label = str(item.get("dimension_label") or item.get("dimension_localized_label") or "").strip()
    raw = str(item.get("dimension_raw_key") or "").strip()
    return localize_historical_text(label or raw or "维度")


def _format_clean_number(value: Any) -> str:
    if isinstance(value, (int, float)):
        if abs(float(value)) <= 2:
            return f"{float(value):.2%}"
        return f"{float(value):,.1f}"
    return ""


def _assert_historical_markdown_reader_quality(markdown_path: Path) -> None:
    text = _read_text_artifact(markdown_path)
    banned_tokens = [
        "scaleleader",
        "repairlaggard",
        "该页把当前数据证据压缩成一个可执行的管理判断",
        "重点是决定资源应投向哪里",
        "这一页应形成可执行的管理判断",
        "而不是只描述图形",
        "这页可视化把复杂结构压缩成单页经营判断",
        "历史 PDF 仅用于页面系统逆向",
        "排名ing",
    ]
    hits = [token for token in banned_tokens if token in text]
    if hits:
        raise ValueError("historical rewrite contains forbidden reader-facing tokens: " + ", ".join(hits[:8]))
    bullet_lines = [
        re.sub(r"\s+", " ", line.strip())
        for line in text.splitlines()
        if line.strip().startswith("-") and len(line.strip()) >= 18
    ]
    repeated = [line for line in set(bullet_lines) if bullet_lines.count(line) >= 3]
    if repeated:
        raise ValueError("historical rewrite contains repeated low-value bullets: " + " | ".join(repeated[:3]))
    diagnostics = inspect_reader_facing_text(
        text,
        label=str(markdown_path.name),
        min_visible_chars=400,
        min_cjk_ratio=0.18,
    )
    if int(diagnostics.get("mojibake_count") or 0) > 0:
        raise ValueError("historical rewrite contains mojibake.")
    if int(diagnostics.get("placeholder_count") or 0) > 0:
        raise ValueError("historical rewrite contains placeholder text.")
    if float(diagnostics.get("cjk_ratio") or 0) < 0.18:
        raise ValueError("historical rewrite Chinese ratio is too low.")


def _write_fallback_historical_style_report(  # type: ignore[no-redef]
    *,
    rewrite_context: dict[str, Any],
    markdown_path: Path,
    json_path: Path,
) -> dict[str, Any]:
    """Clean deterministic fallback for historical-style rewrite outages.

    The fallback must remain reader-facing. It should never mention runtime
    failures, HTTP errors, or internal pipeline recovery.
    """
    dataset = dict(rewrite_context.get("dataset") or {})
    evidence = dict(rewrite_context.get("data_evidence") or {})
    page_plan = dict(rewrite_context.get("page_plan_summary") or {})
    metrics = [item for item in list(evidence.get("metric_priorities_seed") or []) if isinstance(item, dict)]
    dimensions = [item for item in list(evidence.get("dimension_evidence_seed") or []) if isinstance(item, dict)]
    relationships = [item for item in list(evidence.get("relationship_seed") or []) if isinstance(item, dict)]
    actions = [item for item in list(evidence.get("action_candidate_seed") or []) if isinstance(item, dict)]
    family = str(rewrite_context.get("historical_report_family") or "generic_chinese_analysis_deck")
    dataset_name = localize_historical_text(dataset.get("dataset_name") or "")
    title = "当前消费经营表现复盘" if not dataset_name or "regression" in dataset_name.lower() else f"{dataset_name}经营表现复盘"

    metric_lines: list[str] = []
    for item in metrics[:12]:
        label = _clean_historical_metric_label(item)
        total = _format_clean_number(item.get("sum"))
        mean = _format_clean_number(item.get("mean"))
        parts = [part for part in (f"合计 {total}" if total else "", f"均值 {mean}" if mean else "") if part]
        metric_lines.append(f"- {label}：{'；'.join(parts) if parts else '已纳入本期经营判断'}")
    if not metric_lines:
        metric_lines.append("- 当前可展开指标较少，报告将优先从维度结构、对象分层和行动候选切入。")

    dimension_lines: list[str] = []
    seen_dimensions: set[str] = set()
    for item in dimensions:
        label = _clean_historical_dimension_label(item)
        if label in seen_dimensions:
            continue
        seen_dimensions.add(label)
        dimension_lines.append(f"- {label}：用于拆分头部贡献、尾部短板与资源优先级。")
        if len(dimension_lines) >= 6:
            break
    if not dimension_lines:
        dimension_lines.append("- 当前可展开维度较少，报告将以核心指标、关系网络和重点对象清单为主。")

    relationship_lines: list[str] = []
    for item in relationships[:8]:
        left = localize_historical_text(item.get("left_label") or item.get("left_raw_key") or "左侧指标")
        right = localize_historical_text(item.get("right_label") or item.get("right_raw_key") or "右侧指标")
        corr = _format_clean_number(item.get("correlation"))
        relationship_lines.append(f"- {left} × {right}：相关强度 {corr or '已识别'}，适合作为后续管理解释的线索。")
    if not relationship_lines:
        relationship_lines.append("- 当前强关系信号较弱，建议先通过分层贡献和异常项建立判断。")

    page_lines: list[str] = []
    for page in list(page_plan.get("page_type_sequence") or [])[:10]:
        if not isinstance(page, dict):
            continue
        page_no = page.get("page_number") or len(page_lines) + 1
        page_title = localize_historical_text(page.get("title") or "经营分析页")
        page_lines.append(f"- P{page_no}: {page_title}")
    if not page_lines:
        page_lines.append("- 按封面、目录、图表页、矩阵页、行动页和附录页组织。")

    action_lines: list[str] = []
    seen_actions: set[str] = set()
    action_type_map = {
        "scale_leader": "放大头部优势",
        "scaleleader": "放大头部优势",
        "repair_laggard": "修复尾部短板",
        "repairlaggard": "修复尾部短板",
        "monitor": "持续监控",
        "action": "管理动作",
    }
    object_replacements = {
        "region": "区域",
        "channel": "渠道",
        "consumer_segment": "消费客群",
        "dimension": "维度",
        "_": " ",
    }
    for item in actions[:16]:
        priority = localize_historical_text(item.get("priority") or "中优先级")
        obj = str(item.get("object_label") or item.get("candidate_id") or "重点对象")
        for old, new in object_replacements.items():
            obj = obj.replace(old, new)
        obj = localize_historical_text(obj)
        raw_action_type = str(item.get("action_type") or "管理动作").strip().lower()
        action_type = action_type_map.get(raw_action_type, localize_historical_text(raw_action_type or "管理动作"))
        action_key = f"{priority}|{obj}|{action_type}"
        if action_key in seen_actions:
            continue
        seen_actions.add(action_key)
        action_lines.append(f"- {priority}：围绕{obj}执行{action_type}，并用对应指标复核本期动作效果。")
        if len(action_lines) >= 8:
            break
    if not action_lines:
        action_lines.append("- 先围绕头部单元复制、尾部单元修复、指标关系解释三类动作组织。")

    markdown = "\n\n".join(
        [
            f"# {title}",
            "## 结论先行\n当前数据支持生成一份短篇高密度咨询式经营报告：先解释规模与效率主线，再展开利润质量、复购服务和风险修复，最后落到本期可执行动作。历史样本只用于页面节奏、图表编号、白底克制版式和来源页脚语法；所有判断均来自当前数据证据包。",
            "## 图表 1：本期核心指标\n" + "\n".join(metric_lines),
            "## 图表 2：必须覆盖的经营维度\n" + "\n".join(dimension_lines),
            "## 图表 3：指标关系与管理解释\n" + "\n".join(relationship_lines),
            "## 图表 4：页面计划\n" + "\n".join(page_lines),
            "## 管理动作建议\n" + "\n".join(action_lines),
            "## 交付说明\n本报告使用真实历史 PDF 的页面系统作为视觉参照，并使用当前数据证据包生成图表、表格、矩阵与行动建议；不复制历史报告的旧事实、旧数字、品牌标识或旧结论。",
        ]
    )
    markdown = localize_historical_text(markdown)
    payload = {
        "title": title,
        "source_name": "historical_real_pdf_style_reference",
        "template_signals": [
            family,
            "answer_first_titles",
            "exhibit_rhythm",
            "source_footer_rhythm",
            "data_evidence_pack_driven",
        ],
        "adaptation_notes": [
            "使用当前数据证据包恢复正文。",
            "保留真实 PDF 的页面系统和 exhibit 节奏。",
            "不复制历史 PDF 的原始事实、旧数字或旧结论。",
        ],
        "adapted_report_markdown": markdown,
        "runtime_status": "deterministic_reader_facing_fallback",
    }
    markdown_path.write_text(markdown, encoding="utf-8")
    _write_normalized_json(json_path, payload)
    return payload


def _write_historical_page_plan_context(
    *,
    workspace: Path,
    reverse_spec_payload: dict[str, Any],
    data_storyline_payload: dict[str, Any],
    data_manifest_payload: dict[str, Any],
    current_report_context_path: Path,
    visual_reference_path: Path,
    output_path: Path,
) -> dict[str, Any]:
    current_context = _read_json(current_report_context_path, "historical_current_report_context") if current_report_context_path.exists() else {}
    visual_reference = _read_json(visual_reference_path, "historical_visual_reference") if visual_reference_path.exists() else {}
    logic_reference_path = workspace / "historical_logic_reference.json"
    logic_reference = _read_json(logic_reference_path, "historical_logic_reference") if logic_reference_path.exists() else _dict_or_empty(current_context.get("historical_logic_reference"))
    report_logic_blueprint_path = workspace / "03_report_logic_blueprint.json"
    report_logic_blueprint = (
        _read_json(report_logic_blueprint_path, "historical_report_logic_blueprint")
        if report_logic_blueprint_path.exists()
        else {}
    )
