def _normalize_page_type_sequence(value: Any) -> list[dict[str, Any]]:
    raw_items = _mapping_to_structured_list(value, key_name="page_template_type")
    output: list[dict[str, Any]] = []
    for index, item in enumerate(raw_items, start=1):
        if isinstance(item, dict):
            normalized = dict(item)
        else:
            normalized = {"page_template_type": str(item or "").strip()}
        normalized.setdefault("page_number", index)
        page_type = str(
            normalized.get("page_template_type")
            or normalized.get("page_type")
            or normalized.get("type")
            or normalized.get("role")
            or ""
        ).strip()
        if page_type:
            normalized["page_template_type"] = page_type.replace(" ", "_").replace("-", "_")
        output.append(normalized)
    return output


def _historical_logic_role_for_page(page: dict[str, Any], *, index: int, total: int) -> str:
    explicit = str(page.get("logic_role") or page.get("argument_step") or page.get("page_logic_role") or "").strip()
    if explicit:
        return explicit
    template = str(page.get("page_template_type") or "").lower()
    expected = str(page.get("expected_conclusion_type") or "").lower()
    title = str(page.get("title") or page.get("headline") or "").lower()
    combined = f"{template} {expected} {title}"
    if index == 1 or "cover_page" in combined:
        return "opening_thesis"
    if "toc_navigation_page" in combined or "module_divider_page" in combined:
        return "business_question" if index <= max(3, total // 4) else "transition_navigation"
    if "appendix" in combined or index >= max(1, total - 1):
        return "appendix_support"
    if "recommend" in combined or "action" in combined or "summary_map_page" in combined:
        return "recommendation" if index >= max(4, int(total * 0.65)) else "management_implication"
    if "contrast" in combined or "matrix" in combined or "ranking" in combined or "scorecard" in combined:
        return "contrast_or_segmentation"
    if "funnel" in combined or "driver" in combined or "causal" in combined:
        return "driver_explanation"
    if "chart" in combined or "scatter" in combined or "heatmap" in combined or "visual" in combined:
        return "diagnostic_evidence"
    if index >= max(3, int(total * 0.7)):
        return "management_implication"
    return "diagnostic_evidence"


def _historical_claim_evidence_action_contract(page: dict[str, Any]) -> dict[str, Any]:
    role = str(page.get("logic_role") or page.get("argument_step") or "").strip()
    template = str(page.get("page_template_type") or "").strip()
    title = str(page.get("title") or page.get("headline") or "").strip()
    asset_source = str(page.get("primary_asset_source") or page.get("storyline_source") or "").strip()
    return {
        "claim_role": "answer_first_title" if role not in {"appendix_support", "transition_navigation"} else "navigation_or_support_claim",
        "evidence_role": "primary_exhibit_or_table" if template not in {"cover_page", "toc_navigation_page", "module_divider_page"} else "section_positioning",
        "action_role": "explicit_action_or_implication" if role in {"management_implication", "recommendation"} else "implied_next_step",
        "page_claim_seed": title[:240],
        "evidence_source_seed": asset_source or template,
    }


def _normalize_page_count_target(value: Any) -> dict[str, Any]:
    def _complete(target: int, payload: dict[str, Any] | None = None) -> dict[str, Any]:
        payload = dict(payload or {})
        minimum = int(payload.get("min") or payload.get("hard_floor") or max(1, target))
        maximum = int(payload.get("max") or payload.get("hard_ceiling") or max(minimum, target))
        recommended = int(payload.get("recommended") or target)
        hard_floor = int(payload.get("hard_floor") or minimum)
        hard_ceiling = int(payload.get("hard_ceiling") or maximum)
        if hard_ceiling < hard_floor:
            hard_ceiling = hard_floor
        if maximum < minimum:
            maximum = minimum
        return {
            **payload,
            "recommended": max(1, recommended),
            "min": max(1, minimum),
            "max": max(1, maximum),
            "hard_floor": max(1, hard_floor),
            "hard_ceiling": max(1, hard_ceiling),
            "family_target": str(payload.get("family_target") or f"{minimum}-{maximum} pages"),
        }

    if isinstance(value, dict):
        target_value = value.get("recommended") or value.get("target") or value.get("min") or value.get("max") or 12
        try:
            target = int(float(target_value))
        except Exception:
            target = 12
        return _complete(target, value)
    if isinstance(value, (int, float)) and not isinstance(value, bool):
        target = int(value)
        return _complete(target)
    text = str(value or "").strip()
    if text.isdigit():
        target = int(text)
        return _complete(target)
    return {}


def _normalize_historical_report_family(value: Any, payload: dict[str, Any] | None = None) -> str:
    allowed = {
        "bcg_consulting_quarterly_watch_family",
        "brand_analysis_deck_yili_family",
        "mckinsey_consulting_deck_family",
        "management_report_light_blue_family",
        "dark_editorial_management_family",
        "generic_chinese_analysis_deck",
    }
    text = str(value or "").strip()
    try:
        combined = json.dumps(payload or {}, ensure_ascii=False, default=str).lower()
    except Exception:
        combined = " ".join(str(item).lower() for item in list((payload or {}).values())[:24])
    if any(token in combined for token in ("bcg", "boston consulting", "quarterly watch")):
        return "bcg_consulting_quarterly_watch_family"
    if text in allowed:
        return text
    if "mckinsey" in combined or "consulting" in combined or "pyramid" in combined or "issue tree" in combined:
        return "mckinsey_consulting_deck_family"
    if "yili" in combined or "brand_analysis" in combined or ("brand" in combined and "deck" in combined):
        return "brand_analysis_deck_yili_family"
    if "dark" in combined or "editorial" in combined or "memo" in combined:
        return "dark_editorial_management_family"
    if "light blue" in combined or ("management" in combined and "blue" in combined):
        return "management_report_light_blue_family"
    return "generic_chinese_analysis_deck"


def _require_file(path: Path, stage_name: str) -> None:
    if not path.exists():
        raise FileNotFoundError(f"{stage_name} missing required artifact: {path.name}")
    if path.is_file() and path.stat().st_size <= 0:
        raise ValueError(f"{stage_name} produced an empty artifact: {path.name}")


def _validate_required_pair(markdown_path: Path, json_path: Path, stage_name: str) -> dict[str, Any]:
    _require_file(markdown_path, stage_name)
    _require_file(json_path, stage_name)
    return _read_json(json_path, stage_name)


def _validate_analysis_outline(markdown_path: Path, json_path: Path) -> dict[str, Any]:
    payload = _validate_required_pair(markdown_path, json_path, "analysis_outline")
    required = ["headline_thesis", "section_plan", "action_zones", "weak_evidence_zones"]
    missing = [key for key in required if key not in payload]
    if missing:
        raise ValueError(f"analysis_outline JSON missing required keys: {', '.join(missing)}")
    if not str(payload.get("headline_thesis") or "").strip():
        raise ValueError("analysis_outline JSON has an empty headline_thesis.")
    if not isinstance(payload.get("section_plan"), list) or not payload.get("section_plan"):
        raise ValueError("analysis_outline JSON must contain a non-empty section_plan list.")
    if not isinstance(payload.get("action_zones"), list):
        raise ValueError("analysis_outline JSON must contain an action_zones list.")
    if not isinstance(payload.get("weak_evidence_zones"), list):
        raise ValueError("analysis_outline JSON must contain a weak_evidence_zones list.")
    return payload


def _validate_evidence_map(markdown_path: Path, json_path: Path) -> dict[str, Any]:
    payload = _validate_required_pair(markdown_path, json_path, "evidence_map")
    if "section_evidence_map" not in payload:
        raise ValueError("evidence_map JSON missing required key: section_evidence_map")
    if "unsupported_claims" not in payload:
        raise ValueError("evidence_map JSON missing required key: unsupported_claims")
    section_map = payload.get("section_evidence_map")
    if not isinstance(section_map, list) or not section_map:
        raise ValueError("evidence_map JSON must contain a non-empty section_evidence_map list.")
    for index, item in enumerate(section_map, 1):
        if not isinstance(item, dict):
            raise ValueError(f"evidence_map section {index} must be an object.")
        for key in ("section_id", "section_title", "evidence_files"):
            if key not in item:
                raise ValueError(f"evidence_map section {index} missing required key: {key}")
        evidence_files = item.get("evidence_files")
        if not isinstance(evidence_files, list) or not evidence_files:
            raise ValueError(f"evidence_map section {index} must contain evidence_files.")
    if not isinstance(payload.get("unsupported_claims"), list):
        raise ValueError("evidence_map JSON unsupported_claims must be a list.")
    return payload


def _validate_appendix_intake(markdown_path: Path, json_path: Path) -> dict[str, Any]:
    payload = _validate_required_pair(markdown_path, json_path, "appendix_intake")
    required = [
        "appendix_summary",
        "available_tables",
        "method_signals",
        "upgrade_themes",
        "detail_dimensions",
        "business_actions_to_expand",
        "design_requirements",
    ]
    missing = [key for key in required if key not in payload]
    if missing:
        raise ValueError(f"appendix_intake JSON missing required keys: {', '.join(missing)}")
    for key in ("available_tables", "method_signals", "upgrade_themes", "detail_dimensions", "business_actions_to_expand"):
        if not isinstance(payload.get(key), list):
            raise ValueError(f"appendix_intake JSON `{key}` must be a list.")
    return payload


def _validate_historical_reverse_spec(markdown_path: Path, json_path: Path) -> dict[str, Any]:
    payload = _validate_required_pair(markdown_path, json_path, "historical_reverse_spec")
    required = [
        "source_name",
        "template_signals",
        "section_blueprint",
        "tone_rules",
        "must_preserve",
        "must_avoid",
        "unsupported_or_softened_sections",
    ]
    missing = [key for key in required if key not in payload]
    if missing:
        raise ValueError(f"historical_reverse_spec JSON missing required keys: {', '.join(missing)}")
    if not str(payload.get("source_name") or "").strip():
        raise ValueError("historical_reverse_spec JSON has an empty source_name.")
    family_context = dict(payload)
    visual_reference_path = json_path.parent / "historical_visual_reference.json"
    if visual_reference_path.exists():
        family_context["historical_visual_reference"] = _read_json(
            visual_reference_path,
            "historical_visual_reference",
        )
    payload["historical_report_family"] = _normalize_historical_report_family(
        payload.get("historical_report_family"),
        family_context,
    )
    payload["template_signals"] = _flatten_template_signals(payload.get("template_signals"))
    for key in ("tone_rules", "must_preserve", "must_avoid"):
        payload[key] = _stringify_list_like(payload.get(key))
    payload["page_taxonomy"] = _mapping_to_structured_list(
        payload.get("page_taxonomy") or payload.get("section_blueprint"),
        key_name="page_family",
    )
    payload["visual_furniture_rules"] = _mapping_to_structured_list(
        payload.get("visual_furniture_rules") or payload.get("must_preserve"),
        key_name="rule",
    )
    payload["data_expression_rules"] = _mapping_to_structured_list(
        payload.get("data_expression_rules") or payload.get("template_signals"),
        key_name="rule",
    )
    payload["appendix_rules"] = _mapping_to_structured_list(
        payload.get("appendix_rules") or payload.get("unsupported_or_softened_sections"),
        key_name="rule",
    )
    payload["logic_blueprint"] = _mapping_to_structured_list(
        payload.get("logic_blueprint") or payload.get("section_blueprint"),
        key_name="logic",
    )
    payload["narrative_progression_rules"] = _mapping_to_structured_list(
        payload.get("narrative_progression_rules") or payload.get("tone_rules"),
        key_name="rule",
    )
    payload["claim_evidence_action_rules"] = _mapping_to_structured_list(
        payload.get("claim_evidence_action_rules") or payload.get("data_expression_rules") or payload.get("template_signals"),
        key_name="rule",
    )
    if not isinstance(payload.get("logic_flow_contract"), dict):
        payload["logic_flow_contract"] = {
            "dominant_logic_pattern": "",
            "argument_arc": _stringify_list_like(payload.get("argument_arc") or payload.get("logic_blueprint")),
            "transition_rules": _mapping_to_structured_list(payload.get("page_transition_rules"), key_name="transition"),
            "claim_evidence_action_required": bool(payload.get("claim_evidence_action_rules")),
        }
    payload["argument_arc"] = _stringify_list_like(
        payload.get("argument_arc")
        or (payload.get("logic_flow_contract") or {}).get("argument_arc")
        or payload.get("logic_blueprint")
    )
    payload["page_role_taxonomy"] = _mapping_to_structured_list(
        payload.get("page_role_taxonomy")
        or (payload.get("logic_flow_contract") or {}).get("page_logic_role_contract")
        or payload.get("page_taxonomy"),
        key_name="role",
    )
    payload["page_transition_rules"] = _mapping_to_structured_list(
        payload.get("page_transition_rules")
        or (payload.get("logic_flow_contract") or {}).get("transition_rules")
        or payload.get("narrative_progression_rules"),
        key_name="transition",
    )
    if isinstance(payload.get("unsupported_or_softened_sections"), dict):
        payload["unsupported_or_softened_sections"] = [
            {"section": key, "rewrite_guidance": str(value).strip()}
            for key, value in payload["unsupported_or_softened_sections"].items()
            if str(key).strip() or str(value).strip()
        ]
    for key in (
        "template_signals",
        "section_blueprint",
        "tone_rules",
        "must_preserve",
        "must_avoid",
        "unsupported_or_softened_sections",
        "argument_arc",
        "page_role_taxonomy",
        "page_transition_rules",
    ):
        if not isinstance(payload.get(key), list):
            raise ValueError(f"historical_reverse_spec JSON `{key}` must be a list.")
    _write_normalized_json(json_path, payload)
    return payload


def _validate_historical_template_intake(markdown_path: Path, json_path: Path) -> dict[str, Any]:
    return _validate_historical_reverse_spec(markdown_path, json_path)


def _validate_historical_data_storyline_scan(markdown_path: Path, json_path: Path) -> dict[str, Any]:
    payload = _validate_required_pair(markdown_path, json_path, "historical_data_storyline_scan")
    required = [
        "headline_data_story",
        "metric_priorities",
        "dimension_priorities",
        "chart_recommendations",
        "table_recommendations",
        "action_candidates",
        "coverage_targets",
        "must_use_artifacts",
    ]
    missing = [key for key in required if key not in payload]
    if missing:
        raise ValueError(f"historical_data_storyline_scan JSON missing required keys: {', '.join(missing)}")
    headline = payload.get("headline_data_story")
    if isinstance(headline, dict):
        payload["headline_data_story"] = str(
            headline.get("primary")
            or headline.get("title")
            or headline.get("summary")
            or json.dumps(headline, ensure_ascii=False)
        ).strip()
    elif isinstance(headline, list):
        payload["headline_data_story"] = "；".join(str(item).strip() for item in headline if str(item).strip())
    if not str(payload.get("headline_data_story") or "").strip():
        raise ValueError("historical_data_storyline_scan JSON has an empty headline_data_story.")
    for key in (
        "metric_priorities",
        "dimension_priorities",
        "chart_recommendations",
        "table_recommendations",
        "action_candidates",
        "must_use_artifacts",
    ):
        payload[key] = _mapping_to_structured_list(payload.get(key), key_name="item")
        if not isinstance(payload.get(key), list):
            raise ValueError(f"historical_data_storyline_scan JSON `{key}` must be a list.")
    if not isinstance(payload.get("coverage_targets"), dict):
        payload["coverage_targets"] = {
            "minimum_metric_count": 6,
            "minimum_derived_metric_count": 0,
            "minimum_dimension_count": 3,
            "minimum_chart_pages": 6,
            "minimum_table_pages": 3,
            "minimum_action_pages": 1,
        }
    _write_normalized_json(json_path, payload)
    return payload


def _validate_historical_page_plan(
    markdown_path: Path,
    json_path: Path,
    *,
    historical_report_family: str = "",
) -> dict[str, Any]:
    payload = _validate_required_pair(markdown_path, json_path, "historical_page_plan")
    required = [
        "page_count_target",
        "page_type_sequence",
        "module_plan",
        "hero_pages",
        "required_visual_pages",
        "required_table_pages",
        "required_appendix_pages",
        "asset_usage_plan",
        "page_density_rules",
    ]
    missing = [key for key in required if key not in payload]
    if missing:
        raise ValueError(f"historical_page_plan JSON missing required keys: {', '.join(missing)}")
    payload["page_count_target"] = _normalize_page_count_target(payload.get("page_count_target"))
    if not isinstance(payload.get("page_count_target"), dict) or not payload.get("page_count_target"):
        raise ValueError("historical_page_plan JSON page_count_target must be an object.")
    payload["page_type_sequence"] = _normalize_page_type_sequence(payload.get("page_type_sequence"))
    payload["module_plan"] = _mapping_to_structured_list(payload.get("module_plan"), key_name="module")
    payload["hero_pages"] = _mapping_to_structured_list(payload.get("hero_pages"), key_name="page")
    payload["required_visual_pages"] = _mapping_to_structured_list(payload.get("required_visual_pages"), key_name="page")
    payload["required_table_pages"] = _mapping_to_structured_list(payload.get("required_table_pages"), key_name="page")
    payload["required_appendix_pages"] = _mapping_to_structured_list(payload.get("required_appendix_pages"), key_name="page")
    payload["asset_usage_plan"] = _mapping_to_structured_list(payload.get("asset_usage_plan"), key_name="group")
    payload["page_density_rules"] = _mapping_to_structured_list(payload.get("page_density_rules"), key_name="rule")
    for key in (
        "page_type_sequence",
        "module_plan",
        "hero_pages",
        "required_visual_pages",
        "required_table_pages",
        "required_appendix_pages",
        "asset_usage_plan",
        "page_density_rules",
    ):
        if not isinstance(payload.get(key), list):
            raise ValueError(f"historical_page_plan JSON `{key}` must be a list.")
    if len(payload.get("page_type_sequence") or []) < 8:
        raise ValueError("historical_page_plan JSON page_type_sequence is too short for a deck-style report.")
    total_pages = len(payload.get("page_type_sequence") or [])
    for index, item in enumerate(payload.get("page_type_sequence") or [], start=1):
        if not isinstance(item, dict):
            continue
        role = _historical_logic_role_for_page(item, index=index, total=total_pages)
        item["logic_role"] = role
        item["argument_step"] = str(item.get("argument_step") or role)
        if not isinstance(item.get("claim_evidence_action"), dict):
            item["claim_evidence_action"] = _historical_claim_evidence_action_contract(item)
    payload["logic_flow_plan"] = _mapping_to_structured_list(
        payload.get("logic_flow_plan")
        or [
            {
                "page_number": item.get("page_number"),
                "logic_role": item.get("logic_role"),
                "argument_step": item.get("argument_step"),
                "claim_evidence_action": item.get("claim_evidence_action"),
            }
            for item in payload.get("page_type_sequence") or []
            if isinstance(item, dict)
        ],
        key_name="page",
    )
    page_types = {
        str(
            (item or {}).get("page_template_type")
            or (item or {}).get("page_type")
            or (item or {}).get("type")
            or ""
        ).lower()
        for item in payload.get("page_type_sequence") or []
        if isinstance(item, dict)
    }
    if False and historical_report_family in {"brand_analysis_deck_yili_family", "mckinsey_consulting_deck_family"}:
        required_hints = {
            "cover": ["cover", "cover_page"],
            "toc": ["toc", "directory", "navigation", "toc_navigation_page"],
            "divider": ["divider", "module", "module_divider_page"],
            "chart": ["chart", "visual", "thesis_chart_page"],
            "comparison": ["comparison", "benchmark", "comparison_matrix_page"],
            "matrix": ["matrix", "table", "comparison_matrix_page"],
            "summary": ["summary", "summary_map", "summary_map_page"],
            "appendix": ["appendix", "glossary", "appendix_detail_table_page", "appendix_glossary_page"],
        }
        missing_hints = [
            label
            for label, hints in required_hints.items()
            if not any(any(hint in page_type for hint in hints) for page_type in page_types)
        ]
        if missing_hints:
            raise ValueError(
                f"historical_page_plan JSON lacks required {historical_report_family} page families: "
                + ", ".join(missing_hints)
            )
    _write_normalized_json(json_path, payload)
    return payload


def _validate_historical_style_report(markdown_path: Path, json_path: Path) -> dict[str, Any]:
    payload = _validate_required_pair(markdown_path, json_path, "historical_style_report")
    required = [
        "title",
        "source_name",
        "template_signals",
        "adaptation_notes",
        "adapted_report_markdown",
    ]
    missing = [key for key in required if key not in payload]
    if missing:
        raise ValueError(f"historical_style_report JSON missing required keys: {', '.join(missing)}")
    markdown_text = _normalize_artifact_text(_read_text_artifact(markdown_path))
    if len(markdown_text) < 400:
        raise ValueError("historical_style_report markdown is too short.")
    if not str(payload.get("title") or "").strip():
        raise ValueError("historical_style_report JSON has an empty title.")
    if not str(payload.get("source_name") or "").strip():
        raise ValueError("historical_style_report JSON has an empty source_name.")
    payload["template_signals"] = _flatten_template_signals(payload.get("template_signals"))
    payload["adaptation_notes"] = _stringify_list_like(payload.get("adaptation_notes"))
    if not isinstance(payload.get("template_signals"), list):
        raise ValueError("historical_style_report JSON template_signals must be a list.")
    if not isinstance(payload.get("adaptation_notes"), list):
        raise ValueError("historical_style_report JSON adaptation_notes must be a list.")
    json_markdown = _normalize_artifact_text(str(payload.get("adapted_report_markdown") or ""))
    if len(json_markdown) < 400:
        raise ValueError("historical_style_report JSON adapted_report_markdown is too short.")
    if markdown_text != json_markdown:
        raise ValueError("historical_style_report JSON adapted_report_markdown must match the markdown file.")
    markdown_quality = inspect_reader_facing_text(
        markdown_text,
        label="05_historical_style_report.md",
        artifact_type="markdown",
        min_visible_chars=400,
        min_cjk_ratio=0.18,
    )
    if not markdown_quality.get("ok"):
        raise ValueError(f"historical_style_report markdown failed reader-facing quality gate: {markdown_quality}")
    _write_normalized_json(json_path, payload)
    return payload


