def _should_use_existing_requirement_intent(workspace: Path, context_payload: dict[str, Any]) -> bool:
    if not bool(context_payload.get("prefer_existing_requirement_intent")):
        return False
    if (workspace / "existing_requirement_intent.json").is_file():
        return True
    requirement_payload = context_payload.get("requirement_intent")
    return isinstance(requirement_payload, dict) and bool(requirement_payload)


