def _chinese_metric_name(metric_id: str, metric_name: Any, metric_kind: str = "") -> str:
    metric_id = str(metric_id or "").strip()
    text = str(metric_name or "").strip()
    if _contains_cjk_text(text):
        return text
    if metric_id in _ECOMMERCE_METRIC_NAME_OVERRIDES:
        return _ECOMMERCE_METRIC_NAME_OVERRIDES[metric_id]
    if str(metric_kind or "").strip().lower() == "proxy_metric":
        return f"代理指标（{metric_id}）"
    return f"派生指标（{metric_id}）"


def _chinese_metric_meaning(metric_id: str, business_meaning: Any, metric_kind: str = "") -> str:
    metric_id = str(metric_id or "").strip()
    text = str(business_meaning or "").strip()
    if _contains_cjk_text(text):
        return text
    if metric_id in _ECOMMERCE_METRIC_MEANING_OVERRIDES:
        return _ECOMMERCE_METRIC_MEANING_OVERRIDES[metric_id]
    metric_name = _chinese_metric_name(metric_id, "", metric_kind)
    return f"{metric_name}用于补充判断电商经营效率、风险或结构变化。"


def _read_metric_table_rows(path: Path) -> list[dict[str, Any]]:
    if not path.is_file():
        return []
    try:
        frame = pd.read_csv(path, encoding="utf-8-sig")
    except Exception:
        return []
    rows: list[dict[str, Any]] = []
    for row in frame.fillna("").to_dict(orient="records"):
        if not isinstance(row, dict):
            continue
        metric_id = str(row.get("metric_id") or "").strip()
        metric_name = str(row.get("metric_name") or "").strip()
        if not metric_id and not metric_name:
            continue
        normalized = {str(key): value for key, value in row.items()}
        normalized["metric_id"] = metric_id or metric_name.lower().replace(" ", "_")
        normalized["metric_name"] = _chinese_metric_name(
            normalized["metric_id"],
            metric_name or metric_id,
            str(row.get("metric_kind") or ""),
        )
        normalized["business_meaning"] = _chinese_metric_meaning(
            normalized["metric_id"],
            row.get("business_meaning"),
            str(row.get("metric_kind") or ""),
        )
        normalized["source_columns"] = _normalize_metric_source_columns(row.get("source_columns"))
        rows.append(normalized)
    return rows


def _metric_value_is_meaningful(value: Any) -> bool:
    text = str(value or "").strip()
    if not text:
        return False
    if text.lower() in {"none", "null", "nan", "na", "n/a"}:
        return False
    try:
        numeric = float(text)
    except Exception:
        return True
    return abs(numeric) > 1e-12


def _metric_source_kind(metric: dict[str, Any]) -> str:
    return str(metric.get("metric_kind") or "").strip().lower()


def _metric_is_cross_profile_or_weak(metric: dict[str, Any]) -> bool:
    combined = " ".join(
        [
            str(metric.get("metric_id") or ""),
            str(metric.get("metric_name") or ""),
            str(metric.get("business_meaning") or ""),
            str(metric.get("formula") or ""),
        ]
    ).lower()
    tokens = [
        "cpm",
        "cpa",
        "ctr",
        "cpc",
        "roi",
        "media",
        "campaign",
        "曝光",
        "点击",
        "获客",
        "转化成本",
        "曝光获取成本",
    ]
    return any(token in combined for token in tokens)


def _target_sections_for_metric(metric: dict[str, Any], *, consumption_target: str) -> list[str]:
    combined = " ".join(
        [
            str(metric.get("metric_id") or ""),
            str(metric.get("metric_name") or ""),
            str(metric.get("business_meaning") or ""),
        ]
    ).lower()
    if consumption_target == "appendix_only":
        return ["S13"]
    if any(token in combined for token in ("contribution", "share", "金额贡献", "集中度", "mix")):
        return ["S03", "S05"]
    if any(token in combined for token in ("trend", "change", "趋势", "波动")):
        return ["S03", "S08"]
    if any(token in combined for token in ("quality", "评价", "review", "评分")):
        return ["S08", "S10"]
    return ["S03", "S11"] if consumption_target == "body_support" else ["S03", "S05", "S12"]


def _classify_ecommerce_metric_consumption(metric: dict[str, Any]) -> str:
    confidence = str(metric.get("confidence") or "").strip().lower()
    evidence_level = str(metric.get("evidence_level") or "").strip().upper()
    metric_kind = _metric_source_kind(metric)
    meaningful = _metric_value_is_meaningful(metric.get("value"))
    if metric_kind == "proxy_metric" or evidence_level.startswith("C_") or not meaningful or _metric_is_cross_profile_or_weak(metric):
        return "appendix_only"
    if confidence not in {"high", "medium"}:
        return "appendix_only"
    combined = " ".join(
        [
            str(metric.get("metric_id") or ""),
            str(metric.get("metric_name") or ""),
            str(metric.get("business_meaning") or ""),
        ]
    ).lower()
    if any(token in combined for token in ("contribution", "share", "金额贡献", "集中度", "mix")):
        return "body_primary"
    if any(token in combined for token in ("trend", "change", "趋势", "波动")):
        return "body_support"
    return "body_primary" if confidence == "high" and evidence_level.startswith(("A_", "B_")) else "body_support"


def _merge_metric_records(
    csv_rows: list[dict[str, Any]],
    json_rows: list[dict[str, Any]],
    *,
    csv_source_name: str,
    json_source_name: str,
) -> list[dict[str, Any]]:
    merged_by_id: dict[str, dict[str, Any]] = {}
    order: list[str] = []

    def _upsert(rows: list[dict[str, Any]], source_name: str, prefer_existing: bool) -> None:
        for row in rows:
            metric_id = str(row.get("metric_id") or "").strip()
            metric_name = str(row.get("metric_name") or "").strip()
            if not metric_id:
                metric_id = metric_name.lower().replace(" ", "_")
            if not metric_id:
                continue
            if metric_id not in order:
                order.append(metric_id)
            current = merged_by_id.get(metric_id, {})
            candidate = {
                "metric_id": metric_id,
                "metric_name": _chinese_metric_name(
                    metric_id,
                    metric_name or current.get("metric_name") or metric_id,
                    str(row.get("metric_kind") or current.get("metric_kind") or ""),
                ),
                "metric_kind": str(row.get("metric_kind") or current.get("metric_kind") or "").strip(),
                "formula": str(row.get("formula") or current.get("formula") or "").strip(),
                "value": str(row.get("value") or current.get("value") or "").strip(),
                "confidence": str(row.get("confidence") or current.get("confidence") or "").strip().lower(),
                "evidence_level": str(row.get("evidence_level") or current.get("evidence_level") or "").strip().upper(),
                "business_meaning": _chinese_metric_meaning(
                    metric_id,
                    row.get("business_meaning") or current.get("business_meaning"),
                    str(row.get("metric_kind") or current.get("metric_kind") or ""),
                ),
                "note": str(row.get("note") or current.get("note") or "").strip(),
                "source_columns": _normalize_metric_source_columns(row.get("source_columns")) or list(current.get("source_columns") or []),
                "source_records": list(current.get("source_records") or []),
            }
            candidate["source_records"].append(source_name)
            if prefer_existing and current:
                keep = dict(current)
                for key, value in candidate.items():
                    if key == "source_records":
                        keep[key] = list(dict.fromkeys([*list(current.get(key) or []), *list(value or [])]))
                    elif not keep.get(key) and value:
                        keep[key] = value
                merged_by_id[metric_id] = keep
            else:
                if current:
                    candidate["source_records"] = list(dict.fromkeys([*list(current.get("source_records") or []), *candidate["source_records"]]))
                merged_by_id[metric_id] = candidate

    _upsert(csv_rows, csv_source_name, prefer_existing=False)
    _upsert(json_rows, json_source_name, prefer_existing=True)
    return [merged_by_id[item] for item in order if item in merged_by_id]


