def _safe_preview_values(series: pd.Series, *, limit: int = 3) -> list[str]:
    previews: list[str] = []
    for value in series.dropna().astype(str):
        text = value.strip()
        if not text or text in previews:
            continue
        previews.append(text)
        if len(previews) >= limit:
            break
    return previews


def _numeric_compatibility(series: pd.Series) -> float:
    non_null = int(series.notna().sum())
    if non_null <= 0:
        return 0.0
    return float(pd.to_numeric(series, errors="coerce").notna().sum()) / float(non_null)


def _datetime_compatibility(series: pd.Series) -> float:
    non_null = int(series.notna().sum())
    if non_null <= 0:
        return 0.0
    return float(pd.to_datetime(series, errors="coerce").notna().sum()) / float(non_null)


def _binary_compatibility(series: pd.Series) -> float:
    non_null = int(series.notna().sum())
    if non_null <= 0:
        return 0.0
    numeric = pd.to_numeric(series, errors="coerce")
    if numeric.notna().any():
        unique_values = {float(value) for value in numeric.dropna().tolist()}
        if unique_values.issubset({0.0, 1.0}):
            return 1.0
    text = series.fillna("").astype(str).str.strip().str.lower()
    allowed = {"1", "0", "true", "false", "yes", "no", "y", "n", "late", "on_time"}
    hits = sum(1 for value in text if value in allowed)
    return float(hits) / float(non_null)


def _best_matching_column(
    columns: list[str],
    aliases: list[str],
    *,
    prefer_tokens: list[str] | None = None,
    disallow_tokens: list[str] | None = None,
) -> tuple[str, str, int]:
    compact_aliases = [_compact_column_name(alias) for alias in aliases if _compact_column_name(alias)]
    compact_prefer = [_compact_column_name(token) for token in list(prefer_tokens or []) if _compact_column_name(token)]
    compact_disallow = [_compact_column_name(token) for token in list(disallow_tokens or []) if _compact_column_name(token)]
    best_column = ""
    best_match_type = ""
    best_score = 0
    for column in columns:
        compact = _compact_column_name(column)
        if not compact:
            continue
        for alias in compact_aliases:
            score = 0
            match_type = ""
            if compact == alias:
                score = 400
                match_type = "exact"
            elif compact.startswith(alias) or compact.endswith(alias):
                score = 280
                match_type = "edge"
            elif alias in compact:
                score = 180
                match_type = "contains"
            if not score:
                continue
            score += sum(20 for token in compact_prefer if token and token in compact)
            score -= sum(160 for token in compact_disallow if token and token in compact)
            if score > best_score:
                best_column = column
                best_match_type = match_type
                best_score = score
    if best_score < 160:
        return "", "", 0
    return best_column, best_match_type, best_score


def _collect_ecommerce_role_candidates(frame: pd.DataFrame) -> tuple[list[dict[str, Any]], dict[str, str]]:
    role_candidates: list[dict[str, Any]] = []
    role_map: dict[str, str] = {}
    columns = [str(column) for column in frame.columns]
    for role_spec in _ECOMMERCE_DERIVED_ROLE_SPECS:
        column_name, match_type, score = _best_matching_column(
            columns,
            list(role_spec.get("aliases") or []),
            prefer_tokens=list(role_spec.get("prefer_tokens") or []),
            disallow_tokens=list(role_spec.get("disallow_tokens") or []),
        )
        if not column_name:
            continue
        series = frame[column_name]
        kind = str(role_spec.get("kind") or "").strip()
        compatibility = 1.0
        if kind == "numeric":
            compatibility = _numeric_compatibility(series)
        elif kind == "datetime":
            compatibility = _datetime_compatibility(series)
        elif kind == "binary":
            compatibility = _binary_compatibility(series)
        if compatibility <= 0:
            continue
        confidence = "high" if score >= 280 and compatibility >= 0.8 else "medium"
        role_candidates.append(
            {
                "role_id": str(role_spec.get("role_id") or ""),
                "column_name": column_name,
                "data_kind": kind,
                "confidence": confidence,
                "match_type": match_type,
                "compatibility_ratio": round(float(compatibility), 4),
                "sample_values": _safe_preview_values(series),
                "reason": f"{match_type} alias match with compatibility {compatibility:.2f}",
            }
        )
        role_map[str(role_spec.get("role_id") or "")] = column_name
    return role_candidates, role_map


def _read_json_value(path: Path) -> Any:
    if not path.is_file():
        return {}
    try:
        return json.loads(_read_text_artifact(path))
    except Exception:
        return {}


def _recommended_metric_target(
    *,
    target_metric_id: str,
    reader_title: str,
    formula_family: str,
    required_role_ids: list[str],
    recommended_spec: dict[str, Any] | None,
    role_map: dict[str, str],
    priority: str = "high",
    business_reason: str = "",
    proxy_only: bool = False,
) -> dict[str, Any]:
    available_role_ids = [role_id for role_id in required_role_ids if role_map.get(role_id)]
    missing_role_ids = [role_id for role_id in required_role_ids if role_id not in available_role_ids]
    payload: dict[str, Any] = {
        "target_metric_id": target_metric_id,
        "reader_title": reader_title,
        "formula_family": formula_family,
        "priority": priority,
        "required_role_ids": required_role_ids,
        "available_role_ids": available_role_ids,
        "missing_role_ids": missing_role_ids,
        "eligible": not missing_role_ids,
        "business_reason": business_reason,
        "proxy_only": proxy_only,
    }
    if recommended_spec:
        payload["recommended_spec"] = recommended_spec
    return payload


