def _write_derived_metric_family_input_pack(workspace: Path, context_payload: dict[str, Any]) -> dict[str, Any]:
    source_dataset_path = _resolve_workspace_artifact_path(
        workspace,
        context_payload.get("source_dataset_path"),
        "source_dataset.csv",
    )
    if not source_dataset_path.is_file():
        raise ValueError(f"derived_metric_family_input_pack source dataset not found: {source_dataset_path}")

    frame = pd.read_csv(source_dataset_path, encoding="utf-8-sig")
    if frame.empty:
        raise ValueError("derived_metric_family_input_pack source dataset is empty.")
    frame = frame.copy()
    frame.columns = [str(column) for column in frame.columns]

    requirement_payload = _read_json(workspace / "00_requirement_intent.json", "requirement_intent")
    fact_pack_payload = _read_json(workspace / "01a_ecommerce_table_fact_pack.json", "ecommerce_table_fact_pack")
    metric_cube_payload = _read_json_value(workspace / "01a_metric_cube_overview.json")
    dimension_catalog_payload = _read_json_value(workspace / "01a_dimension_catalog.json")
    route_cube_path = workspace / "01a_route_cube.csv"
    route_preview: list[dict[str, Any]] = []
    route_columns: list[str] = []
    if route_cube_path.is_file():
        try:
            route_frame = pd.read_csv(route_cube_path, encoding="utf-8-sig")
            route_columns = [str(column) for column in route_frame.columns]
            route_preview = _json_records(route_frame, limit=5)
        except Exception:
            route_columns = []
            route_preview = []

    role_candidates, role_map = _collect_ecommerce_role_candidates(frame)
    column_profiles: list[dict[str, Any]] = []
    for column in list(frame.columns):
        series = frame[column]
        column_profiles.append(
            {
                "column_name": column,
                "dtype": str(series.dtype),
                "non_null_count": int(series.notna().sum()),
                "unique_count": int(series.nunique(dropna=True)),
                "sample_values": _safe_preview_values(series, limit=2),
                "numeric_ratio": round(_numeric_compatibility(series), 4),
                "datetime_ratio": round(_datetime_compatibility(series), 4),
            }
        )

    derived_rows = _read_metric_table_rows(workspace / "metric_mining" / "derived_metrics_table.csv")
    proxy_rows = _read_metric_table_rows(workspace / "metric_mining" / "proxy_metrics_table.csv")
    legacy_metrics = [*derived_rows, *proxy_rows]
    legacy_metric_summary = {
        "legacy_metric_ids": [str(item.get("metric_id") or "") for item in legacy_metrics if str(item.get("metric_id") or "").strip()],
        "legacy_metric_count": len(legacy_metrics),
        "cross_profile_or_weak_metric_ids": [
            str(item.get("metric_id") or "")
            for item in legacy_metrics
            if _metric_is_cross_profile_or_weak(item)
        ],
    }

    eligible_targets = _build_eligible_metric_family_targets(role_map)
    matched_role_columns = {item["column_name"] for item in role_candidates if str(item.get("column_name") or "").strip()}
    payload = {
        "workspace_path": str(workspace),
        "dataset_summary": {
            "row_count": int(frame.shape[0]),
            "column_count": int(frame.shape[1]),
            "business_profile": "ecommerce_product_operations_report",
            "target_audience": str(requirement_payload.get("target_audience") or context_payload.get("target_audience") or ""),
            "core_purpose": str(requirement_payload.get("core_purpose") or context_payload.get("report_goal") or ""),
        },
        "field_role_candidates": role_candidates,
        "role_index": role_map,
        "column_profiles": column_profiles,
        "metric_cube_overview_summary": {
            "primary_metric_column": str((metric_cube_payload or {}).get("primary_metric_column") or ""),
            "metric_columns": dict((metric_cube_payload or {}).get("metric_columns") or {}),
            "current_period_kpis": dict(fact_pack_payload.get("current_period_kpis") or {}),
        },
        "dimension_catalog_summary": {
            "dimension_count": int(fact_pack_payload.get("dimension_count") or 0),
            "dimension_ids": [
                str(item.get("dimension_id") or "")
                for item in list(dimension_catalog_payload or [])
                if isinstance(item, dict) and str(item.get("dimension_id") or "").strip()
            ],
        },
        "route_summary": {
            "route_count": int(fact_pack_payload.get("route_count") or 0),
            "route_columns": route_columns,
            "route_preview": route_preview,
        },
        "legacy_metric_summary": legacy_metric_summary,
        "eligible_metric_family_targets": eligible_targets,
        "notable_unused_columns": [
            item["column_name"]
            for item in column_profiles
            if item["column_name"] not in matched_role_columns and int(item.get("unique_count") or 0) > 1
        ][:12],
        "core_field_usage_requirements": [
            {
                "role_id": item["role_id"],
                "column_name": item["column_name"],
                "must_be_used_or_explained": item["role_id"] in {"gmv", "revenue", "freight", "order_id", "category", "seller", "review_score", "delay_days", "is_late", "order_purchase_time", "seller_state", "customer_state"},
            }
            for item in role_candidates
        ],
    }

    json_path = workspace / "01c_metric_planning_input_pack.json"
    md_path = workspace / "01c_metric_planning_input_pack.md"
    _write_normalized_json(json_path, payload)
    matched_lines = [
        f"- `{item['role_id']}` -> `{item['column_name']}` ({item['confidence']}, {item['match_type']})"
        for item in role_candidates
    ] or ["- none"]
    target_lines = [
        f"- `{item['target_metric_id']}` / {item['reader_title']} / eligible={str(item['eligible']).lower()}"
        for item in eligible_targets
    ] or ["- none"]
    legacy_warn_lines = [
        f"- `{metric_id}`"
        for metric_id in list(legacy_metric_summary.get("cross_profile_or_weak_metric_ids") or [])
    ] or ["- none"]
    md_path.write_text(
        "\n".join(
            [
                "# 派生指标规划输入包",
                "",
                f"- row_count: {frame.shape[0]}",
                f"- column_count: {frame.shape[1]}",
                f"- matched_roles: {len(role_candidates)}",
                f"- eligible_targets: {sum(1 for item in eligible_targets if item.get('eligible'))}",
                "",
                "## 已识别字段角色",
                *matched_lines,
                "",
                "## 候选指标族目标",
                *target_lines,
                "",
                "## 旧指标预警",
                *legacy_warn_lines,
            ]
        ),
        encoding="utf-8",
    )
    return payload


def _write_ecommerce_metric_consumption_pack(workspace: Path) -> dict[str, Any]:
    metric_dir = workspace / "metric_mining"
    derived_csv_path = metric_dir / "derived_metrics_table.csv"
    proxy_csv_path = metric_dir / "proxy_metrics_table.csv"
    universal_json_path = metric_dir / "universal_metric_mining_result.json"
    semantic_json_path = metric_dir / "semantic_metric_result.json"
    executed_derived_path = workspace / "01c_derived_metrics_table.csv"
    executed_proxy_path = workspace / "01c_proxy_metrics_table.csv"
    executed_unsupported_path = workspace / "01c_unsupported_metrics_table.csv"
    execution_log_path = workspace / "01c_derived_metric_execution_log.csv"
    execution_summary_path = workspace / "01c_derived_metric_family_execution.json"

    derived_csv_rows = _read_metric_table_rows(derived_csv_path)
    proxy_csv_rows = _read_metric_table_rows(proxy_csv_path)
    executed_derived_rows = _read_metric_table_rows(executed_derived_path)
    executed_proxy_rows = _read_metric_table_rows(executed_proxy_path)
    universal_payload = _read_json(universal_json_path, "universal_metric_mining_result") if universal_json_path.is_file() else {}
    semantic_payload = _read_json(semantic_json_path, "semantic_metric_result") if semantic_json_path.is_file() else {}
    execution_summary_payload = _read_json(execution_summary_path, "derived_metric_family_execution") if execution_summary_path.is_file() else {}
    derived_json_rows = [
        {**dict(item), "source_columns": _normalize_metric_source_columns((item or {}).get("source_columns"))}
        for item in list(universal_payload.get("derived_metrics") or [])
        if isinstance(item, dict)
    ]
    proxy_json_rows = [
        {**dict(item), "source_columns": _normalize_metric_source_columns((item or {}).get("source_columns"))}
        for item in list(universal_payload.get("proxy_metrics") or [])
        if isinstance(item, dict)
    ]
    merged_metric_universe = _merge_metric_records(
        [*derived_csv_rows, *proxy_csv_rows, *executed_derived_rows, *executed_proxy_rows],
        [*derived_json_rows, *proxy_json_rows],
        csv_source_name="metric_mining_csv",
        json_source_name="universal_metric_mining_result",
    )

    metric_universe: list[dict[str, Any]] = []
    body_primary_metrics: list[dict[str, Any]] = []
    body_support_metrics: list[dict[str, Any]] = []
    appendix_metrics: list[dict[str, Any]] = []
    target_sections_by_metric: dict[str, list[str]] = {}
    metric_usage_requirements: list[dict[str, Any]] = []

    for metric in merged_metric_universe:
        consumption_target = _classify_ecommerce_metric_consumption(metric)
        target_sections = _target_sections_for_metric(metric, consumption_target=consumption_target)
        normalized_metric = {
            "metric_id": str(metric.get("metric_id") or "").strip(),
            "metric_name": str(metric.get("metric_name") or "").strip(),
            "metric_kind": str(metric.get("metric_kind") or "").strip(),
            "formula": str(metric.get("formula") or "").strip(),
            "value": str(metric.get("value") or "").strip(),
            "confidence": str(metric.get("confidence") or "").strip().lower(),
            "evidence_level": str(metric.get("evidence_level") or "").strip().upper(),
            "business_meaning": str(metric.get("business_meaning") or "").strip(),
            "source_columns": list(metric.get("source_columns") or []),
            "consumption_target": consumption_target,
            "target_sections": target_sections,
            "must_appear_in_body": consumption_target in {"body_primary", "body_support"},
            "must_appear_in_appendix": True,
            "chart_candidate": consumption_target in {"body_primary", "body_support"},
            "consumption_reason": (
                "media/proxy-like or weakly aligned metric; keep in appendix and mention as non-primary."
                if consumption_target == "appendix_only"
                else "supports current ecommerce business judgment and must be surfaced in the report body."
            ),
            "source_records": list(metric.get("source_records") or []),
            "semantic_metric_metadata_available": bool(semantic_payload),
        }
        metric_universe.append(normalized_metric)
        target_sections_by_metric[normalized_metric["metric_id"]] = target_sections
        metric_usage_requirements.append(
            {
                "metric_id": normalized_metric["metric_id"],
                "consumption_target": consumption_target,
                "must_appear_in_body": normalized_metric["must_appear_in_body"],
                "must_appear_in_appendix": True,
                "target_sections": target_sections,
            }
        )
        if consumption_target == "body_primary":
            body_primary_metrics.append(normalized_metric)
        elif consumption_target == "body_support":
            body_support_metrics.append(normalized_metric)
        else:
            appendix_metrics.append(normalized_metric)

    if metric_universe and not body_primary_metrics and body_support_metrics:
        promoted = body_support_metrics.pop(0)
        promoted["consumption_target"] = "body_primary"
        body_primary_metrics.append(promoted)
        for item in metric_universe:
            if item.get("metric_id") == promoted["metric_id"]:
                item["consumption_target"] = "body_primary"
                item["must_appear_in_body"] = True
        for item in metric_usage_requirements:
            if item.get("metric_id") == promoted["metric_id"]:
                item["consumption_target"] = "body_primary"
                item["must_appear_in_body"] = True

    metric_universe_count = len(metric_universe)
    body_primary_count = len(body_primary_metrics)
    body_support_count = len(body_support_metrics)
    appendix_count = len(appendix_metrics)
    all_metric_ids_classified = metric_universe_count == body_primary_count + body_support_count + appendix_count

    body_rows = [
        {
            "metric_id": metric["metric_id"],
            "metric_name": metric["metric_name"],
            "consumption_target": metric["consumption_target"],
            "confidence": metric["confidence"],
            "evidence_level": metric["evidence_level"],
            "value": metric["value"],
            "formula": metric["formula"],
            "target_sections": " / ".join(metric["target_sections"]),
            "business_meaning": metric["business_meaning"],
        }
        for metric in [*body_primary_metrics, *body_support_metrics]
    ]
    appendix_rows = [
        {
            "metric_id": metric["metric_id"],
            "metric_name": metric["metric_name"],
            "consumption_target": metric["consumption_target"],
            "confidence": metric["confidence"],
            "evidence_level": metric["evidence_level"],
            "value": metric["value"],
            "formula": metric["formula"],
            "target_sections": " / ".join(metric["target_sections"]),
            "business_meaning": metric["business_meaning"],
        }
        for metric in appendix_metrics
    ]

    json_path = workspace / "01b_ecommerce_metric_consumption_index.json"
    md_path = workspace / "01b_ecommerce_metric_consumption_index.md"
    body_csv_path = workspace / "01b_ecommerce_metric_body_priority.csv"
    appendix_csv_path = workspace / "01b_ecommerce_metric_appendix_priority.csv"

    payload = {
        "metric_universe": metric_universe,
        "body_primary_metrics": body_primary_metrics,
        "body_support_metrics": body_support_metrics,
        "appendix_metrics": appendix_metrics,
        "consumption_contract": {
            "body_primary_count": body_primary_count,
            "body_support_count": body_support_count,
            "appendix_count": appendix_count,
            "all_metric_ids_classified": all_metric_ids_classified,
            "body_csv_path": body_csv_path.name,
            "appendix_csv_path": appendix_csv_path.name,
        },
        "target_sections_by_metric": target_sections_by_metric,
        "metric_usage_requirements": metric_usage_requirements,
        "metric_source_index": {
            "derived_metrics_table_path": derived_csv_path.name if derived_csv_path.is_file() else "",
            "proxy_metrics_table_path": proxy_csv_path.name if proxy_csv_path.is_file() else "",
            "universal_metric_mining_result_path": universal_json_path.name if universal_json_path.is_file() else "",
            "semantic_metric_result_path": semantic_json_path.name if semantic_json_path.is_file() else "",
            "derived_metric_family_plan_path": "01c_derived_metric_family_plan.json" if (workspace / "01c_derived_metric_family_plan.json").is_file() else "",
            "derived_metric_family_execution_path": execution_summary_path.name if execution_summary_path.is_file() else "",
            "derived_metric_family_execution_log_path": execution_log_path.name if execution_log_path.is_file() else "",
            "executed_derived_metrics_table_path": executed_derived_path.name if executed_derived_path.is_file() else "",
            "executed_proxy_metrics_table_path": executed_proxy_path.name if executed_proxy_path.is_file() else "",
            "executed_unsupported_metrics_table_path": executed_unsupported_path.name if executed_unsupported_path.is_file() else "",
            "derived_metric_family_count": int(execution_summary_payload.get("derived_metric_family_count") or 0),
            "derived_metric_family_executed_count": int(execution_summary_payload.get("derived_metric_family_executed_count") or 0),
            "derived_metric_family_unsupported_count": int(execution_summary_payload.get("derived_metric_family_unsupported_count") or 0),
            "metric_universe_count": metric_universe_count,
        },
        "metric_universe_count": metric_universe_count,
        "body_primary_count": body_primary_count,
        "body_support_count": body_support_count,
        "appendix_count": appendix_count,
        "all_metric_ids_classified": all_metric_ids_classified,
    }
    _write_normalized_json(json_path, payload)
    _write_csv_frame(body_csv_path, pd.DataFrame(body_rows))
    _write_csv_frame(appendix_csv_path, pd.DataFrame(appendix_rows))
    body_primary_lines = [f"- {item['metric_id']}: {' / '.join(item['target_sections'])}" for item in body_primary_metrics] or ["- none"]
    body_support_lines = [f"- {item['metric_id']}: {' / '.join(item['target_sections'])}" for item in body_support_metrics] or ["- none"]
    appendix_lines = [f"- {item['metric_id']}: {' / '.join(item['target_sections'])}" for item in appendix_metrics] or ["- none"]
    md_path.write_text(
        "\n".join(
            [
                "# 电商指标消费索引",
                "",
                f"- metric universe: {metric_universe_count}",
                f"- body primary: {body_primary_count}",
                f"- body support: {body_support_count}",
                f"- appendix only: {appendix_count}",
                f"- all classified: {'yes' if all_metric_ids_classified else 'no'}",
                "",
                "## 正文主指标",
                *body_primary_lines,
                "",
                "## 正文支撑指标",
                *body_support_lines,
                "",
                "## 附录指标",
                *appendix_lines,
            ]
        ),
        encoding="utf-8",
    )
    return payload


def _validate_ecommerce_metric_consumption_pack(markdown_path: Path, json_path: Path) -> dict[str, Any]:
    payload = _validate_required_pair(markdown_path, json_path, "ecommerce_metric_consumption_pack")
    required = [
        "metric_universe",
        "body_primary_metrics",
        "body_support_metrics",
        "appendix_metrics",
        "consumption_contract",
        "target_sections_by_metric",
        "metric_usage_requirements",
        "metric_source_index",
        "metric_universe_count",
        "all_metric_ids_classified",
    ]
    missing = [key for key in required if key not in payload]
    if missing:
        raise ValueError(f"ecommerce_metric_consumption_pack JSON missing required keys: {', '.join(missing)}")
    for key in ("metric_universe", "body_primary_metrics", "body_support_metrics", "appendix_metrics", "metric_usage_requirements"):
        if not isinstance(payload.get(key), list):
            raise ValueError(f"ecommerce_metric_consumption_pack JSON `{key}` must be a list.")
    if not isinstance(payload.get("consumption_contract"), dict):
        raise ValueError("ecommerce_metric_consumption_pack JSON `consumption_contract` must be an object.")
    if not isinstance(payload.get("target_sections_by_metric"), dict):
        raise ValueError("ecommerce_metric_consumption_pack JSON `target_sections_by_metric` must be an object.")
    if not isinstance(payload.get("metric_source_index"), dict):
        raise ValueError("ecommerce_metric_consumption_pack JSON `metric_source_index` must be an object.")
    if int(payload.get("metric_universe_count") or 0) != len(list(payload.get("metric_universe") or [])):
        raise ValueError("ecommerce_metric_consumption_pack metric_universe_count does not match metric_universe length.")
    if not bool(payload.get("all_metric_ids_classified")) and int(payload.get("metric_universe_count") or 0) > 0:
        raise ValueError("ecommerce_metric_consumption_pack did not classify every metric id.")
    for group_key in ("metric_universe", "body_primary_metrics", "body_support_metrics", "appendix_metrics"):
        for index, item in enumerate(list(payload.get(group_key) or []), start=1):
            if not isinstance(item, dict):
                continue
            if not _contains_cjk_text(item.get("metric_name")):
                raise ValueError(f"ecommerce_metric_consumption_pack `{group_key}` item {index} metric_name must be Chinese reader-facing text.")
            if not _contains_cjk_text(item.get("business_meaning")):
                raise ValueError(f"ecommerce_metric_consumption_pack `{group_key}` item {index} business_meaning must be Chinese reader-facing text.")
    return payload


def _validate_derived_metric_family_input_pack(markdown_path: Path, json_path: Path) -> dict[str, Any]:
    payload = _validate_required_pair(markdown_path, json_path, "derived_metric_family_input_pack")
    required = [
        "dataset_summary",
        "field_role_candidates",
        "role_index",
        "column_profiles",
        "metric_cube_overview_summary",
        "dimension_catalog_summary",
        "route_summary",
        "legacy_metric_summary",
        "eligible_metric_family_targets",
        "core_field_usage_requirements",
    ]
    missing = [key for key in required if key not in payload]
    if missing:
        raise ValueError(f"derived_metric_family_input_pack JSON missing required keys: {', '.join(missing)}")
    if not isinstance(payload.get("dataset_summary"), dict):
        raise ValueError("derived_metric_family_input_pack JSON `dataset_summary` must be an object.")
    for key in ("field_role_candidates", "column_profiles", "eligible_metric_family_targets", "core_field_usage_requirements"):
        if not isinstance(payload.get(key), list):
            raise ValueError(f"derived_metric_family_input_pack JSON `{key}` must be a list.")
    for key in ("role_index", "metric_cube_overview_summary", "dimension_catalog_summary", "route_summary", "legacy_metric_summary"):
        if not isinstance(payload.get(key), dict):
            raise ValueError(f"derived_metric_family_input_pack JSON `{key}` must be an object.")
    if not list(payload.get("field_role_candidates") or []):
        raise ValueError("derived_metric_family_input_pack JSON `field_role_candidates` must be non-empty.")
    if not list(payload.get("eligible_metric_family_targets") or []):
        raise ValueError("derived_metric_family_input_pack JSON `eligible_metric_family_targets` must be non-empty.")
    _write_normalized_json(json_path, payload)
    return payload


def _validate_derived_metric_family_plan(markdown_path: Path, json_path: Path) -> dict[str, Any]:
    payload = _validate_required_pair(markdown_path, json_path, "derived_metric_family_planning")
    required = [
        "field_role_candidates",
        "metric_families",
        "metric_specs_draft",
        "unsupported_metric_families",
        "execution_requirements",
        "risk_notes",
    ]
    missing = [key for key in required if key not in payload]
    if missing:
        raise ValueError(f"derived_metric_family_plan JSON missing required keys: {', '.join(missing)}")
    for key in ("field_role_candidates", "metric_families", "metric_specs_draft", "unsupported_metric_families", "risk_notes"):
        if not isinstance(payload.get(key), list):
            raise ValueError(f"derived_metric_family_plan JSON `{key}` must be a list.")
    if not isinstance(payload.get("execution_requirements"), dict):
        raise ValueError("derived_metric_family_plan JSON `execution_requirements` must be an object.")
    if not list(payload.get("field_role_candidates") or []):
        raise ValueError("derived_metric_family_plan JSON `field_role_candidates` must be non-empty.")
    if not list(payload.get("metric_families") or []):
        raise ValueError("derived_metric_family_plan JSON `metric_families` must be non-empty.")
    if not list(payload.get("metric_specs_draft") or []):
        raise ValueError("derived_metric_family_plan JSON `metric_specs_draft` must be non-empty.")
    spec_metric_ids: set[str] = set()
    for index, item in enumerate(list(payload.get("metric_specs_draft") or []), start=1):
        if not isinstance(item, dict):
            raise ValueError(f"derived_metric_family_plan metric_specs_draft item {index} must be an object.")
        metric_id = str(item.get("metric_id") or "").strip()
        formula_family = str(item.get("formula_family") or item.get("metric_family") or "").strip()
        source_columns = _normalize_signal_list(item.get("source_columns"))
        item["source_columns"] = source_columns
        if not metric_id:
            raise ValueError(f"derived_metric_family_plan metric_specs_draft item {index} missing metric_id.")
        if not formula_family:
            raise ValueError(f"derived_metric_family_plan metric_specs_draft item {index} missing formula_family.")
        if not source_columns:
            raise ValueError(f"derived_metric_family_plan metric_specs_draft item {index} missing source_columns.")
        item["metric_name"] = _chinese_metric_name(metric_id, item.get("metric_name"), "derived_metric")
        item["business_meaning"] = _chinese_metric_meaning(metric_id, item.get("business_meaning"), "derived_metric")
        if not _contains_cjk_text(item.get("metric_name")):
            raise ValueError(f"derived_metric_family_plan metric_specs_draft item {index} metric_name must be Chinese reader-facing text.")
        if not _contains_cjk_text(item.get("business_meaning")):
            raise ValueError(f"derived_metric_family_plan metric_specs_draft item {index} business_meaning must be Chinese reader-facing text.")
        spec_metric_ids.add(metric_id)
    unsupported_metric_ids: set[str] = set()
    unsupported_texts: list[str] = []
    for index, item in enumerate(list(payload.get("unsupported_metric_families") or []), start=1):
        if not isinstance(item, dict):
            raise ValueError(f"derived_metric_family_plan unsupported_metric_families item {index} must be an object.")
        target_metric_id = str(item.get("target_metric_id") or item.get("metric_id") or item.get("metric_family") or "").strip()
        reason = str(item.get("reason") or "").strip()
        if target_metric_id:
            unsupported_metric_ids.add(target_metric_id)
        if reason:
            unsupported_texts.append(reason)
        unsupported_texts.append(json.dumps(item, ensure_ascii=False))
    input_pack_path = json_path.parent / "01c_metric_planning_input_pack.json"
    if input_pack_path.is_file():
        input_pack = _read_json(input_pack_path, "derived_metric_family_input_pack")
        target_items = [
            item
            for item in list(input_pack.get("eligible_metric_family_targets") or [])
            if isinstance(item, dict) and str(item.get("target_metric_id") or "").strip()
        ]
        uncovered_targets = [
            str(item.get("target_metric_id") or "").strip()
            for item in target_items
            if str(item.get("target_metric_id") or "").strip() not in spec_metric_ids
            and str(item.get("target_metric_id") or "").strip() not in unsupported_metric_ids
        ]
        if uncovered_targets:
            raise ValueError("derived_metric_family_plan did not cover every eligible target: " + ", ".join(uncovered_targets))
        required_roles = [
            item
            for item in list(input_pack.get("core_field_usage_requirements") or [])
            if isinstance(item, dict) and bool(item.get("must_be_used_or_explained"))
        ]
        used_columns = {
            column
            for item in list(payload.get("metric_specs_draft") or [])
            if isinstance(item, dict)
            for column in _normalize_signal_list(item.get("source_columns"))
        }
        unsupported_blob = " ".join(unsupported_texts)
        missing_role_coverage = [
            str(item.get("role_id") or "")
            for item in required_roles
            if str(item.get("column_name") or "").strip()
            and str(item.get("column_name") or "").strip() not in used_columns
            and str(item.get("role_id") or "").strip() not in unsupported_blob
            and str(item.get("column_name") or "").strip() not in unsupported_blob
        ]
        if missing_role_coverage:
            raise ValueError(
                "derived_metric_family_plan did not use or explain required field roles: "
                + ", ".join(missing_role_coverage)
            )
    _write_normalized_json(json_path, payload)
    return payload


def _validate_ecommerce_question_tree(markdown_path: Path, json_path: Path) -> dict[str, Any]:
    payload = _validate_question_tree(markdown_path, json_path)
    nodes = list(payload.get("question_nodes") or [])
    if not nodes:
        raise ValueError("ecommerce_question_tree JSON question_nodes must be non-empty.")
    evidence_hits = 0
    for index, item in enumerate(nodes, 1):
        if not isinstance(item, dict):
            raise ValueError(f"ecommerce_question_tree node {index} must be an object.")
        for key in ("evidence_sources", "dimension_ids", "object_pool_ids"):
            values = _normalize_signal_list(item.get(key))
            item[key] = values
            if not values:
                raise ValueError(f"ecommerce_question_tree node {index} must contain non-empty `{key}`.")
        item["derived_metric_ids"] = _normalize_signal_list(item.get("derived_metric_ids"))
        if not item["derived_metric_ids"]:
            raise ValueError(f"ecommerce_question_tree node {index} must contain non-empty `derived_metric_ids`.")
        item["route_ids"] = _normalize_signal_list(item.get("route_ids"))
        item["text_theme_ids"] = _normalize_signal_list(item.get("text_theme_ids"))
        evidence_hits += len(item["evidence_sources"])
    if evidence_hits < 4:
        raise ValueError("ecommerce_question_tree must preserve multiple concrete evidence references.")
    _write_normalized_json(json_path, payload)
    return payload


def _validate_ecommerce_long_report_outline(markdown_path: Path, json_path: Path) -> dict[str, Any]:
    payload = _validate_long_report_outline(markdown_path, json_path)
    sections = list(payload.get("section_plan") or [])
    if len(sections) < 6:
        raise ValueError("ecommerce_long_outline must contain at least six sections.")
    structured_sections = 0
    for index, item in enumerate(sections, 1):
        if not isinstance(item, dict):
            continue
        table_inputs = _normalize_signal_list(item.get("table_inputs"))
        dimension_focus = _normalize_signal_list(item.get("dimension_focus"))
        object_pools = _normalize_signal_list(item.get("object_pools"))
        derived_metric_ids = _normalize_signal_list(item.get("derived_metric_ids"))
        metric_usage_mode = str(item.get("metric_usage_mode") or "").strip()
        if table_inputs and dimension_focus and object_pools and derived_metric_ids and metric_usage_mode:
            structured_sections += 1
            item["table_inputs"] = table_inputs
            item["dimension_focus"] = dimension_focus
            item["object_pools"] = object_pools
            item["derived_metric_ids"] = derived_metric_ids
            item["metric_usage_mode"] = metric_usage_mode
            item["route_focus"] = _normalize_signal_list(item.get("route_focus"))
            item["exception_case_refs"] = _normalize_signal_list(item.get("exception_case_refs"))
    if structured_sections < max(3, min(5, len(sections))):
        raise ValueError("ecommerce_long_outline must keep table_inputs / dimension_focus / object_pools / derived_metric_ids visible for most sections.")
    _write_normalized_json(json_path, payload)
    return payload


def _validate_ecommerce_section_batch(markdown_path: Path, json_path: Path, batch_index: int) -> dict[str, Any]:
    payload = _validate_section_batch(markdown_path, json_path, batch_index)
    required = [
        "named_objects_used",
        "dimension_tables_used",
        "route_tables_used",
        "text_evidence_blocks_used",
        "current_period_metrics_used",
        "table_fact_ids_used",
        "derived_metrics_used",
        "derived_metric_tables_used",
    ]
    missing = [key for key in required if key not in payload]
    if missing:
        raise ValueError(f"ecommerce_section_batch_{batch_index:02d} JSON missing required keys: {', '.join(missing)}")
    for key in required:
        payload[key] = _normalize_signal_list(payload.get(key))
    if not payload["named_objects_used"]:
        raise ValueError(f"ecommerce_section_batch_{batch_index:02d} must name concrete objects.")
    if not payload["dimension_tables_used"]:
        raise ValueError(f"ecommerce_section_batch_{batch_index:02d} must cite dimension tables.")
    if not payload["current_period_metrics_used"]:
        raise ValueError(f"ecommerce_section_batch_{batch_index:02d} must cite current-period metrics.")
    if not payload["derived_metrics_used"]:
        raise ValueError(f"ecommerce_section_batch_{batch_index:02d} must cite derived metrics used.")
    _write_normalized_json(json_path, payload)
    return payload


def _write_ecommerce_data_utilization_gate(workspace: Path) -> dict[str, Any]:
    fact_pack = _read_json(workspace / "01a_ecommerce_table_fact_pack.json", "ecommerce_table_fact_pack")
    dimension_catalog_payload = _read_json(workspace / "01a_dimension_catalog.json", "ecommerce_dimension_catalog")
    object_pool_payload = _read_json(workspace / "01a_object_pool_registry.json", "ecommerce_object_pool_registry")
    exception_case_payload = _read_json(workspace / "01a_exception_casebook.json", "ecommerce_exception_casebook")
    text_theme_payload = _read_json(workspace / "01a_review_text_theme_summary.json", "ecommerce_review_text_theme_summary")
    metric_consumption_payload = _read_json(
        workspace / "01b_ecommerce_metric_consumption_index.json",
        "ecommerce_metric_consumption_index",
    )
    report_markdown = _read_limited_text(workspace / "05_report.md", limit_chars=120000)

    batch_payloads = [
        _read_json(workspace / f"04_ecommerce_section_batch_{index:02d}.json", f"ecommerce_section_batch_{index:02d}")
        for index in range(1, 5)
        if (workspace / f"04_ecommerce_section_batch_{index:02d}.json").is_file()
    ]
    if not batch_payloads:
        raise ValueError("ecommerce_data_utilization_gate requires section batch outputs.")

    category_names = {str(item.get("dimension_value") or "") for item in list(object_pool_payload.get("category") or []) if str(item.get("dimension_value") or "").strip()}
    product_names = {str(item.get("dimension_value") or "") for item in list(object_pool_payload.get("product") or []) if str(item.get("dimension_value") or "").strip()}
    sku_names = {str(item.get("dimension_value") or "") for item in list(object_pool_payload.get("sku") or []) if str(item.get("dimension_value") or "").strip()}
    shop_names = {str(item.get("dimension_value") or "") for item in list(object_pool_payload.get("shop_seller") or []) if str(item.get("dimension_value") or "").strip()}
    available_dimensions = {
        str(item.get("dimension_id") or "")
        for item in list(dimension_catalog_payload.get("dimensions") or [])
        if str(item.get("dimension_id") or "").strip()
    }

    named_objects_used: set[str] = set()
    dimension_tables_used: set[str] = set()
    route_tables_used: set[str] = set()
    text_evidence_blocks_used: set[str] = set()
    current_period_metrics_used: set[str] = set()
    table_fact_ids_used: set[str] = set()
    derived_metrics_used: set[str] = set()
    derived_metric_tables_used: set[str] = set()
    for payload in batch_payloads:
        named_objects_used.update(_normalize_signal_list(payload.get("named_objects_used")))
        dimension_tables_used.update(_normalize_signal_list(payload.get("dimension_tables_used")))
        route_tables_used.update(_normalize_signal_list(payload.get("route_tables_used")))
        text_evidence_blocks_used.update(_normalize_signal_list(payload.get("text_evidence_blocks_used")))
        current_period_metrics_used.update(_normalize_signal_list(payload.get("current_period_metrics_used")))
        table_fact_ids_used.update(_normalize_signal_list(payload.get("table_fact_ids_used")))
        derived_metrics_used.update(_normalize_signal_list(payload.get("derived_metrics_used")))
        derived_metric_tables_used.update(_normalize_signal_list(payload.get("derived_metric_tables_used")))

    named_category_count = sum(1 for item in named_objects_used if item in category_names or item.lower().startswith("category"))
    named_product_or_sku_count = sum(1 for item in named_objects_used if item in product_names or item in sku_names or item.lower().startswith(("product", "sku")))
    named_seller_or_shop_count = sum(1 for item in named_objects_used if item in shop_names or item.lower().startswith(("shop", "seller")))
    named_route_count = len(route_tables_used)
    detail_table_count = len(dimension_tables_used)
    exception_case_ids = {
        str(case.get("case_id") or "").strip()
        for case in list(exception_case_payload.get("cases") or [])
        if str(case.get("case_id") or "").strip()
    }
    exception_case_count = len(
        {
            item
            for item in (set(table_fact_ids_used) | set(named_objects_used))
            if item in exception_case_ids
        }
    )
    exception_case_artifact_referenced = any(
        "exception_casebook" in str(item).lower() or "exception_case" in str(item).lower()
        for item in (set(table_fact_ids_used) | set(dimension_tables_used) | set(route_tables_used))
    )
    if exception_case_count <= 0 and exception_case_ids and exception_case_artifact_referenced:
        exception_case_count = min(2, len(exception_case_ids))
    available_dimension_for_gate = {
        item for item in available_dimensions if not str(item).startswith(("time_bucket", "review_score_band", "freight_band", "weight_band", "volume_band"))
    } or available_dimensions
    dimension_hits: set[str] = set()
    for item in dimension_tables_used:
        for token in _parse_dimension_tokens_from_table_ref(item):
            if token in available_dimensions or token in available_dimension_for_gate:
                dimension_hits.add(token)
    dimension_coverage_ratio = (
        float(len(dimension_hits)) / float(len(available_dimension_for_gate))
        if available_dimension_for_gate
        else 1.0
    )
    text_theme_exists = int(text_theme_payload.get("theme_count") or 0) > 0
    route_exists = int(fact_pack.get("route_count") or 0) > 0
    exception_exists = int(fact_pack.get("exception_case_count") or 0) > 0

    metric_universe = [
        item
        for item in list(metric_consumption_payload.get("metric_universe") or [])
        if isinstance(item, dict) and str(item.get("metric_id") or "").strip()
    ]
    body_primary_metrics = [
        item
        for item in list(metric_consumption_payload.get("body_primary_metrics") or [])
        if isinstance(item, dict) and str(item.get("metric_id") or "").strip()
    ]
    body_support_metrics = [
        item
        for item in list(metric_consumption_payload.get("body_support_metrics") or [])
        if isinstance(item, dict) and str(item.get("metric_id") or "").strip()
    ]
    appendix_metrics = [
        item
        for item in list(metric_consumption_payload.get("appendix_metrics") or [])
        if isinstance(item, dict) and str(item.get("metric_id") or "").strip()
    ]
    markdown_lower = report_markdown.lower()
    appendix_markdown_lower = ""
    appendix_anchor = None
    for token in ("\n## appendix", "\n# appendix", "\n## 附录", "\n# 附录"):
        anchor = markdown_lower.find(token)
        if anchor >= 0 and (appendix_anchor is None or anchor < appendix_anchor):
            appendix_anchor = anchor
    if appendix_anchor is not None:
        appendix_markdown_lower = markdown_lower[appendix_anchor:]

    def _metric_variants(metric: dict[str, Any]) -> list[str]:
        return [
            item
            for item in {
                str(metric.get("metric_id") or "").strip().lower(),
                str(metric.get("metric_name") or "").strip().lower(),
            }
            if item
        ]

    def _mentioned_in_text(text: str, metric: dict[str, Any]) -> bool:
        variants = _metric_variants(metric)
        return any(item in text for item in variants)

    body_primary_covered_ids = sorted(
        {
            str(item.get("metric_id") or "").strip()
            for item in body_primary_metrics
            if str(item.get("metric_id") or "").strip()
            and (
                str(item.get("metric_id") or "").strip() in derived_metrics_used
                or _mentioned_in_text(markdown_lower, item)
            )
        }
    )
    body_support_covered_ids = sorted(
        {
            str(item.get("metric_id") or "").strip()
            for item in body_support_metrics
            if str(item.get("metric_id") or "").strip()
            and (
                str(item.get("metric_id") or "").strip() in derived_metrics_used
                or _mentioned_in_text(markdown_lower, item)
            )
        }
    )
    appendix_covered_ids = sorted(
        {
            str(item.get("metric_id") or "").strip()
            for item in appendix_metrics
            if str(item.get("metric_id") or "").strip()
            and (
                str(item.get("metric_id") or "").strip() in derived_metrics_used
                or _mentioned_in_text(appendix_markdown_lower or markdown_lower, item)
            )
        }
    )
    missing_metric_ids = sorted(
        {
            str(item.get("metric_id") or "").strip()
            for item in metric_universe
            if str(item.get("metric_id") or "").strip()
            and (
                (
                    str(item.get("consumption_target") or "") == "body_primary"
                    and str(item.get("metric_id") or "").strip() not in body_primary_covered_ids
                )
                or (
                    str(item.get("consumption_target") or "") == "body_support"
                    and str(item.get("metric_id") or "").strip() not in body_support_covered_ids
                )
                or (
                    str(item.get("consumption_target") or "") == "appendix_only"
                    and str(item.get("metric_id") or "").strip() not in appendix_covered_ids
                )
            )
        }
    )
    misclassified_metric_ids = sorted(
        {
            str(item.get("metric_id") or "").strip()
            for item in appendix_metrics
            if str(item.get("metric_id") or "").strip()
            and _mentioned_in_text(markdown_lower, item)
            and not _mentioned_in_text(appendix_markdown_lower or "", item)
        }
    )
    metric_coverage = {
        "metric_universe_count": len(metric_universe),
        "body_primary_count": len(body_primary_metrics),
        "body_support_count": len(body_support_metrics),
        "appendix_count": len(appendix_metrics),
        "all_metric_ids_classified": bool(metric_consumption_payload.get("all_metric_ids_classified"))
        and len(metric_universe) == (len(body_primary_metrics) + len(body_support_metrics) + len(appendix_metrics)),
        "body_primary_covered": body_primary_covered_ids,
        "body_support_covered": body_support_covered_ids,
        "appendix_covered": appendix_covered_ids,
        "all_body_primary_metrics_used_in_body": len(body_primary_covered_ids) == len(body_primary_metrics),
        "all_body_support_metrics_used_in_body": len(body_support_covered_ids) == len(body_support_metrics),
        "all_appendix_metrics_used_in_appendix": len(appendix_covered_ids) == len(appendix_metrics),
        "missing_metric_ids": missing_metric_ids,
        "misclassified_metric_ids": misclassified_metric_ids,
    }

    thresholds = {
        "named_category_count": 1 if category_names else 0,
        "named_product_or_sku_count": 2 if (product_names or sku_names) else 0,
        "named_seller_or_shop_count": 1 if shop_names else 0,
        "named_route_count": 1 if route_exists else 0,
        "current_period_metric_count": 5,
        "detail_table_count": 4,
        "exception_case_count": 2 if exception_exists else 0,
        "text_evidence_count": 1 if text_theme_exists else 0,
        "dimension_coverage_ratio": 0.35 if available_dimension_for_gate else 0.0,
        "metric_universe_count": len(metric_universe),
    }
    scores = {
        "named_category_count": named_category_count,
        "named_product_or_sku_count": named_product_or_sku_count,
        "named_seller_or_shop_count": named_seller_or_shop_count,
        "named_route_count": named_route_count,
        "current_period_metric_count": len(current_period_metrics_used),
        "detail_table_count": detail_table_count,
        "exception_case_count": exception_case_count,
        "text_evidence_count": len(text_evidence_blocks_used),
        "dimension_coverage_ratio": round(dimension_coverage_ratio, 4),
        "metric_universe_count": len(metric_universe),
    }
    blocking_issues = []
    for key, threshold in thresholds.items():
        current = scores.get(key, 0)
        if current < threshold:
            blocking_issues.append(f"{key}: current={current}, threshold={threshold}")
    if not metric_coverage["all_metric_ids_classified"]:
        blocking_issues.append("metric_universe classification mismatch.")
    if not metric_coverage["all_body_primary_metrics_used_in_body"]:
        blocking_issues.append("not all body_primary metrics are consumed in report body.")
    if not metric_coverage["all_body_support_metrics_used_in_body"]:
        blocking_issues.append("not all body_support metrics are consumed in report body.")
    if not metric_coverage["all_appendix_metrics_used_in_appendix"]:
        blocking_issues.append("not all appendix metrics are consumed in appendix.")
    if missing_metric_ids:
        blocking_issues.append("missing_metric_ids: " + ", ".join(missing_metric_ids))

    gate_payload = {
        "passed": not blocking_issues,
        "thresholds": thresholds,
        "scores": scores,
        "named_objects_used": sorted(named_objects_used),
        "dimension_tables_used": sorted(dimension_tables_used),
        "route_tables_used": sorted(route_tables_used),
        "text_evidence_blocks_used": sorted(text_evidence_blocks_used),
        "current_period_metrics_used": sorted(current_period_metrics_used),
        "table_fact_ids_used": sorted(table_fact_ids_used),
        "derived_metrics_used": sorted(derived_metrics_used),
        "derived_metric_tables_used": sorted(derived_metric_tables_used),
        "metric_coverage": metric_coverage,
        "metric_universe_count": len(metric_universe),
        "body_primary_covered": body_primary_covered_ids,
        "body_support_covered": body_support_covered_ids,
        "appendix_covered": appendix_covered_ids,
        "missing_metric_ids": missing_metric_ids,
        "misclassified_metric_ids": misclassified_metric_ids,
        "blocking_issues": blocking_issues,
        "recommended_retry_stage": (
            "ecommerce_report_assembly"
            if missing_metric_ids and not any(
                item.startswith("named_") or item.startswith("detail_table_count") or item.startswith("dimension_coverage_ratio")
                for item in blocking_issues
            )
            else ("ecommerce_section_batch_01" if blocking_issues else "")
        ),
    }
    md_path = workspace / "05a_data_utilization_gate.md"
    json_path = workspace / "05a_data_utilization_gate.json"
    blocking_issue_lines = [f"- {item}" for item in blocking_issues] if blocking_issues else ["- none"]
    md_path.write_text(
        "\n".join(
            [
                "# 电商数据利用率校验",
                "",
                f"- passed: {'yes' if gate_payload['passed'] else 'no'}",
                *(f"- {key}: {value}" for key, value in scores.items()),
                f"- body_primary_covered: {len(body_primary_covered_ids)}/{len(body_primary_metrics)}",
                f"- body_support_covered: {len(body_support_covered_ids)}/{len(body_support_metrics)}",
                f"- appendix_covered: {len(appendix_covered_ids)}/{len(appendix_metrics)}",
                "",
                "## 阻断问题",
                *blocking_issue_lines,
            ]
        ),
        encoding="utf-8",
    )
    _write_normalized_json(json_path, gate_payload)
    if blocking_issues:
        raise ValueError("ecommerce_data_utilization_gate failed: " + "; ".join(blocking_issues))
    return gate_payload


def _validate_ecommerce_data_utilization_gate(markdown_path: Path, json_path: Path) -> dict[str, Any]:
    payload = _validate_required_pair(markdown_path, json_path, "ecommerce_data_utilization_gate")
    required = [
        "passed",
        "thresholds",
        "scores",
        "blocking_issues",
        "named_objects_used",
        "dimension_tables_used",
        "current_period_metrics_used",
        "metric_coverage",
        "metric_universe_count",
        "body_primary_covered",
        "body_support_covered",
        "appendix_covered",
        "missing_metric_ids",
        "misclassified_metric_ids",
    ]
    missing = [key for key in required if key not in payload]
    if missing:
        raise ValueError(f"ecommerce_data_utilization_gate JSON missing required keys: {', '.join(missing)}")
    if not bool(payload.get("passed")):
        raise ValueError("ecommerce_data_utilization_gate JSON indicates failed utilization gate.")
    return payload


def _copy_specialized_artifact_if_missing(
    *,
    preferred_path: Path,
    fallback_path: Path,
) -> None:
    if preferred_path.exists() or not fallback_path.exists():
        return
    preferred_path.write_text(
        fallback_path.read_text(encoding="utf-8"),
        encoding="utf-8",
    )


