def _validate_metric_chart_plan(markdown_path: Path, json_path: Path) -> dict[str, Any]:
    payload = _validate_required_pair(markdown_path, json_path, "metric_chart_plan")
    required = [
        "main_report_figures",
        "support_figures",
        "appendix_figures",
        "render_specs",
        "reuse_existing_figures",
        "skipped_metrics",
        "appendix_overflow_figures",
    ]
    missing = [key for key in required if key not in payload]
    if missing:
        raise ValueError(f"metric_chart_plan JSON missing required keys: {', '.join(missing)}")
    for key in required:
        if not isinstance(payload.get(key), list):
            raise ValueError(f"metric_chart_plan JSON `{key}` must be a list.")
    normalized_specs: list[dict[str, Any]] = []
    for index, spec in enumerate(list(payload.get("render_specs") or []), 1):
        if not isinstance(spec, dict):
            raise ValueError(f"metric_chart_plan render_spec {index} must be an object.")
        for key in ("figure_id", "metric_source_kind", "metric_ids", "chart_family", "reader_tier", "object_scope", "title", "reason"):
            if key not in spec:
                raise ValueError(f"metric_chart_plan render_spec {index} missing `{key}`.")
        chart_family = str(spec.get("chart_family") or "").strip()
        metric_ids = _normalize_signal_list(spec.get("metric_ids"))
        aggregate_chart_families = {"direct_derived_proxy_split", "confidence_matrix", "semantic_coverage_map"}
        if not metric_ids and chart_family not in aggregate_chart_families:
            raise ValueError(f"metric_chart_plan render_spec {index} must contain metric_ids.")
        reader_tier = str(spec.get("reader_tier") or "").strip()
        if reader_tier not in {"main_report", "appendix"}:
            raise ValueError(f"metric_chart_plan render_spec {index} has invalid reader_tier: {reader_tier or 'unknown'}")
        metric_source_kind = str(spec.get("metric_source_kind") or "").strip()
        section_anchor = str(spec.get("section_anchor") or "").strip()
        business_reason = str(spec.get("business_reason") or spec.get("reason") or "").strip()
        evidence_reason = str(spec.get("evidence_reason") or business_reason or "").strip()
        figure_role = str(spec.get("figure_role") or ("hero" if reader_tier == "main_report" else "appendix")).strip()
        if figure_role not in {"hero", "support", "appendix", "extension"}:
            raise ValueError(f"metric_chart_plan render_spec {index} has invalid figure_role: {figure_role or 'unknown'}")
        try:
            page_priority = int(spec.get("page_priority") if spec.get("page_priority") is not None else int(spec.get("business_priority") or 999))
        except Exception:
            raise ValueError(f"metric_chart_plan render_spec {index} page_priority must be an integer.")
        proxy_disclaimer_required = bool(
            spec.get("proxy_disclaimer_required")
            if "proxy_disclaimer_required" in spec
            else metric_source_kind == "proxy_metric"
        )
        cannot_say = spec.get("cannot_say")
        if isinstance(cannot_say, str):
            cannot_say = [cannot_say.strip()] if cannot_say.strip() else []
        elif not isinstance(cannot_say, list):
            cannot_say = []
        semantic_status = str(spec.get("metric_semantic_status") or spec.get("formula_validity") or "unknown").strip() or "unknown"
        normalized_specs.append(
            {
                **spec,
                "figure_id": str(spec.get("figure_id") or "").strip(),
                "metric_source_kind": metric_source_kind,
                "metric_ids": metric_ids,
                "chart_family": chart_family,
                "reader_tier": reader_tier,
                "object_scope": str(spec.get("object_scope") or "").strip(),
                "title": str(spec.get("title") or "").strip(),
                "reason": str(spec.get("reason") or "").strip(),
                "section_anchor": section_anchor or f"auto::{reader_tier}",
                "business_reason": business_reason or "auto business reason unavailable",
                "evidence_reason": evidence_reason or "auto evidence reason unavailable",
                "proxy_disclaimer_required": proxy_disclaimer_required,
                "figure_role": figure_role,
                "page_priority": page_priority,
                "denominator_basis": str(spec.get("denominator_basis") or "unknown").strip() or "unknown",
                "unit_basis": str(spec.get("unit_basis") or "unknown").strip() or "unknown",
                "time_basis": str(spec.get("time_basis") or "none").strip() or "none",
                "metric_semantic_status": semantic_status,
                "proxy_direction": str(spec.get("proxy_direction") or ("proxy_direction_unspecified" if metric_source_kind == "proxy_metric" else "not_proxy")).strip(),
                "allowed_reader_claim": str(spec.get("allowed_reader_claim") or "").strip(),
                "cannot_say": [str(item).strip() for item in cannot_say if str(item).strip()][:8],
                "claim_strength": str(spec.get("claim_strength") or ("proxy" if metric_source_kind == "proxy_metric" else "metric_supported")).strip(),
            }
        )
    payload["render_specs"] = normalized_specs
    _write_normalized_json(json_path, payload)
    return payload


def _report_package_contract(pipeline_type: str) -> dict[str, str]:
    if pipeline_type == "multi_table_generic_long_cli_pipeline":
        return {
            "report_markdown": "08_report.md",
            "html": "09_report.html",
            "css": "09_report.css",
            "review_notes": "10_review_notes.md",
            "pdf": "11_report.pdf",
        }
    return {
        "report_markdown": "05_report.md",
        "html": "06_report.html",
        "css": "06_report.css",
        "review_notes": "08_review_notes.md",
        "pdf": "07_report.pdf",
    }


