def _validate_cross_table_question_tree(markdown_path: Path, json_path: Path) -> dict[str, Any]:
    payload = _validate_required_pair(markdown_path, json_path, "cross_table_question_tree")
    required = ["root_questions", "cross_table_questions", "evidence_paths", "action_zones"]
    missing = [key for key in required if key not in payload]
    if missing:
        raise ValueError(f"cross_table_question_tree JSON missing required keys: {', '.join(missing)}")
    normalized_evidence_paths = _normalize_cross_table_evidence_paths(payload.get("evidence_paths"))
    if normalized_evidence_paths != payload.get("evidence_paths"):
        payload["evidence_paths"] = normalized_evidence_paths
        _write_normalized_json(json_path, payload)
    for key in required:
        if not isinstance(payload.get(key), list):
            raise ValueError(f"cross_table_question_tree JSON `{key}` must be a list.")
    return payload


def _normalize_cross_table_evidence_paths(value: Any) -> list[Any]:
    """Coerce CLI evidence receipts into the list contract used downstream."""
    if isinstance(value, list):
        return value
    if value is None:
        return []
    if isinstance(value, str):
        stripped = value.strip()
        return [stripped] if stripped else []
    if isinstance(value, dict):
        rows: list[Any] = []
        for source_group, group_value in value.items():
            if isinstance(group_value, list):
                for item in group_value:
                    if isinstance(item, dict):
                        rows.append({"source_group": source_group, **item})
                    elif str(item).strip():
                        rows.append({"source_group": source_group, "path": str(item).strip()})
                continue
            if isinstance(group_value, dict):
                rows.append({"source_group": source_group, **group_value})
                continue
            if str(group_value).strip():
                rows.append({"source_group": source_group, "path": str(group_value).strip()})
        return rows
    return [str(value).strip()] if str(value).strip() else []


def _looks_like_placeholder_ascii(text: str) -> bool:
    """Detect Chinese-stage artifacts that degraded into placeholder ASCII or mojibake."""
    if not text:
        return True
    non_ascii = sum(1 for ch in text if ord(ch) > 127)
    if non_ascii == 0:
        return True
    # A high question-mark share usually means the writer fell back to a lossy code page.
    # Do not fail valid mixed artifacts that still contain real Chinese copied from
    # upstream contracts; fail only when question marks dominate the readable text.
    if text.count("?") > 100 and text.count("?") > non_ascii * 2:
        return True
    return False


def _validate_cross_table_outline(markdown_path: Path, json_path: Path) -> dict[str, Any]:
    payload = _validate_required_pair(markdown_path, json_path, "cross_table_outline")
    markdown_text = _read_text_artifact(markdown_path).strip()
    json_text = _read_text_artifact(json_path).strip()
    if _looks_like_placeholder_ascii(markdown_text) or _looks_like_placeholder_ascii(json_text):
        raise ValueError("cross_table_outline output appears to be placeholder text or mojibake; rewrite with UTF-8 Chinese text.")
    required = [
        "headline_thesis",
        "section_plan",
        "cross_table_evidence_plan",
        "management_recommendation_zones",
        "batch_plan",
    ]
    missing = [key for key in required if key not in payload]
    if missing:
        raise ValueError(f"cross_table_outline JSON missing required keys: {', '.join(missing)}")
    if not isinstance(payload.get("batch_plan"), list) or len(payload.get("batch_plan") or []) != 4:
        raise ValueError("cross_table_outline JSON batch_plan must contain exactly four batches.")
    return payload


def _validate_cross_table_section_batch(markdown_path: Path, json_path: Path, batch_index: int) -> dict[str, Any]:
    payload = _validate_required_pair(markdown_path, json_path, f"cross_table_section_batch_{batch_index:02d}")
    markdown_text = _read_text_artifact(markdown_path).strip()
    json_text = _read_text_artifact(json_path).strip()
    if _looks_like_placeholder_ascii(markdown_text) or _looks_like_placeholder_ascii(json_text):
        raise ValueError(f"cross_table_section_batch_{batch_index:02d} output appears to be placeholder text or mojibake; rewrite with UTF-8 Chinese text.")
    if len(markdown_text) < 1200:
        raise ValueError(f"cross_table_section_batch_{batch_index:02d} markdown is too short.")
    has_structured_detail = (
        "|" in markdown_text
        or "KPI" in markdown_text
        or "table" in markdown_text.lower()
        or "action" in markdown_text.lower()
    )
    if not has_structured_detail:
        raise ValueError(f"cross_table_section_batch_{batch_index:02d} lacks table/KPI/detail/action structure.")
    required = ["batch_index", "section_ids", "section_titles", "completion_status", "tables_used"]
    missing = [key for key in required if key not in payload]
    if missing:
        raise ValueError(f"cross_table_section_batch_{batch_index:02d} JSON missing required keys: {', '.join(missing)}")
    if int(payload.get("batch_index") or 0) != batch_index:
        raise ValueError(f"cross_table_section_batch_{batch_index:02d} JSON batch_index mismatch.")
    return payload


def _validate_question_tree(markdown_path: Path, json_path: Path) -> dict[str, Any]:
    payload = _validate_required_pair(markdown_path, json_path, "question_tree")
    required = ["root_question", "question_nodes", "analysis_paths", "decision_questions", "recommended_sections"]
    missing = [key for key in required if key not in payload]
    if missing:
        raise ValueError(f"question_tree JSON missing required keys: {', '.join(missing)}")
    for key in ("question_nodes", "analysis_paths", "decision_questions", "recommended_sections"):
        if not isinstance(payload.get(key), list):
            raise ValueError(f"question_tree JSON `{key}` must be a list.")
    return payload


def _validate_internet_ops_inventory(markdown_path: Path, json_path: Path) -> dict[str, Any]:
    payload = _validate_required_pair(markdown_path, json_path, "ops_inventory")
    required = [
        "dataset_summary",
        "metric_glossary_summary",
        "priority_object_pools",
        "cross_dimension_tables",
        "time_window_focus",
        "current_week_actions",
        "daily_action_summary",
        "owner_schedule_summary",
        "derived_metric_diagnosis_summary",
        "gap_analysis",
        "evidence_index",
    ]
    missing = [key for key in required if key not in payload]
    if missing:
        raise ValueError(f"ops_inventory JSON missing required keys: {', '.join(missing)}")
    if not isinstance(payload.get("metric_glossary_summary"), dict):
        raise ValueError("ops_inventory JSON metric_glossary_summary must be an object.")
    if not isinstance(payload.get("priority_object_pools"), dict):
        raise ValueError("ops_inventory JSON priority_object_pools must be an object.")
    if not isinstance(payload.get("cross_dimension_tables"), list) or len(payload.get("cross_dimension_tables") or []) < 4:
        raise ValueError("ops_inventory JSON must contain at least four cross_dimension_tables entries.")
    if not isinstance(payload.get("time_window_focus"), list) or not payload.get("time_window_focus"):
        raise ValueError("ops_inventory JSON time_window_focus must be a non-empty list.")
    if not isinstance(payload.get("current_week_actions"), list) or not payload.get("current_week_actions"):
        raise ValueError("ops_inventory JSON current_week_actions must be a non-empty list.")
    if not isinstance(payload.get("daily_action_summary"), list) or not payload.get("daily_action_summary"):
        raise ValueError("ops_inventory JSON daily_action_summary must be a non-empty list.")
    if not isinstance(payload.get("owner_schedule_summary"), list) or not payload.get("owner_schedule_summary"):
        raise ValueError("ops_inventory JSON owner_schedule_summary must be a non-empty list.")
    if not isinstance(payload.get("derived_metric_diagnosis_summary"), list) or not payload.get("derived_metric_diagnosis_summary"):
        raise ValueError("ops_inventory JSON derived_metric_diagnosis_summary must be a non-empty list.")
    if not isinstance(payload.get("gap_analysis"), list):
        raise ValueError("ops_inventory JSON gap_analysis must be a list.")
    if not isinstance(payload.get("evidence_index"), dict):
        raise ValueError("ops_inventory JSON evidence_index must be an object.")
    return payload


def _validate_internet_ops_question_tree(markdown_path: Path, json_path: Path) -> dict[str, Any]:
    payload = _validate_question_tree(markdown_path, json_path)
    if not isinstance(payload.get("action_focus_objects"), list) or not payload.get("action_focus_objects"):
        raise ValueError("ops_question_tree JSON action_focus_objects must be a non-empty list.")
    recommended_sections = " ".join(str(item) for item in list(payload.get("recommended_sections") or []))
    required_pairs = [
        "channel × traffic_source",
        "user_segment × city_tier",
        "content_category × campaign",
        "product_module × campaign",
    ]
    pair_hits = sum(1 for label in required_pairs if label in recommended_sections)
    if pair_hits < 3:
        raise ValueError("ops_question_tree JSON must preserve most required cross-dimension lenses.")
    return payload


def _validate_long_report_outline(markdown_path: Path, json_path: Path) -> dict[str, Any]:
    payload = _validate_required_pair(markdown_path, json_path, "long_report_outline")
