def _append_procurement_layout_guard_css(css_path: Path) -> None:
    css_text = _read_text_artifact(css_path) if css_path.exists() else ""
    marker = "procurement-layout-guard-v4"
    if marker in css_text:
        return
    next_text = (css_text.rstrip() + "\n\n" + _procurement_layout_guard_css() + "\n").lstrip()
    css_path.write_text(next_text, encoding="utf-8")


def _procurement_figure_title(asset: dict[str, Any], insight: dict[str, Any], markdown_text: str) -> str:
    explicit = str(asset.get("title") or insight.get("title") or "").strip()
    stem = Path(str(asset.get("relative_path") or insight.get("relative_path") or insight.get("figure_id") or "")).stem
    spend_ledger = "支出台账" in markdown_text or "采购卡" in markdown_text
    title_map = {
        "generic_category_metric_heatmap": "用途与商户指标热力图" if spend_ledger else "品类指标热力图",
        "generic_cumulative_contribution_curve": "头部商户累计贡献曲线" if spend_ledger else "头部对象累计贡献曲线",
        "generic_numeric_distribution_grid": "金额分布与异常读数网格" if spend_ledger else "数值指标分布网格",
        "generic_segment_bubble": "商户与用途治理气泡图" if spend_ledger else "经营对象气泡图",
        "generic_time_trend_grid": "入账日期支出趋势网格" if spend_ledger else "时间趋势网格",
        "generic_missingness_matrix": "字段可用性与补数矩阵",
    }
    if stem in title_map:
        return title_map[stem]
    if explicit and not any(token in explicit for token in ("metric_", "generic_", "proxy_metric", "custom_")):
        return explicit
    return stem.replace("_", " ").strip() or "经营图表"


def _ensure_procurement_html_visual_assets(
    *,
    html_path: Path,
    markdown_path: Path,
    visual_asset_index_path: Path,
    chart_insights_path: Path | None = None,
) -> None:
    if not html_path.exists() or not visual_asset_index_path.exists():
        return
    html_text = _read_text_artifact(html_path)
    visual_payload = _read_json(visual_asset_index_path, "source_visual_assets_index")
    image_assets = [asset for asset in list(visual_payload.get("image_assets") or []) if isinstance(asset, dict)]
    if not image_assets:
        return
    existing_sources = {
        str(match.group(1) or "").strip()
        for match in re.finditer(r'<img[^>]+src="([^"]+)"', html_text, flags=re.I)
    }
    existing_names = {Path(source).name for source in existing_sources if source}
    referenced = 0
    for asset in image_assets:
        metadata = _visual_asset_render_metadata(asset)
        name = str(metadata.get("name") or "")
        relative_path = str(metadata.get("relative_path") or "")
        if (name and name in existing_names) or (relative_path and relative_path in existing_sources):
            referenced += 1
    required = min(4, len(image_assets))
    validation_note = (
        "<p><strong>验证：</strong>验证：将图中对象与商户、用途、入账日期和金额明细逐项对照；"
        "边界：不把缺失的 SKU、履约、客户或 GMV 字段写成已观测结论；"
        "后续问题：复核授权链、预算归口和凭证附件是否一致。</p>"
    )

    def _ensure_validation_note(match: re.Match[str]) -> str:
        block = match.group(0)
        plain = re.sub(r"<[^>]+>", " ", block)
        if any(label in plain for label in ("验证：", "边界：", "后续问题：", "分析：")):
            return block
        return block.replace("</div>", validation_note + "</div>", 1)

    patched_html = re.sub(r'<div class="figure-notes">[\s\S]*?</div>', _ensure_validation_note, html_text, flags=re.I)
    if patched_html != html_text:
        html_text = patched_html
        html_path.write_text(html_text, encoding="utf-8")
    if referenced >= required:
        return

    chart_payload = (
        _read_json(chart_insights_path, "chart_insights")
        if chart_insights_path and chart_insights_path.exists()
        else _build_fallback_chart_insights_payload(visual_payload)
    )
    insight_by_ref: dict[str, dict[str, Any]] = {}
    for item in list(chart_payload.get("figures") or []):
        if not isinstance(item, dict):
            continue
        figure_id = str(item.get("figure_id") or "").strip()
        relative_path = str(item.get("relative_path") or "").strip()
        for key in {figure_id, relative_path, Path(relative_path).name if relative_path else ""}:
            if key:
                insight_by_ref[key] = item

    markdown_text = _read_text_artifact(markdown_path) if markdown_path.exists() else ""
    blocks: list[str] = []
    for asset in image_assets:
        metadata = _visual_asset_render_metadata(asset)
        relative_path = str(metadata.get("relative_path") or asset.get("relative_path") or "").strip()
        name = str(metadata.get("name") or Path(relative_path).name).strip()
        if not relative_path or name in existing_names or relative_path in existing_sources:
            continue
        insight = insight_by_ref.get(relative_path) or insight_by_ref.get(name) or insight_by_ref.get(str(asset.get("figure_id") or "")) or {}
        title = _procurement_figure_title(asset, insight, markdown_text)
        observation = str(insight.get("observation") or f"{title} 已作为本期经营判断的图表证据。").strip()
        implication = str(insight.get("implication") or "该图用于把支出结构、对象集中度或时间窗口转成可复核的管理动作。").strip()
        action = str(insight.get("action") or "本周按图中对象清单推进授权、归口、凭证和重复交易复核。").strip()
        validation = (
            "验证：将图中对象与商户、用途、入账日期和金额明细逐项对照；"
            "边界：不把缺失的 SKU、履约、客户或 GMV 字段写成已观测结论；"
            "后续问题：复核授权链、预算归口和凭证附件是否一致。"
        )
        evidence_numbers = [str(item).strip() for item in list(insight.get("evidence_numbers") or []) if str(item).strip()][:5]
        evidence_html = ""
        if evidence_numbers:
            evidence_html = "<p><strong>证据：</strong>" + "<br>".join(html.escape(item) for item in evidence_numbers) + "</p>"
        blocks.append(
            "\n".join(
                [
                    '<figure class="report-figure figure-block procurement-auto-figure">',
                    '  <div class="figure-media">',
                    f'    <img src="{html.escape(relative_path)}" alt="{html.escape(title)}">',
                    "  </div>",
                    f"  <figcaption>{html.escape(title)}</figcaption>",
                    '  <div class="figure-notes">',
                    f"    <p><strong>观察：</strong>{html.escape(observation)}</p>",
                    f"    <p><strong>含义：</strong>{html.escape(implication)}</p>",
                    f"    <p><strong>动作：</strong>{html.escape(action)}</p>",
                    f"    <p><strong>验证：</strong>{html.escape(validation)}</p>",
                    f"    {evidence_html}",
                    "  </div>",
                    "</figure>",
                ]
            )
        )
        existing_sources.add(relative_path)
        existing_names.add(name)
        referenced += 1
        if referenced >= required:
            break
    if not blocks:
        return
    section = (
        '<section class="page-block visual-evidence-section">\n'
        '  <div class="section-kicker">图表证据</div>\n'
        '  <h2>支出台账图表证据与动作挂点</h2>\n'
        '  <div class="figure-grid">\n'
        + "\n".join(blocks)
        + "\n  </div>\n</section>\n"
    )
    if "</body>" in html_text:
        html_text = html_text.replace("</body>", section + "</body>", 1)
    else:
        html_text = html_text.rstrip() + "\n" + section
    html_path.write_text(html_text, encoding="utf-8")


def _ensure_procurement_html_css_package(
    *,
    markdown_path: Path,
    html_path: Path,
    css_path: Path,
    visual_asset_index_path: Path,
    chart_insights_path: Path | None = None,
    workspace: Path | None = None,
) -> None:
    """Ensure procurement HTML/CSS artifacts are present before review/PDF stages."""
    def render_markdown_fallback() -> None:
        if html_path.name == "06_report.html":
            _render_procurement_markdown_html(markdown_path, html_path, css_name=css_path.name)
        else:
            _render_procurement_markdown_with_tables_html(markdown_path, html_path, css_name=css_path.name)

    css_text = ""
    if css_path.exists():
        css_text = _read_text_artifact(css_path)
    if len(css_text.strip()) < 200 or ("@page" not in css_text and "print" not in css_text.lower()):
        css_path.write_text(_default_procurement_report_css(), encoding="utf-8")
    _append_procurement_layout_guard_css(css_path)
    if workspace and html_path.exists():
        _sanitize_procurement_html_report(html_path, workspace)
    if html_path.exists() and _procurement_reader_text_has_mojibake(_read_text_artifact(html_path)):
        render_markdown_fallback()
        if workspace and html_path.exists():
            _sanitize_procurement_html_report(html_path, workspace)
    _ensure_procurement_html_visual_assets(
        html_path=html_path,
        markdown_path=markdown_path,
        visual_asset_index_path=visual_asset_index_path,
        chart_insights_path=chart_insights_path,
    )

    try:
        _validate_html_css(
            html_path,
            css_path,
            chart_insights_path=chart_insights_path if chart_insights_path and chart_insights_path.exists() else None,
            visual_asset_index_path=visual_asset_index_path if visual_asset_index_path.exists() else None,
        )
    except Exception:
        if not html_path.exists():
            render_markdown_fallback()
        else:
            _repair_procurement_html_package(
                markdown_path=markdown_path,
                html_path=html_path,
                visual_asset_index_path=visual_asset_index_path,
                chart_insights_path=chart_insights_path,
        )
        if workspace and html_path.exists():
            _sanitize_procurement_html_report(html_path, workspace)
        if html_path.exists() and _procurement_reader_text_has_mojibake(_read_text_artifact(html_path)):
            render_markdown_fallback()
            if workspace and html_path.exists():
                _sanitize_procurement_html_report(html_path, workspace)
        _ensure_procurement_html_visual_assets(
            html_path=html_path,
            markdown_path=markdown_path,
            visual_asset_index_path=visual_asset_index_path,
            chart_insights_path=chart_insights_path,
        )
        _validate_html_css(
            html_path,
            css_path,
            chart_insights_path=chart_insights_path if chart_insights_path and chart_insights_path.exists() else None,
            visual_asset_index_path=visual_asset_index_path if visual_asset_index_path.exists() else None,
        )


def _enforce_claim_audit_release_marker(notes_path: Path, claim_audit_path: Path) -> str:
    """Keep review release markers aligned with the claim-consistency audit soft gate."""
    if not claim_audit_path.exists() or not notes_path.exists():
        return _read_text_artifact(notes_path) if notes_path.exists() else ""
    audit_payload = _read_json(claim_audit_path, "claim_consistency_audit")
    audit_release_allowed = bool(audit_payload.get("release_allowed"))
    if audit_release_allowed:
        return _read_text_artifact(notes_path)

    notes_text = _read_text_artifact(notes_path)
    if "`release_allowed=true`" in notes_text:
        notes_text = notes_text.replace("`release_allowed=true`", "`release_allowed=false`", 1)
    elif "`release_allowed=false`" not in notes_text:
        notes_text = notes_text.replace(
            "\n\n",
            "\n\n- `release_allowed=false`\n",
            1,
        )
    marker = (
        "\n\n## Claim Consistency Soft Gate\n\n"
        "- `05c_claim_consistency_audit.json` reports `release_allowed=false`; "
        "the pipeline may still render PDF in v1 soft-gate mode, but the review record must not mark the source package as fully released.\n"
    )
    if "Claim Consistency Soft Gate" not in notes_text:
        notes_text = notes_text.rstrip() + marker
    notes_path.write_text(notes_text, encoding="utf-8")
    return notes_text

def _generic_band_rows_by_chart(payload: dict[str, Any]) -> dict[str, list[dict[str, Any]]]:
    grouped: dict[str, list[dict[str, Any]]] = {}
    for row in list(payload.get("rows") or []):
        if not isinstance(row, dict):
            continue
        chart_id = str(row.get("chart_id") or "").strip()
        if not chart_id:
            continue
        grouped.setdefault(chart_id, []).append(row)
    return grouped


def _validate_generic_visual_band_contracts(
    generic_visual_band_index_path: Path,
    generic_bubble_coverage_manifest_path: Path,
) -> tuple[dict[str, Any], dict[str, Any]]:
    _require_file(generic_visual_band_index_path, "generic_visual_band_index")
    _require_file(generic_bubble_coverage_manifest_path, "generic_bubble_coverage_manifest")
    band_payload = _read_json(generic_visual_band_index_path, "generic_visual_band_index")
    manifest_payload = _read_json(generic_bubble_coverage_manifest_path, "generic_bubble_coverage_manifest")
    if str(band_payload.get("version") or "") != "generic_visual_band_index_v1":
        raise ValueError("generic_visual_band_index.json must use v1 contract.")
    if str(manifest_payload.get("version") or "") != "generic_bubble_coverage_manifest_v1":
        raise ValueError("generic_bubble_coverage_manifest.json must use v1 contract.")
    rows = [item for item in list(band_payload.get("rows") or []) if isinstance(item, dict)]
    charts = [item for item in list(manifest_payload.get("charts") or []) if isinstance(item, dict)]
    if not charts:
        raise ValueError("generic_bubble_coverage_manifest.json must contain chart declarations.")
    if not rows:
        raise ValueError("generic_visual_band_index.json must contain object-band rows.")
    band_rows = _generic_band_rows_by_chart(band_payload)
    missing = [
        str(chart.get("chart_id") or "")
        for chart in charts
        if band_rows.get(str(chart.get("chart_id") or "")) in (None, [])
        and str(chart.get("chart_family") or "") not in {"heatmap", ""}
    ]
    if missing:
        raise ValueError("generic visual band index is missing chart rows: " + ", ".join(missing[:12]))
    fixed_label_blocklist = {"优先扩张", "提效优化", "低成本验证", "立即收缩"}
    fixed_band_rows = [
        str(row.get("band_name") or "")
        for row in rows
        if str(row.get("band_name") or "") in fixed_label_blocklist
    ]
    if fixed_band_rows:
        raise ValueError("generic_visual_band_index must use CLI-generated quadrant labels, not fixed quadrant labels.")
    workspace = generic_visual_band_index_path.parent
    object_universe_count = 0
    object_universe_path = workspace / "generic_object_universe.json"
    if object_universe_path.exists():
        try:
            object_universe_payload = _read_json(object_universe_path, "generic_object_universe")
            object_universe_count = int(float(object_universe_payload.get("object_count") or 0))
        except Exception:
            object_universe_count = 0
    object_level_scope_values = {
        "object",
        "object_level",
        "primary_object",
        "cross_table_object",
    }
    for chart in charts:
        if not bool(chart.get("required_bubble")):
            continue
        source_csv = str(chart.get("source_csv") or "").strip()
        if not source_csv:
            raise ValueError(f"required generic visual `{chart.get('chart_id')}` must declare source_csv.")
        csv_path = workspace / "source_visual_assets" / source_csv
        if not csv_path.exists():
            raise ValueError(f"required generic visual `{chart.get('chart_id')}` source CSV is missing: {source_csv}")
        try:
            frame = pd.read_csv(csv_path)
        except Exception as exc:
            raise ValueError(f"required generic visual `{chart.get('chart_id')}` source CSV is unreadable: {source_csv}") from exc
        if frame.empty:
            raise ValueError(f"required generic visual `{chart.get('chart_id')}` source CSV has no rows.")
        if not len(frame.columns) or str(frame.columns[0]) not in {"图中序号", "鍥句腑搴忓彿"}:
            raise ValueError(f"required generic visual `{chart.get('chart_id')}` source CSV first column must be `图中序号`.")
        point_id_column = str(frame.columns[0])
        point_ids = frame[point_id_column].astype(str).tolist()
        if not point_ids or any(not re.fullmatch(r"B\d{2,}", value.strip()) for value in point_ids):
            raise ValueError(f"required generic visual `{chart.get('chart_id')}` must use Bxx point ids.")
        if "象限" not in frame.columns and "璞￠檺" not in frame.columns:
            raise ValueError(f"required generic visual `{chart.get('chart_id')}` source CSV must include `象限`.")
        object_scope = str(chart.get("object_scope") or "").strip().lower()
        chart_title = str(chart.get("chart_title") or chart.get("title") or "").strip()
        object_level_chart = object_universe_count > 0 and (
            object_scope in object_level_scope_values
            or "对象" in chart_title
            or bool(chart.get("object_dimension"))
        )
        if object_level_chart and len(frame) < object_universe_count:
            explanation = str(
                chart.get("object_universe_coverage_explanation")
                or chart.get("coverage_explanation")
                or ""
            ).strip()
            if not explanation:
                raise ValueError(
                    f"required object-level generic visual `{chart.get('chart_id')}` covers {len(frame)} rows "
                    f"but object universe has {object_universe_count}; render all objects or declare an explicit coverage explanation."
                )
    return band_payload, manifest_payload


def _validate_chart_insights(
    chart_insights_path: Path,
    visual_asset_index_path: Path,
    *,
    ops_visual_explanation_manifest_path: Path | None = None,
    require_ops_visuals: bool = False,
    allow_empty_assets: bool = False,
    generic_visual_band_index_path: Path | None = None,
    generic_bubble_coverage_manifest_path: Path | None = None,
    generic_smart_lens_contract_path: Path | None = None,
    report_lens: str = "",
) -> dict[str, Any]:
    _require_file(chart_insights_path, "chart_insights")
    _require_file(visual_asset_index_path, "chart_insights")
    payload = _read_json(chart_insights_path, "chart_insights")
    visual_payload = _read_json(visual_asset_index_path, "source_visual_assets_index")
    figures = payload.get("figures")
    if not isinstance(figures, list):
        raise ValueError("chart_insights JSON must contain a `figures` list.")
    image_assets = list(visual_payload.get("image_assets") or [])
    if not image_assets:
        if require_ops_visuals or not allow_empty_assets:
            raise ValueError("chart_insights requires image_assets in source_visual_assets_index.json.")
        return payload
    ops_manifest: dict[str, Any] = {}
    ops_charts: list[dict[str, Any]] = []
    if ops_visual_explanation_manifest_path and ops_visual_explanation_manifest_path.exists():
        ops_manifest = _read_json(ops_visual_explanation_manifest_path, "ops_visual_explanation_manifest")
        ops_charts = [item for item in list(ops_manifest.get("charts") or []) if isinstance(item, dict)]

    figure_by_id: dict[str, dict[str, Any]] = {}
    figure_by_ref: dict[str, dict[str, Any]] = {}
    for item in figures:
        if not isinstance(item, dict):
            raise ValueError("chart_insights figures must be objects.")
        figure_id = str(item.get("figure_id") or "").strip()
        if not figure_id:
            raise ValueError("chart_insights figure is missing `figure_id`.")
        figure_by_id[figure_id] = item
        relative_path = str(item.get("relative_path") or "").strip()
        for key in {figure_id, relative_path, Path(figure_id).name, Path(relative_path).name}:
            if key:
                figure_by_ref[key] = item
        for key in ("observation", "implication", "action"):
            text = str(item.get(key) or "").strip()
            if not text:
                raise ValueError(f"chart_insights `{figure_id}` is missing `{key}`.")
            if len(text) < 20:
                raise ValueError(f"chart_insights `{figure_id}` `{key}` is too short.")
            if "????" in text or re.search(r"\?{4,}", text):
                raise ValueError(f"chart_insights `{figure_id}` `{key}` contains placeholder question marks or mojibake.")

    vague_terms = {
        "\u67d0\u4eba\u7fa4",
        "\u67d0\u4e9b\u6e20\u9053",
        "\u67d0\u7c7b\u5bf9\u8c61",
        "\u90e8\u5206\u7fa4\u4f53",
        "\u4e00\u4e9b\u7528\u6237",
        "\u67d0\u4e2a\u5bf9\u8c61",
        "\u67d0\u4e2a\u7ef4\u5ea6",
    }
    evidence_required_tokens = ("bubble", "scatter", "heatmap", "correlation", "segment")

    for asset in image_assets:
        render_metadata = _visual_asset_render_metadata(asset)
        figure_id = str(asset.get("figure_id") or render_metadata.get("name") or "").strip()
        if not figure_id:
            raise ValueError("source visual asset is missing figure id.")
        item = figure_by_id.get(figure_id)
        if item is None:
            raise ValueError(f"chart_insights missing figure entry for `{figure_id}`.")
        for key in ("observation", "implication", "action"):
            text = str(item.get(key) or "").strip()
            for token in vague_terms:
                if token in text:
                    raise ValueError(f"chart_insights `{figure_id}` `{key}` contains vague wording: {token}")
        evidence_numbers = item.get("evidence_numbers") or []
        if not isinstance(evidence_numbers, list):
            raise ValueError(f"chart_insights `{figure_id}` `evidence_numbers` must be a list when present.")
        chart_type = _visual_asset_chart_type(asset)
        if any(token in chart_type for token in evidence_required_tokens) and not evidence_numbers:
            raise ValueError(f"chart_insights `{figure_id}` requires non-empty evidence_numbers.")
        if evidence_numbers and not any(re.search(r"\d", str(value)) for value in evidence_numbers):
            raise ValueError(f"chart_insights `{figure_id}` evidence_numbers must contain concrete numeric evidence.")
    if require_ops_visuals:
        if not ops_charts:
            raise ValueError("chart_insights requires ops_visual_explanation_manifest charts for internet-operations chart interpretation.")
        for chart in ops_charts:
            chart_id = str(chart.get("chart_id") or "").strip()
            png_path = str(chart.get("png_path") or "").strip()
            png_name = Path(png_path).name if png_path else f"{chart_id}.png"
            item = figure_by_ref.get(png_path) or figure_by_ref.get(png_name) or figure_by_ref.get(chart_id) or figure_by_ref.get(f"{chart_id}.png")
            if item is None:
                raise ValueError(f"chart_insights missing CLI interpretation for internet-ops chart `{png_name or chart_id}`.")
            evidence_numbers = [str(value).strip() for value in list(item.get("evidence_numbers") or []) if str(value).strip()]
            if len(evidence_numbers) < 2 or not any(re.search(r"\d", value) for value in evidence_numbers):
                raise ValueError(f"chart_insights `{png_name or chart_id}` must copy at least two concrete numeric evidence values from ops_visual_explanation_manifest.")
            narrative_text = str(item.get("chart_narrative") or item.get("reader_narrative") or "").strip()
            reader_blocks = item.get("reader_blocks") or {}
            if not narrative_text and isinstance(reader_blocks, dict):
                narrative_text = " ".join(str(value or "") for value in reader_blocks.values())
            if not narrative_text:
                raise ValueError(f"chart_insights `{png_name or chart_id}` must contain continuous chart narrative.")
            if re.search(r"(\*\*)?(数值证据|经营判断|动作指向|配表关系)(\*\*)?\s*[：:]", narrative_text):
                raise ValueError(f"chart_insights `{png_name or chart_id}` must not expose scaffold chart labels.")
            if len(re.findall(r"(?<![A-Za-z])[-+]?\d+(?:,\d{3})*(?:\.\d+)?%?", narrative_text)) < 2:
                raise ValueError(f"chart_insights `{png_name or chart_id}` narrative must cite at least two concrete values.")
    if generic_visual_band_index_path and generic_bubble_coverage_manifest_path:
        band_payload, manifest_payload = _validate_generic_visual_band_contracts(
            generic_visual_band_index_path,
            generic_bubble_coverage_manifest_path,
        )
        band_rows = _generic_band_rows_by_chart(band_payload)
        for chart in [item for item in list(manifest_payload.get("charts") or []) if isinstance(item, dict)]:
            chart_id = str(chart.get("chart_id") or "").strip()
            if not chart_id:
                continue
            item = figure_by_ref.get(chart_id) or figure_by_ref.get(f"source_visual_assets/{chart_id}") or figure_by_id.get(chart_id)
            if item is None:
                raise ValueError(f"chart_insights missing generic visual interpretation for `{chart_id}`.")
            combined_text = " ".join(
                str(item.get(key) or "").strip()
                for key in ("observation", "implication", "action")
            )
            if not combined_text:
                raise ValueError(f"chart_insights `{chart_id}` has empty interpretation text.")
            related_rows = band_rows.get(chart_id) or []
            if not related_rows:
                continue
            band_names = [str(row.get("band_name") or "").strip() for row in related_rows if str(row.get("band_name") or "").strip()]
            representative_objects: list[str] = []
            for row in related_rows:
                representative_objects.extend(
                    [
                        part.strip()
                        for part in re.split(r"[；;]", str(row.get("representative_objects") or ""))
                        if part.strip()
                    ]
                )
            if band_names and not any(name in combined_text for name in band_names):
                raise ValueError(f"chart_insights `{chart_id}` must mention at least one band/object-pool name from generic_visual_band_index.")
            if representative_objects and not any(name in combined_text for name in representative_objects[:6]):
                raise ValueError(f"chart_insights `{chart_id}` must cite at least one representative object from generic_visual_band_index.")
            if bool(chart.get("required_bubble")) and "bubble" not in str(item.get("chart_type") or "").lower() and "scatter" not in str(item.get("chart_type") or "").lower() and "quadrant" not in str(item.get("chart_type") or "").lower():
                raise ValueError(f"chart_insights `{chart_id}` must preserve bubble/scatter/quadrant chart typing for reader-facing delivery.")
    if generic_smart_lens_contract_path and generic_smart_lens_contract_path.exists():
        lens_payload = _read_json(generic_smart_lens_contract_path, "generic_smart_lens_contract")
        lens_name = str(lens_payload.get("lens_name") or "").strip()
        if lens_name and report_lens != "business_management":
            combined_text = "\n".join(
                " ".join(str(item.get(key) or "").strip() for key in ("observation", "implication", "action"))
                for item in figures
                if isinstance(item, dict)
            )
            if lens_name not in combined_text and "镜头" not in combined_text:
                raise ValueError("chart_insights generic smart-lens output must stay aligned with the generated lens narrative.")
    return payload


def _validate_section_batch(markdown_path: Path, json_path: Path, batch_index: int) -> dict[str, Any]:
    payload = _validate_required_pair(markdown_path, json_path, f"section_batch_{batch_index:02d}")
    markdown_text = _read_text_artifact(markdown_path).strip()
    if len(markdown_text) < 2000:
        raise ValueError(f"section_batch_{batch_index:02d} markdown is too short for a long-report batch.")
    has_structured_detail = "|" in markdown_text or "KPI" in markdown_text or "明细" in markdown_text or "行动" in markdown_text
    if not has_structured_detail:
        raise ValueError(f"section_batch_{batch_index:02d} markdown lacks tables/KPI/detail/action structure.")
    required = ["batch_index", "section_ids", "section_titles", "completion_status", "tables_used"]
    missing = [key for key in required if key not in payload]
    if missing:
        raise ValueError(f"section_batch_{batch_index:02d} JSON missing required keys: {', '.join(missing)}")
    if int(payload.get("batch_index") or 0) != batch_index:
        raise ValueError(f"section_batch_{batch_index:02d} JSON batch_index mismatch.")
    visual_blocks_used = payload.get("visual_blocks_used")
    if visual_blocks_used is not None and not isinstance(visual_blocks_used, list):
        raise ValueError(f"section_batch_{batch_index:02d} JSON `visual_blocks_used` must be a list when present.")
    return payload


def _count_csv_rows(path: Path, *, max_rows: int = 200000) -> int | None:
    try:
        with path.open("r", encoding="utf-8-sig", newline="") as handle:
            reader = csv.reader(handle)
            next(reader, None)
            count = 0
            for count, _ in enumerate(reader, 1):
                if count >= max_rows:
                    return count
            return count
    except Exception:
        return None


def _csv_columns(path: Path, *, max_columns: int = 80) -> list[str]:
    try:
        with path.open("r", encoding="utf-8-sig", newline="") as handle:
            reader = csv.reader(handle)
            header = next(reader, [])
            return [str(column).strip() for column in header[:max_columns] if str(column).strip()]
    except Exception:
        return []


def _compact_column_name(value: str) -> str:
    return "".join(ch for ch in str(value or "").lower().strip() if ch.isalnum() or "\u4e00" <= ch <= "\u9fff")


def _find_column(columns: list[str], aliases: list[str]) -> str:
    compact_aliases = [_compact_column_name(alias) for alias in aliases]
    for column in columns:
        compact = _compact_column_name(column)
        if any(alias and (alias == compact or alias in compact) for alias in compact_aliases):
            return column
    return ""


def _format_detail_number(value: Any, *, percent: bool = False) -> str:
    try:
        numeric = float(value)
    except Exception:
        return ""
    if numeric != numeric:
        return ""
    if percent:
        return f"{numeric:.1%}"
    if abs(numeric) >= 10000:
        return f"{numeric:,.0f}"
    if abs(numeric) >= 100:
        return f"{numeric:,.1f}"
    return f"{numeric:.2f}"


def _dimension_action_signal(
    *,
    budget: float | None,
    conversions: float | None,
    ctr: float | None,
    cpa: float | None,
    budget_cutoff: float,
    cpa_cutoff: float | None,
    ctr_cutoff: float | None,
) -> tuple[str, str]:
    has_budget_pressure = budget is not None and budget >= budget_cutoff
    has_conversion = conversions is not None and conversions > 0
    high_cpa = cpa_cutoff is not None and cpa is not None and cpa >= cpa_cutoff
    low_ctr = ctr_cutoff is not None and ctr is not None and ctr <= ctr_cutoff
    if has_budget_pressure and high_cpa:
        return "priority_fix", "Keep the segment visible in this-cycle review; reduce waste, inspect creative/placement quality, and reallocate budget only after CPA improves."
    if has_budget_pressure and low_ctr:
        return "traffic_quality_watch", "Audit traffic quality and creative match this week; keep spend capped until click quality recovers."
    if has_conversion and cpa is not None and (cpa_cutoff is None or cpa < cpa_cutoff):
        return "scale_candidate", "Protect supply and test controlled budget expansion while watching CPA and conversion stability."
    if has_budget_pressure:
        return "budget_watch", "Review budget share versus output this week and assign an owner for segment-level operating follow-up."
    return "monitor", "Keep in the management watchlist and compare against top segments before changing budget."


def _build_dimension_detail_inputs(workspace: Path, context_payload: dict[str, Any]) -> dict[str, Any]:
    pd = _pd()
    source_candidates = [
        workspace / "cleaned_dataset.csv",
        workspace / "input-data.csv",
    ]
    source_path = next((path for path in source_candidates if path.exists()), None)
    if source_path is None:
        return {"created": False, "reason": "no input-data.csv or cleaned_dataset.csv found"}

    try:
        frame = pd.read_csv(source_path, encoding="utf-8-sig")
    except Exception as exc:
        return {"created": False, "reason": f"failed to read source csv: {exc}"}
    if frame.empty:
        return {"created": False, "reason": "source csv is empty"}

    columns = [str(column) for column in frame.columns]
    numeric_columns = [
        column
        for column in columns
        if pd.to_numeric(frame[column], errors="coerce").notna().mean() >= 0.65
    ]
    categorical_columns = [
        column
        for column in columns
        if column not in numeric_columns and 1 < int(frame[column].nunique(dropna=True)) <= 80
    ]
    required_dimensions = [str(item).strip() for item in context_payload.get("required_detail_dimensions") or [] if str(item).strip()]
    selected_dimensions: list[str] = []
    for requested in required_dimensions:
        matched = _find_column(categorical_columns, [requested])
        if matched and matched not in selected_dimensions:
            selected_dimensions.append(matched)
    for column in categorical_columns:
        compact = _compact_column_name(column)
        if any(token in compact for token in ("media", "channel", "source", "terminal", "brand", "province", "placement", "campaign", "category", "sku", "product", "region")):
            if column not in selected_dimensions:
                selected_dimensions.append(column)
    for column in categorical_columns:
        if len(selected_dimensions) >= 8:
            break
        if column not in selected_dimensions:
            selected_dimensions.append(column)

    budget_col = _find_column(columns, ["budget", "spend", "cost", "预算", "消耗", "花费"])
    impression_col = _find_column(columns, ["monitor impression", "measured impression", "impression", "曝光", "监测曝光"])
    click_col = _find_column(columns, ["monitor click", "measured click", "click", "点击", "监测点击"])
    conversion_col = _find_column(columns, ["conversion", "conversions", "转化", "转化数"])
    ctr_col = _find_column(columns, ["ctr", "click rate", "点击率"])
    cpa_col = _find_column(columns, ["cpa", "cost per action"])
    exposure_completion_col = _find_column(columns, ["exposure completion", "曝光完成率"])
    click_completion_col = _find_column(columns, ["click completion", "点击完成率"])

    numeric_lookup: dict[str, Any] = {}
    for column in [budget_col, impression_col, click_col, conversion_col, ctr_col, cpa_col, exposure_completion_col, click_completion_col]:
        if column and column in frame.columns:
            numeric_lookup[column] = pd.to_numeric(frame[column], errors="coerce")

    budget_series = numeric_lookup.get(budget_col)
    cpa_series = numeric_lookup.get(cpa_col)
    ctr_series = numeric_lookup.get(ctr_col)
    budget_cutoff = float(budget_series.quantile(0.70)) if budget_series is not None and budget_series.notna().any() else 0.0
    cpa_cutoff = float(cpa_series.quantile(0.70)) if cpa_series is not None and cpa_series.notna().any() else None
    ctr_cutoff = float(ctr_series.quantile(0.30)) if ctr_series is not None and ctr_series.notna().any() else None

    rows: list[dict[str, Any]] = []
    for dimension in selected_dimensions[:8]:
        if dimension not in frame.columns:
            continue
        grouped = frame.copy()
        grouped[dimension] = grouped[dimension].fillna("Missing").astype(str)
        for column, series in numeric_lookup.items():
            grouped[column] = series
        aggregations: dict[str, tuple[str, str]] = {"record_count": (dimension, "size")}
        if budget_col:
            aggregations["budget_sum"] = (budget_col, "sum")
        if impression_col:
            aggregations["impressions_sum"] = (impression_col, "sum")
        if click_col:
            aggregations["clicks_sum"] = (click_col, "sum")
        if conversion_col:
            aggregations["conversions_sum"] = (conversion_col, "sum")
        if ctr_col:
            aggregations["ctr_avg"] = (ctr_col, "mean")
        if cpa_col:
            aggregations["cpa_avg"] = (cpa_col, "mean")
        if exposure_completion_col:
            aggregations["exposure_completion_avg"] = (exposure_completion_col, "mean")
        if click_completion_col:
            aggregations["click_completion_avg"] = (click_completion_col, "mean")

        summary = grouped.groupby(dimension, dropna=False).agg(**aggregations).reset_index()
        if "ctr_avg" not in summary.columns and {"clicks_sum", "impressions_sum"}.issubset(summary.columns):
            summary["ctr_avg"] = summary.apply(
                lambda row: float(row["clicks_sum"]) / float(row["impressions_sum"]) if float(row["impressions_sum"] or 0) else pd.NA,
                axis=1,
            )
        if "cpa_avg" not in summary.columns and {"budget_sum", "conversions_sum"}.issubset(summary.columns):
            summary["cpa_avg"] = summary.apply(
                lambda row: float(row["budget_sum"]) / float(row["conversions_sum"]) if float(row["conversions_sum"] or 0) else pd.NA,
                axis=1,
            )

        rank_col = "budget_sum" if "budget_sum" in summary.columns else "record_count"
        summary = summary.sort_values([rank_col, "record_count"], ascending=[False, False]).head(10)
        for _, row in summary.iterrows():
            budget = float(row["budget_sum"]) if "budget_sum" in row and pd.notna(row["budget_sum"]) else None
            conversions = float(row["conversions_sum"]) if "conversions_sum" in row and pd.notna(row["conversions_sum"]) else None
            ctr = float(row["ctr_avg"]) if "ctr_avg" in row and pd.notna(row["ctr_avg"]) else None
            cpa = float(row["cpa_avg"]) if "cpa_avg" in row and pd.notna(row["cpa_avg"]) else None
            signal, action = _dimension_action_signal(
                budget=budget,
                conversions=conversions,
                ctr=ctr,
                cpa=cpa,
                budget_cutoff=budget_cutoff,
                cpa_cutoff=cpa_cutoff,
                ctr_cutoff=ctr_cutoff,
            )
            rows.append(
                {
                    "dimension": dimension,
                    "segment": str(row[dimension]),
                    "record_count": int(row["record_count"]),
                    "budget_sum": _format_detail_number(budget),
                    "impressions_sum": _format_detail_number(row.get("impressions_sum")),
                    "clicks_sum": _format_detail_number(row.get("clicks_sum")),
                    "conversions_sum": _format_detail_number(row.get("conversions_sum")),
                    "ctr": _format_detail_number(ctr, percent=True),
                    "cpa": _format_detail_number(cpa),
                    "exposure_completion": _format_detail_number(row.get("exposure_completion_avg"), percent=True),
                    "click_completion": _format_detail_number(row.get("click_completion_avg"), percent=True),
                    "priority_signal": signal,
                    "suggested_current_action": action,
                    "owner_role": "Growth/Marketing Ops owner",
                }
            )

    if not rows:
        return {"created": False, "reason": "no categorical detail rows generated"}

    csv_path = workspace / "00_dimension_detail_summary.csv"
    json_path = workspace / "00_dimension_detail_summary.json"
    md_path = workspace / "00_dimension_detail_summary.md"
    pd.DataFrame(rows).to_csv(csv_path, index=False, encoding="utf-8-sig")
    payload = {
        "source_file": source_path.name,
        "generated_at": _now_iso(),
        "selected_dimensions": selected_dimensions[:8],
        "metric_columns": {
            "budget": budget_col,
            "impressions": impression_col,
            "clicks": click_col,
            "conversions": conversion_col,
            "ctr": ctr_col,
            "cpa": cpa_col,
            "exposure_completion": exposure_completion_col,
            "click_completion": click_completion_col,
        },
        "row_count": len(rows),
        "rows": rows,
    }
    json_path.write_text(json.dumps(payload, ensure_ascii=False, indent=2), encoding="utf-8")
    preview_lines = "\n".join(
        f"| {item['dimension']} | {item['segment']} | {item['budget_sum']} | {item['conversions_sum']} | {item['ctr']} | {item['cpa']} | {item['priority_signal']} | {item['suggested_current_action']} |"
        for item in rows[:30]
    )
    md_path.write_text(
        "\n".join(
            [
                "# Dimension Detail Summary",
                "",
                "This deterministic backend artifact turns categorical dimensions into current-period management inputs before Codex writes the report.",
                "",
                "| dimension | segment | budget_sum | conversions_sum | ctr | cpa | priority_signal | suggested_current_action |",
                "|---|---:|---:|---:|---:|---:|---|---|",
                preview_lines,
                "",
                "Use this as a required detail-table input for the reader-facing business report.",
            ]
        ),
        encoding="utf-8",
    )
    return {
        "created": True,
        "csv": str(csv_path.resolve()),
        "json": str(json_path.resolve()),
        "markdown": str(md_path.resolve()),
        "selected_dimensions": selected_dimensions[:8],
        "row_count": len(rows),
    }


def _artifact_role(path: Path) -> str:
    name = path.name.lower()
    suffix = path.suffix.lower()
    if name in {"input-data.csv", "cleaned_dataset.csv", "summary_stats.csv", "method_log.csv", "00_dimension_detail_summary.csv"}:
        return "primary"
    if suffix in {".csv", ".xlsx"} and any(
        token in name
        for token in (
            "category",
            "dimension",
            "detail",
            "temporal",
            "top",
            "summary",
            "outlier",
            "correlation",
            "cluster",
            "pca",
            "metric",
            "profile",
            "member",
        )
    ):
        return "primary"
    if suffix in {".md", ".html", ".pdf"} and any(token in name for token in ("interpretation", "report", "deep")):
        return "secondary"
    if suffix in {".png", ".jpg", ".jpeg", ".svg"}:
        return "secondary"
    if suffix in {".r", ".log", ".txt"}:
        return "support"
    return "weak"


def _relative_artifact(path: Path, workspace: Path) -> str:
    try:
        return path.resolve().relative_to(workspace.resolve()).as_posix()
    except Exception:
        return path.name


def _build_business_asset_scan_artifacts(workspace: Path, context_payload: dict[str, Any]) -> dict[str, Path]:
    dimension_detail_summary = _build_dimension_detail_inputs(workspace, context_payload)
    files = [path for path in workspace.rglob("*") if path.is_file()]
    files.sort(key=lambda item: (item.parent.as_posix(), item.name.lower()))

    role_buckets: dict[str, list[Path]] = {"primary": [], "secondary": [], "support": [], "weak": []}
    for path in files:
        role_buckets.setdefault(_artifact_role(path), []).append(path)

    primary = role_buckets["primary"][:80]
    secondary = role_buckets["secondary"][:80]
    weak = role_buckets["weak"][:80]
    support = role_buckets["support"][:60]

    csv_profiles: list[dict[str, Any]] = []
    for path in [*primary, *support]:
        if path.suffix.lower() != ".csv":
            continue
        columns = _csv_columns(path)
        if not columns:
            continue
        csv_profiles.append(
            {
                "file": _relative_artifact(path, workspace),
                "columns": columns,
                "row_count_sampled": _count_csv_rows(path),
                "bytes": path.stat().st_size,
            }
        )
        if len(csv_profiles) >= 24:
            break

    suffix_counts: dict[str, int] = {}
    for path in files:
        suffix = path.suffix.lower() or "[no_ext]"
        suffix_counts[suffix] = suffix_counts.get(suffix, 0) + 1

    dataset_scope = {
        "workspace": str(workspace),
        "file_count": len(files),
        "total_bytes": sum(path.stat().st_size for path in files),
        "suffix_counts": dict(sorted(suffix_counts.items())),
        "source": "backend_deterministic_asset_scan",
    }
    business_questions = [
        "Which revenue, cost, fulfillment, category, customer, region, or item groups deserve management attention?",
        "Which named dimensions and segments deserve current-period management action rather than next-period tracking?",
        "Which operating levers should be prioritized in the next 30/60/90 days?",
        "Which R-generated tables and charts can be converted into executive decisions?",
    ]
    operating_themes = [
        "Scale and mix structure",
        "Revenue quality and concentration",
        "Cost or freight pressure",
        "Fulfillment and operational efficiency",
        "Category, item, customer, and region priorities",
        "Named dimension detail tables and current-period segment actions",
        "Management action sequencing",
    ]

    md_path = workspace / "01_evidence_audit.md"
    json_path = workspace / "01_evidence_audit.json"
    primary_lines = "\n".join(f"- `{_relative_artifact(path, workspace)}`" for path in primary[:40]) or "- none"
    secondary_lines = "\n".join(f"- `{_relative_artifact(path, workspace)}`" for path in secondary[:40]) or "- none"
    csv_lines = "\n".join(
        f"- `{profile['file']}`: {profile.get('row_count_sampled') or 'unknown'} rows sampled, columns: "
        + ", ".join(profile.get("columns", [])[:12])
        for profile in csv_profiles[:16]
    ) or "- none"
    md_text = (
        "# 业务资产扫描\n\n"
        "本阶段由后端确定性扫描生成，目的是把大型 R 工作流工作区压缩成后续 Codex CLI 可消费的经营分析输入，避免在大目录中长时间盲扫。\n\n"
        "## 工作区概况\n\n"
        f"- 文件数量：{len(files)}\n"
        f"- 文件体量：{round(dataset_scope['total_bytes'] / 1024 / 1024, 2)} MB\n"
        f"- 目标读者：{context_payload.get('target_audience') or 'management'}\n"
        f"- 业务焦点：{context_payload.get('business_focus') or '经营诊断、管理建议与行动优先级'}\n\n"
        "## 主要经营分析输入\n\n"
        f"{primary_lines}\n\n"
        "## 次级支持材料\n\n"
        f"{secondary_lines}\n\n"
        "## 关键表格轮廓\n\n"
        f"{csv_lines}\n\n"
        "## 最适合回答的管理问题\n\n"
        "- 当前业务结构、收入质量、成本压力、履约效率和品类/区域/客户/商品优先级。\n"
        "- 管理层下一步应把资源投向哪些对象、动作和监控指标。\n"
        "- 哪些 R 结果应进入正式报告正文，哪些只适合作为内部校验。\n\n"
        "## 后续写作口径\n\n"
        "后续正式报告应面向 CEO/COO/经营管理层，读者看到的主线应是经营判断、管理建议和行动优先级；"
        "证据盘点只作为内部护栏，不应成为正式报告的主体结构。\n"
    )
    payload = {
        "primary_evidence_files": [_relative_artifact(path, workspace) for path in primary],
        "secondary_evidence_files": [_relative_artifact(path, workspace) for path in secondary],
        "weak_evidence_files": [_relative_artifact(path, workspace) for path in weak],
        "support_files": [_relative_artifact(path, workspace) for path in support],
        "missing_or_blocked_capabilities": [
            "Backend scan does not infer long-term causality.",
            "Backend scan does not read every row of very large files.",
            "Codex stages should use this scan as input and inspect selected artifacts only.",
        ],
        "dataset_scope_summary": dataset_scope,
        "csv_profiles": csv_profiles,
        "dimension_detail_summary": dimension_detail_summary,
        "business_questions": business_questions,
        "operating_themes": operating_themes,
        "main_risks": [
            "Large workspaces can cause slow CLI exploration if no deterministic index is provided.",
            "Reader-facing report should not expose internal evidence-boundary structure.",
        ],
        "reader_facing_mode": "business_report",
        "internal_grounding_mode": "guardrail_only",
    }
    md_path.write_text(md_text, encoding="utf-8")
    json_path.write_text(json.dumps(payload, ensure_ascii=False, indent=2), encoding="utf-8")
    return {"markdown": md_path, "json": json_path}


def _read_csv_preview(path: Path, *, limit: int = 12) -> list[dict[str, Any]]:
    if not path.exists():
        return []
    try:
        frame = pd.read_csv(path, encoding="utf-8-sig").head(limit)
    except Exception:
        try:
            frame = pd.read_csv(path, encoding="utf-8").head(limit)
        except Exception:
            return []
    return frame.to_dict(orient="records")


def _read_csv_compact_preview(path: Path, *, limit: int = 12, cell_limit: int = 220) -> list[dict[str, Any]]:
    return [_compact_mapping_row(row, limit=cell_limit) for row in _read_csv_preview(path, limit=limit)]


def _compact_prompt_value(value: Any, *, depth: int = 0, max_items: int = 8, max_chars: int = 220) -> Any:
    if depth > 4:
        return _trim_string(value, limit=max_chars)
    if isinstance(value, dict):
        compact: dict[str, Any] = {}
        for idx, (key, item) in enumerate(value.items()):
            if idx >= max_items:
                compact["_truncated_keys"] = max(0, len(value) - max_items)
                break
            compact[str(key)] = _compact_prompt_value(
                item,
                depth=depth + 1,
                max_items=max_items,
                max_chars=max_chars,
            )
        return compact
    if isinstance(value, list):
        compact_list = [
            _compact_prompt_value(item, depth=depth + 1, max_items=max_items, max_chars=max_chars)
            for item in value[:max_items]
        ]
        if len(value) > max_items:
            compact_list.append({"_truncated_items": len(value) - max_items})
        return compact_list
    if isinstance(value, str):
        return _trim_string(value, limit=max_chars)
    return value


def _derived_metric_route_summary(discovery_path: Path, diagnostics_path: Path, *, limit: int = 18) -> dict[str, Any]:
    discovery = _read_json_if_present(discovery_path, "generic_derived_metric_discovery")
    diagnostics = _read_json_if_present(diagnostics_path, "generic_derived_metric_execution_diagnostics")
    candidates = [
        item for item in list(discovery.get("metric_candidates") or discovery.get("derived_metric_candidates") or [])
        if isinstance(item, dict)
    ]
    diag_rows = [item for item in list(diagnostics.get("diagnostics") or []) if isinstance(item, dict)]
    completed_rows = [item for item in diag_rows if str(item.get("status") or "") == "completed"]

    def _metric_item(item: dict[str, Any]) -> dict[str, Any]:
        return {
            "metric_id": _trim_string(item.get("metric_id"), limit=80),
            "指标中文名": _trim_string(item.get("指标中文名") or item.get("metric_name"), limit=80),
            "formula_family": _trim_string(item.get("formula_family") or item.get("operation"), limit=60),
            "formula": _trim_string(item.get("formula"), limit=180),
            "source_fields": _stringify_list_like(item.get("source_fields"))[:6],
            "source_metrics": _stringify_list_like(item.get("source_metrics"))[:6],
            "object_grain": _trim_string(item.get("object_grain"), limit=100),
            "metric_role": _trim_string(item.get("metric_role"), limit=80),
            "unit": _trim_string(item.get("unit"), limit=50),
            "directionality": _trim_string(item.get("directionality"), limit=60),
            "recommended_visual_use": _trim_string(item.get("recommended_visual_use"), limit=160),
            "valid_n": item.get("valid_n", ""),
            "coverage_ratio": item.get("coverage_ratio", ""),
            "overlap_count": item.get("overlap_count", ""),
            "overlap_ratio": item.get("overlap_ratio", ""),
        }

    completed_families = sorted(
        {
            str(item.get("formula_family") or "").strip()
            for item in completed_rows
            if str(item.get("formula_family") or "").strip()
        }
    )
    return {
        "version": discovery.get("version", ""),
        "candidate_count": len(candidates),
        "completed_metric_count": int(diagnostics.get("completed_metric_count") or len(completed_rows)),
        "completed_formula_family_count": int(
            diagnostics.get("completed_formula_family_count") or len(completed_families)
        ),
        "completed_formula_families": completed_families[:12],
        "candidate_examples": [_metric_item(item) for item in candidates[:limit]],
        "completed_metric_examples": [_metric_item(item) for item in completed_rows[:limit]],
        "rejected_candidate_count": len(list(discovery.get("rejected_candidates") or [])),
    }


def _read_csv_header(path: Path) -> list[str]:
    if not path.exists():
        return []
    try:
        frame = pd.read_csv(path, encoding="utf-8-sig", nrows=0)
    except Exception:
        try:
            frame = pd.read_csv(path, encoding="utf-8", nrows=0)
        except Exception:
            return []
    return [str(column) for column in frame.columns.astype(str).tolist()]


def _trim_string(value: Any, *, limit: int = 400) -> str:
    return str(value or "").strip()[:limit]


def _compact_mapping_row(row: dict[str, Any], *, limit: int = 180) -> dict[str, Any]:
    compact: dict[str, Any] = {}
    for key, value in row.items():
        if isinstance(value, str):
            compact[str(key)] = value[:limit]
        elif isinstance(value, (int, float, bool)) or value is None:
            compact[str(key)] = value
        else:
            compact[str(key)] = _trim_string(value, limit=limit)
    return compact


def _build_procurement_batch_input_pack(workspace: Path, *, batch_index: int) -> dict[str, Path]:
    outline_payload = _read_json(workspace / "03_procurement_long_outline.json", "procurement_long_outline")
    question_tree_payload = _read_json(workspace / "02_procurement_question_tree.json", "procurement_question_tree")
    inventory_payload = _read_json(workspace / "01_procurement_inventory.json", "procurement_inventory")

    section_plan = [item for item in list(outline_payload.get("section_plan") or []) if isinstance(item, dict)]
    batch_plan = [item for item in list(outline_payload.get("batch_plan") or []) if isinstance(item, dict)]
    batch_entry = next(
        (
            item
            for item in batch_plan
            if int(item.get("batch_index") or 0) == batch_index
        ),
        batch_plan[batch_index - 1] if 0 <= batch_index - 1 < len(batch_plan) else {},
    )
    section_ids = [str(item).strip() for item in list(batch_entry.get("section_ids") or []) if str(item).strip()]
    section_subset = [
        item
        for item in section_plan
        if str(item.get("section_id") or "").strip() in section_ids
    ]

    driving_question_ids = {
        str(item).strip()
        for section in section_subset
        for item in list(section.get("driving_questions") or [])
        if str(item).strip()
    }
    question_nodes = [item for item in list(question_tree_payload.get("question_nodes") or []) if isinstance(item, dict)]
    selected_question_ids = set(driving_question_ids)
    for node in question_nodes:
        node_id = str(node.get("node_id") or "").strip()
        parent_id = str(node.get("parent_id") or "").strip()
        children = [str(item).strip() for item in list(node.get("children") or []) if str(item).strip()]
        if node_id in driving_question_ids:
            if parent_id:
                selected_question_ids.add(parent_id)
            selected_question_ids.update(children[:6])
        if any(child in driving_question_ids for child in children):
            selected_question_ids.add(node_id)
    selected_question_nodes = []
    for node in question_nodes:
        node_id = str(node.get("node_id") or "").strip()
        if node_id not in selected_question_ids:
            continue
        selected_question_nodes.append(
            {
                "node_id": node_id,
                "parent_id": _trim_string(node.get("parent_id")),
                "level": node.get("level"),
                "question": _trim_string(node.get("question"), limit=500),
                "management_intent": _trim_string(node.get("management_intent"), limit=500),
                "support_level": _trim_string(node.get("support_level")),
                "key_evidence": [str(item).strip() for item in list(node.get("key_evidence") or [])[:8] if str(item).strip()],
                "key_objects": [str(item).strip() for item in list(node.get("key_objects") or [])[:10] if str(item).strip()],
                "key_metrics": [str(item).strip() for item in list(node.get("key_metrics") or [])[:8] if str(item).strip()],
                "children": [str(item).strip() for item in list(node.get("children") or [])[:8] if str(item).strip()],
            }
        )

    inventory_summary = {
        "management_thesis": _trim_string(inventory_payload.get("management_thesis"), limit=1200),
        "reading_note": _trim_string(inventory_payload.get("reading_note"), limit=1000),
        "business_axes": [_compact_mapping_row(item, limit=280) for item in list(inventory_payload.get("business_axes") or [])[:8] if isinstance(item, dict)],
        "priority_metrics": [_compact_mapping_row(item, limit=320) for item in list(inventory_payload.get("priority_metrics") or [])[:10] if isinstance(item, dict)],
        "action_zones": [_compact_mapping_row(item, limit=320) for item in list(inventory_payload.get("action_zones") or [])[:8] if isinstance(item, dict)],
        "field_boundaries": dict(inventory_payload.get("field_boundaries") or {}),
    }

    action_table_rows = [_compact_mapping_row(item, limit=220) for item in _read_csv_preview(workspace / "procurement_action_table.csv", limit=12)]
    object_registry_rows = [_compact_mapping_row(item, limit=220) for item in _read_csv_preview(workspace / "procurement_object_registry.csv", limit=20)]
    category_profile_rows = [_compact_mapping_row(item, limit=220) for item in _read_csv_preview(workspace / "source_category_profile.csv", limit=16)]
    correlation_rows = [_compact_mapping_row(item, limit=220) for item in _read_csv_preview(workspace / "source_correlation_preview.csv", limit=12)]

    payload = {
        "batch_index": batch_index,
        "batch_entry": batch_entry if isinstance(batch_entry, dict) else {},
        "section_ids": section_ids,
        "section_plan_subset": section_subset,
        "driving_question_ids": sorted(driving_question_ids),
        "question_nodes_subset": selected_question_nodes,
        "inventory_summary": inventory_summary,
        "action_table_rows": action_table_rows,
        "object_registry_rows": object_registry_rows,
        "category_profile_rows": category_profile_rows,
        "correlation_preview_rows": correlation_rows,
        "source_files": {
            "outline_json": "03_procurement_long_outline.json",
            "question_tree_json": "02_procurement_question_tree.json",
            "inventory_json": "01_procurement_inventory.json",
            "action_table_csv": "procurement_action_table.csv",
            "object_registry_csv": "procurement_object_registry.csv",
            "category_profile_csv": "source_category_profile.csv",
            "correlation_preview_csv": "source_correlation_preview.csv",
        },
    }

    json_path = workspace / f"03b_procurement_batch_{batch_index:02d}_input.json"
    md_path = workspace / f"03b_procurement_batch_{batch_index:02d}_input.md"
    _write_normalized_json(json_path, payload)
    md_lines = [
        f"# Procurement Batch {batch_index:02d} Input Pack",
        "",
        f"- section ids: {', '.join(section_ids) or 'none'}",
        f"- driving questions: {', '.join(sorted(driving_question_ids)) or 'none'}",
        f"- action rows: {len(action_table_rows)}",
        f"- object rows: {len(object_registry_rows)}",
        f"- category rows: {len(category_profile_rows)}",
        "",
        "## Batch sections",
    ]
    for section in section_subset:
        md_lines.extend(
            [
                f"- {section.get('section_id', '')}: {section.get('section_title', '')}",
                f"  - anchors: {', '.join(str(item) for item in list(section.get('current_period_anchor') or [])[:6])}",
                f"  - tables: {', '.join(str(item) for item in list(section.get('tables') or [])[:6])}",
                f"  - figures: {', '.join(str(item) for item in list(section.get('figures') or [])[:6])}",
            ]
        )
    md_lines.extend(
        [
            "",
            "## Key metrics",
            *[
                f"- {item.get('metric_id', '')}: {item.get('current_signal', '')}"
                for item in inventory_summary["priority_metrics"][:8]
            ],
            "",
            "## Action rows",
            *[
                f"- {json.dumps(item, ensure_ascii=False)}"
                for item in action_table_rows[:8]
            ],
        ]
    )
    md_path.write_text("\n".join(md_lines), encoding="utf-8")
    return {"markdown": md_path, "json": json_path}


