    total_impressions = sum(_internet_ops_float(row.get("impressions")) for row in time_rows)
    total_clicks = sum(_internet_ops_float(row.get("clicks")) for row in time_rows)
    total_registrations = sum(_internet_ops_float(row.get("registrations")) for row in time_rows)
    total_activations = sum(_internet_ops_float(row.get("activations")) for row in time_rows)
    total_paid_users = sum(_internet_ops_float(row.get("paid_users")) for row in time_rows)
    total_revenue = sum(_internet_ops_float(row.get("revenue")) for row in time_rows)
    total_cost = sum(_internet_ops_float(row.get("operating_cost")) for row in time_rows)
    total_margin = sum(_internet_ops_float(row.get("contribution_margin")) for row in time_rows)
    ctr = total_clicks / total_impressions if total_impressions else 0.0
    registration_rate = total_registrations / total_clicks if total_clicks else 0.0
    activation_rate = total_activations / total_registrations if total_registrations else 0.0
