def _split_markdown_sections(text: str) -> list[tuple[str, str]]:
    sections: list[tuple[str, str]] = []
    current_title = "untitled"
    current_lines: list[str] = []
    for raw_line in text.splitlines():
        line = raw_line.rstrip()
        if line.lstrip().startswith("#"):
            if current_lines:
                sections.append((current_title, "\n".join(current_lines).strip()))
            current_title = line.lstrip("#").strip() or current_title
            current_lines = [line]
        else:
            current_lines.append(line)
    if current_lines:
        sections.append((current_title, "\n".join(current_lines).strip()))
    return [(title, body) for title, body in sections if body.strip()]


def _build_internet_ops_section_batch_fallback(workspace: Path, batch_index: int) -> dict[str, Path]:
    management_text = _read_text_artifact(workspace / "management_report.md") if (workspace / "management_report.md").exists() else ""
    appendix_text = _read_text_artifact(workspace / "analyst_appendix.md") if (workspace / "analyst_appendix.md").exists() else ""
    management_sections = _split_markdown_sections(management_text)
    appendix_sections = _split_markdown_sections(appendix_text)
    if not management_sections:
        management_sections = [("management_report", management_text.strip())] if management_text.strip() else []
    if not appendix_sections:
        appendix_sections = [("analyst_appendix", appendix_text.strip())] if appendix_text.strip() else []

    chunk_size = max(1, (len(management_sections) + 2) // 3) if management_sections else 1
    batches: list[list[tuple[str, str]]] = [
        management_sections[0:chunk_size],
        management_sections[chunk_size : chunk_size * 2],
        management_sections[chunk_size * 2 :],
        appendix_sections,
    ]
    selected_sections = batches[min(max(batch_index - 1, 0), len(batches) - 1)]
    batch_md = "\n\n".join(section_body for _title, section_body in selected_sections if section_body.strip()).strip()
    if len(batch_md) < 2200:
        fallback_source = management_text if batch_index < 4 else appendix_text
        batch_md = (batch_md + "\n\n" + fallback_source).strip()

    section_titles = [title for title, _body in selected_sections if title.strip()]
    section_ids = [re.sub(r"[^a-z0-9]+", "_", title.lower()).strip("_") or f"section_{idx+1}" for idx, title in enumerate(section_titles)]
    payload = {
        "batch_index": batch_index,
        "section_ids": section_ids,
        "section_titles": section_titles,
        "completion_status": "fallback_completed",
        "tables_used": [
            "internet_ops_action_table.csv",
            "internet_ops_object_decision_registry.csv",
            "7_day_action_table.csv",
            "30_day_growth_experiment_backlog.csv",
        ],
        "visual_blocks_used": [],
    }
    md_path = workspace / f"04_ops_section_batch_{batch_index:02d}.md"
    json_path = workspace / f"04_ops_section_batch_{batch_index:02d}.json"
    md_path.write_text(batch_md + "\n", encoding="utf-8")
    json_path.write_text(json.dumps(payload, ensure_ascii=False, indent=2), encoding="utf-8")
    return {"markdown": md_path, "json": json_path}


def _build_internet_ops_report_assembly_fallback(workspace: Path) -> Path:
    batch_texts: list[str] = []
    for index in range(1, 5):
        path = workspace / f"04_ops_section_batch_{index:02d}.md"
        if path.exists():
            batch_texts.append(_read_text_artifact(path).strip())
    table_reading_text = render_ops_table_reading_cards_markdown(workspace).strip()
    if table_reading_text:
        batch_texts.append(table_reading_text)
    report_md = workspace / "05_report.md"
    report_md.write_text("\n\n".join(text for text in batch_texts if text).strip() + "\n", encoding="utf-8")
    return report_md


def _split_internet_ops_full_table_columns(headers: list[str], key_columns: list[str], *, values_per_chunk: int = 8) -> list[list[str]]:
    keys = [column for column in key_columns if column in headers]
    values = [column for column in headers if column not in keys]
    if not values:
        return [keys]
    chunks: list[list[str]] = []
    for index in range(0, len(values), values_per_chunk):
        chunks.append([*keys, *values[index : index + values_per_chunk]])
    return chunks


