    text = text.replace("结果贡献头部卖家代理、客户承接头部卖家代理", support.get("seller_detail_sentence", "卖家代理明细见附录"))
    text = text.replace("结果贡献头部卖家代理", f"seller_id {support.get('seller_suffix_6796') or support.get('seller_ids')}")
    text = text.replace("客户承接头部卖家代理", f"seller_id {support.get('seller_suffix_94c0') or support.get('seller_ids')}")
