    text = text.replace("卖家代理尾号 <code>796</code>", f"seller_id <code>{support.get('seller_suffix_6796') or ''}</code>")
    text = text.replace("卖家代理尾号 <code>4c0</code>", f"seller_id <code>{support.get('seller_suffix_94c0') or ''}</code>")
    text = text.replace("卖家代理尾号 <code>b82</code> / <code>769</code>", f"seller_id <code>{support.get('seller_suffix_ab82') or ''}</code> / <code>{support.get('seller_suffix_9769') or ''}</code>")
    text = text.replace("<code>4c0</code>", f"<code>{support.get('seller_suffix_94c0') or '4c0'}</code>")
