        heading_match = re.match(r"^(#{1,6})\s+(.+)$", stripped)
        if heading_match:
            close_list()
            level = min(len(heading_match.group(1)), 4)
            body.append(f"<h{level}>{_procurement_markdown_inline_html(heading_match.group(2))}</h{level}>")
            index += 1
            continue
        if stripped.startswith(("- ", "* ")):
            if not in_list:
                body.append("<ul>")
                in_list = True
            body.append(f"<li>{_procurement_markdown_inline_html(stripped[2:].strip())}</li>")
            index += 1
            continue
        close_list()
        body.append(f"<p>{_procurement_markdown_inline_html(stripped)}</p>")
