        reverse_spec_path = workspace / "01_historical_reverse_spec.json"
        page_plan_path = workspace / "02_historical_page_plan.json"
        deck_layout_path = workspace / "historical_deck_layout_pack.json"
        pdf_path = workspace / "07_historical_style_report.pdf"
        reverse_spec_payload = _read_json(reverse_spec_path, "historical_reverse_spec")
        page_plan_payload = _read_json(page_plan_path, "historical_page_plan")
        deck_layout_payload = _read_json(deck_layout_path, "historical_deck_layout_pack")
        report_logic_blueprint_path = workspace / "03_report_logic_blueprint.json"
        report_logic_blueprint_payload = (
            _read_json(report_logic_blueprint_path, "historical_report_logic_blueprint")
            if report_logic_blueprint_path.exists()
            else {}
        )
        chart_assets_payload = _read_json(workspace / "historical_chart_assets_index.json", "historical_chart_assets")
        table_assets_payload = _read_json(workspace / "historical_table_assets_index.json", "historical_table_assets")
        collage_assets_payload = _read_json(workspace / "historical_collage_assets_index.json", "historical_collage_assets")
        data_manifest_path = workspace / "historical_data_asset_manifest.json"
        data_storyline_path = workspace / "02_data_storyline_scan.json"
        data_manifest_payload = (
            _read_json(data_manifest_path, "historical_data_asset_manifest")
            if data_manifest_path.exists()
            else {}
        )
        data_storyline_payload = (
            _read_json(data_storyline_path, "historical_data_storyline_scan")
            if data_storyline_path.exists()
            else {}
        )
        data_coverage_payload = dict((dict(deck_layout_payload.get("quality_metrics") or {}).get("data_coverage") or {}))
        visual_reference_payload = (
            _read_json(workspace / "historical_visual_reference.json", "historical_visual_reference")
            if (workspace / "historical_visual_reference.json").exists()
            else {}
        )
        rendered_page_count = _count_pdf_pages(pdf_path)
        quality_report_path = workspace / "historical_style_quality_report.json"
        quality_report_payload = build_historical_style_quality_report(
            workspace=workspace,
            reverse_spec_path=reverse_spec_path,
            page_plan_path=page_plan_path,
            deck_layout_path=deck_layout_path,
            markdown_path=md_path,
            html_path=workspace / "06_historical_style_report.html",
            css_path=workspace / "06_historical_style_report.css",
            pdf_path=pdf_path,
            data_manifest_path=data_manifest_path,
            visual_reference_path=workspace / "historical_visual_reference.json",
            chart_assets_index_path=workspace / "historical_chart_assets_index.json",
            table_assets_index_path=workspace / "historical_table_assets_index.json",
            collage_assets_index_path=workspace / "historical_collage_assets_index.json",
            rendered_page_count=rendered_page_count,
            output_path=quality_report_path,
        )
        quality_artifact = _register_artifact(
            pipeline_job_id,
            stage_id=stage_id,
            artifact_path=quality_report_path,
            artifact_type="json",
            role="quality_report",
            is_primary=False,
        )
        quality_blocking_issues = list(quality_report_payload.get("blocking_issues") or [])
        fatal_reader_issues = [
            issue
            for issue in quality_blocking_issues
            if issue
            in {
                "language_quality_score_below_0_90",
                "mojibake_detected",
                "placeholder_or_filler_detected",
                "internal_path_or_artifact_name_leaked",
                "reader_facing_output_too_short",
                "reader_facing_cjk_ratio_too_low",
                "reader_quality_gate_failed",
            }
        ]
        if fatal_reader_issues:
            raise ValueError(f"historical style reader-facing quality gate failed: {fatal_reader_issues}")
        derived_metric_usage_contract_path = workspace / "derived_metric_usage_contract.json"
        derived_metric_usage_contract = (
            _read_json(derived_metric_usage_contract_path, "derived_metric_usage_contract")
            if derived_metric_usage_contract_path.exists()
            else {}
        )
        derived_metric_usage_summary = summarize_derived_metric_usage(
            contract=derived_metric_usage_contract,
            page_plan=list(page_plan_payload.get("pages") or []),
            asset_coverage={
                "used_derived_metric_names": list(data_coverage_payload.get("used_derived_metric_names") or [])
            },
        ) if derived_metric_usage_contract else {}
        if derived_metric_usage_contract:
            used_derived_metric_count = len(list(data_coverage_payload.get("used_derived_metric_names") or []))
            minimum_derived_metric_count = min(3, int(derived_metric_usage_contract.get("derived_metric_count") or 0))
            if minimum_derived_metric_count and used_derived_metric_count < minimum_derived_metric_count:
                raise ValueError(
                    "historical style derived metric usage gate failed: "
                    f"{used_derived_metric_count}/{minimum_derived_metric_count}"
                )
        output_title = str(payload.get("title") or "").strip()
        if not output_title or output_title.count("?") >= max(3, len(output_title) // 2):
            deck_pages = [page for page in list(deck_layout_payload.get("pages") or []) if isinstance(page, dict)]
            output_title = str((deck_pages[0] if deck_pages else {}).get("title") or "").strip()
